import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Search,
  Github,
  Briefcase,
  Sparkles,
  FileText,
  TrendingUp,
  Clock,
} from 'lucide-react';
import toast from 'react-hot-toast';

const actions = [
  {
    id: 1,
    title: 'Create Portfolio',
    description: 'Build and manage your portfolio',
    icon: Briefcase,
    path: '/profile',
  },
  {
    id: 2,
    title: 'Connect GitHub',
    description: 'Link your GitHub account',
    icon: Github,
    path: '/profile',
  },
  {
    id: 3,
    title: 'Analyze Repository',
    description: 'Analyze repository insights',
    icon: Github,
    path: '/profile',
  },
  {
    id: 4,
    title: 'Generate README Assets',
    description: 'Create README enhancements',
    icon: FileText,
    path: '/profile',
  },
  {
    id: 5,
    title: 'Skill Gap Analysis',
    description: 'Analyze missing skills',
    icon: Sparkles,
    path: '/dashboard',
  },
  {
    id: 6,
    title: 'Career Trajectory',
    description: 'Explore career growth insights',
    icon: TrendingUp,
    path: '/dashboard',
  },
  {
    id: 7,
    title: 'Dashboard',
    description: 'Go to dashboard',
    icon: Briefcase,
    path: '/dashboard',
  },
  {
    id: 8,
    title: 'Jobs',
    description: 'Browse jobs',
    icon: Briefcase,
    path: '/jobs',
  },
  {
    id: 9,
    title: 'Profile',
    description: 'Open your profile',
    icon: Briefcase,
    path: '/profile',
  },
];

const CommandPalette = ({ isOpen, setIsOpen }) => {
  const navigate = useNavigate();

  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [recentActions, setRecentActions] = useState([]);

  const inputRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';

      setTimeout(() => {
        inputRef.current?.focus();
      }, 50);

      const saved =
        JSON.parse(localStorage.getItem('recentCommands')) || [];

      setRecentActions(saved);
    } else {
      document.body.style.overflow = 'auto';
      setQuery('');
      setSelectedIndex(0);
    }

    return () => {
      document.body.style.overflow = 'auto';
    };
  }, [isOpen]);

  const filteredActions = useMemo(() => {
    if (!query.trim()) {
      return actions;
    }

    return actions.filter((action) =>
      action.title.toLowerCase().includes(query.toLowerCase())
    );
  }, [query]);

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (!isOpen) return;

      if (e.key === 'Escape') {
        setIsOpen(false);
      }

      if (e.key === 'ArrowDown') {
        e.preventDefault();

        setSelectedIndex((prev) =>
          prev < filteredActions.length - 1 ? prev + 1 : 0
        );
      }

      if (e.key === 'ArrowUp') {
        e.preventDefault();

        setSelectedIndex((prev) =>
          prev > 0 ? prev - 1 : filteredActions.length - 1
        );
      }

      if (e.key === 'Enter') {
        e.preventDefault();

        const selected = filteredActions[selectedIndex];

        if (selected) {
          handleSelect(selected);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);

    return () =>
      window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, selectedIndex, filteredActions]);

  const handleSelect = (action) => {
    navigate(action.path);

    const recentWithoutIcons = [
      {
        id: action.id,
        title: action.title,
        description: action.description,
        path: action.path,
      },
      ...recentActions.filter((a) => a.id !== action.id),
    ].slice(0, 5);

    localStorage.setItem(
      'recentCommands',
      JSON.stringify(recentWithoutIcons)
    );

    setRecentActions(recentWithoutIcons);

    toast.success(`Opening ${action.title}`);

    setIsOpen(false);
  };

  const handleOutsideClick = (e) => {
    if (
      containerRef.current &&
      !containerRef.current.contains(e.target)
    ) {
      setIsOpen(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div
      onClick={handleOutsideClick}
      className="fixed inset-0 z-[9999] bg-black/60 backdrop-blur-sm flex items-start justify-center px-4 pt-24"
    >
      <div
        ref={containerRef}
        className="w-full max-w-2xl rounded-3xl border border-white/10 bg-[#0b1120]/95 shadow-2xl overflow-hidden"
      >
        <div className="flex items-center gap-3 border-b border-white/10 px-5 py-4">
          <Search size={18} className="text-cyan-400" />

          <input
            ref={inputRef}
            type="text"
            placeholder="Search commands..."
            value={query}
            onChange={(e) => {
              setQuery(e.target.value);
              setSelectedIndex(0);
            }}
            className="w-full bg-transparent outline-none text-white placeholder:text-gray-500 text-sm"
          />

          <div className="hidden sm:flex items-center gap-2 text-xs text-gray-500">
            <kbd className="rounded bg-white/10 px-2 py-1">
              ESC
            </kbd>
          </div>
        </div>

        {!query && recentActions.length > 0 && (
          <div className="border-b border-white/10 px-4 py-3">
            <div className="mb-2 flex items-center gap-2 text-xs font-medium uppercase tracking-wide text-gray-400">
              <Clock size={14} />
              Recent
            </div>

            <div className="space-y-1">
              {recentActions.map((action) => {
                const matchedAction = actions.find(
                  (a) => a.id === action.id
                );

                const Icon =
                  matchedAction?.icon || Briefcase;

                return (
                  <button
                    key={action.id}
                    onClick={() => handleSelect(action)}
                    className="flex w-full items-center gap-3 rounded-xl px-3 py-2 text-left hover:bg-white/5 transition"
                  >
                    <div className="text-cyan-400">
                      <Icon size={18} />
                    </div>

                    <div>
                      <p className="text-sm text-white">
                        {action.title}
                      </p>

                      <p className="text-xs text-gray-500">
                        {action.description}
                      </p>
                    </div>
                  </button>
                );
              })}
            </div>
          </div>
        )}

        <div className="max-h-[420px] overflow-y-auto p-3">
          {filteredActions.length > 0 ? (
            filteredActions.map((action, index) => {
              const Icon = action.icon;

              return (
                <button
                  key={action.id}
                  onClick={() => handleSelect(action)}
                  className={`flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-left transition-all duration-200 ${
                    selectedIndex === index
                      ? 'bg-cyan-500/10 border border-cyan-500/20'
                      : 'hover:bg-white/5'
                  }`}
                >
                  <div className="text-cyan-400">
                    <Icon size={18} />
                  </div>

                  <div className="flex-1">
                    <p className="text-sm font-medium text-white">
                      {action.title}
                    </p>

                    <p className="text-xs text-gray-500">
                      {action.description}
                    </p>
                  </div>
                </button>
              );
            })
          ) : (
            <div className="py-12 text-center">
              <p className="text-sm text-gray-400">
                No matching commands found.
              </p>
            </div>
          )}
        </div>

        <div className="flex items-center justify-between border-t border-white/10 px-5 py-3 text-xs text-gray-500">
          <div className="flex items-center gap-3">
            <span>↑↓ Navigate</span>
            <span>↵ Select</span>
          </div>

          <div className="flex items-center gap-2">
            <kbd className="rounded bg-white/10 px-2 py-1">
              Ctrl
            </kbd>

            <span>+</span>

            <kbd className="rounded bg-white/10 px-2 py-1">
              K
            </kbd>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CommandPalette;

import { useCallback, useState } from 'react'
import { useDropzone } from 'react-dropzone'
import { Upload, FileText, X, CheckCircle, AlertCircle } from 'lucide-react'
import toast from 'react-hot-toast'

export default function DropZone({
  onFileSelect,
  disabled = false,
  maxSizeMB = 5,
  multiple = false,
}) {
  const maxSizeBytes = maxSizeMB * 1024 * 1024
  const [previews, setPreviews] = useState([])
  const [uploadProgress, setUploadProgress] = useState({})

  const simulateProgress = (fileName) => {
    let progress = 0
    setUploadProgress((prev) => ({ ...prev, [fileName]: 0 }))
    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 15) + 5
      if (progress >= 100) {
        progress = 100
        clearInterval(interval)
      }
      setUploadProgress((prev) => ({ ...prev, [fileName]: progress }))
    }, 150)
  }

  const onDrop = useCallback(
    (acceptedFiles, rejectedFiles) => {
      if (rejectedFiles && rejectedFiles.length > 0) {
        rejectedFiles.forEach((file) => {
          if (file.errors?.[0]?.code === 'file-too-large') {
            const sizeMB = (file.file.size / (1024 * 1024)).toFixed(2)
            toast.error(`"${file.file.name}" (${sizeMB}MB) exceeds ${maxSizeMB}MB limit`)
          } else if (file.errors?.[0]?.code === 'file-invalid-type') {
            toast.error(`"${file.file.name}" is not a PDF file`)
          } else {
            toast.error(`"${file.file.name}" could not be added`)
          }
        })
        return
      }

      if (acceptedFiles.length === 0) return

      const newPreviews = acceptedFiles.map((file) => ({
        name: file.name,
        size: (file.size / (1024 * 1024)).toFixed(2),
        file,
      }))

      setPreviews((prev) => (multiple ? [...prev, ...newPreviews] : newPreviews))

      acceptedFiles.forEach((file) => simulateProgress(file.name))

      if (multiple) {
        acceptedFiles.forEach((file) => onFileSelect(file))
      } else {
        onFileSelect(acceptedFiles[0])
      }
    },
    [onFileSelect, maxSizeMB, maxSizeBytes, multiple]
  )

  const removeFile = (fileName) => {
    setPreviews((prev) => prev.filter((p) => p.name !== fileName))
    setUploadProgress((prev) => {
      const updated = { ...prev }
      delete updated[fileName]
      return updated
    })
  }

  const { getRootProps, getInputProps, isDragActive, isDragReject } = useDropzone({
    onDrop,
    accept: { 'application/pdf': ['.pdf'] },
    maxFiles: multiple ? 10 : 1,
    maxSize: maxSizeBytes,
    multiple,
    disabled,
  })

  return (
    <div className="w-full space-y-4">
      {/* Drop Zone */}
      <div
        {...getRootProps()}
        className={`
          relative border-2 border-dashed rounded-xl p-10 text-center cursor-pointer
          transition-all duration-300 group
          ${isDragReject
            ? 'border-red-500 bg-red-500/10'
            : isDragActive
            ? 'border-primary bg-primary/10 scale-[1.01]'
            : 'border-border hover:border-primary/50 bg-card hover:bg-muted/50'}
          ${disabled ? 'opacity-50 cursor-not-allowed pointer-events-none' : ''}
        `}
      >
        <input {...getInputProps()} />

        <div className="flex flex-col items-center gap-3">
          <div
            className={`w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300
              ${isDragReject
                ? 'bg-red-500/20'
                : isDragActive
                ? 'bg-primary/20 scale-110'
                : 'bg-muted group-hover:bg-primary/10'}
            `}
          >
            {isDragReject ? (
              <AlertCircle className="w-8 h-8 text-red-500" />
            ) : isDragActive ? (
              <FileText className="w-8 h-8 text-primary animate-bounce" />
            ) : (
              <Upload className="w-8 h-8 text-muted-foreground group-hover:text-primary transition-colors" />
            )}
          </div>

          {isDragReject ? (
            <p className="text-red-500 font-medium">Only PDF files are accepted</p>
          ) : isDragActive ? (
            <p className="text-primary font-medium text-lg">Drop {multiple ? 'files' : 'file'} here...</p>
          ) : (
            <>
              <div>
                <p className="text-foreground font-medium text-lg">
                  Drag & drop {multiple ? 'PDF files' : 'your resume PDF'} here
                </p>
                <p className="text-muted-foreground text-sm mt-1">or click to browse</p>
              </div>
              <div className="inline-flex items-center gap-2 px-4 py-2 bg-muted rounded-lg mt-1">
                <FileText className="w-4 h-4 text-muted-foreground" />
                <span className="text-xs text-muted-foreground">
                  PDF only • Max {maxSizeMB}MB{multiple ? ' • Multiple files supported' : ''}
                </span>
              </div>
            </>
          )}
        </div>
      </div>

      {/* File Previews */}
      {previews.length > 0 && (
        <div className="space-y-3">
          {previews.map((preview) => {
            const progress = uploadProgress[preview.name] ?? 0
            const isDone = progress === 100

            return (
              <div
                key={preview.name}
                className="flex items-center gap-3 p-3 rounded-xl border border-border bg-card"
              >
                {/* Icon */}
                <div className="w-10 h-10 bg-primary/10 rounded-lg flex items-center justify-center shrink-0">
                  <FileText className="w-5 h-5 text-primary" />
                </div>

                {/* Info + Progress */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <p className="text-sm font-medium text-foreground truncate">{preview.name}</p>
                    <span className="text-xs text-muted-foreground ml-2 shrink-0">
                      {preview.size} MB
                    </span>
                  </div>
                  {/* Progress Bar */}
                  <div className="w-full h-1.5 bg-muted rounded-full overflow-hidden">
                    <div
                      className={`h-full rounded-full transition-all duration-200 ${
                        isDone ? 'bg-green-500' : 'bg-primary'
                      }`}
                      style={{ width: `${progress}%` }}
                    />
                  </div>
                  <p className="text-xs text-muted-foreground mt-1">
                    {isDone ? 'Ready to upload' : `Preparing... ${progress}%`}
                  </p>
                </div>

                {/* Status / Remove */}
                <div className="shrink-0">
                  {isDone ? (
                    <CheckCircle className="w-5 h-5 text-green-500" />
                  ) : (
                    <button
                      onClick={(e) => {
                        e.stopPropagation()
                        removeFile(preview.name)
                      }}
                      className="p-1 rounded-md hover:bg-muted transition-colors"
                    >
                      <X className="w-4 h-4 text-muted-foreground hover:text-foreground" />
                    </button>
                  )}
                </div>
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

/**
 * VoiceToTextButton — Reusable microphone toggle button with live transcript display.
 *
 * Implements issue #28: Voice-to-Text for Mock Interviews
 *
 * Props:
 *  onTranscriptChange  (string) => void   Called whenever transcript updates
 *  lang                string             BCP-47 language tag (default 'en-US')
 *  placeholder         string             Hint text shown in empty textarea
 *  disabled            boolean            Disable the button externally
 *  className           string             Extra Tailwind classes for the wrapper
 *  showTranscript      boolean            Whether to render the transcript textarea (default true)
 *  size                'sm'|'md'|'lg'     Button size preset (default 'md')
 */
import { useCallback } from 'react';
import { Mic, MicOff, AlertCircle, Loader2 } from 'lucide-react';
import { useVoiceToText, isSpeechRecognitionSupported } from '../hooks/useVoiceToText';

const SIZE = {
    sm: { btn: 'p-2', icon: 'w-4 h-4', pulse: 'w-8 h-8' },
    md: { btn: 'p-3', icon: 'w-5 h-5', pulse: 'w-10 h-10' },
    lg: { btn: 'p-4', icon: 'w-6 h-6', pulse: 'w-12 h-12' },
};

export default function VoiceToTextButton({
    onTranscriptChange,
    lang = 'en-US',
    placeholder = 'Your spoken answer will appear here…',
    disabled = false,
    className = '',
    showTranscript = true,
    size = 'md',
}) {
    const s = SIZE[size] || SIZE.md;

    const handleFinal = useCallback(
        (text) => onTranscriptChange?.(text),
        [onTranscriptChange]
    );

    const {
        isListening,
        transcript,
        interimTranscript,
        error,
        isSupported,
        startListening,
        stopListening,
        resetTranscript,
    } = useVoiceToText({ lang, onFinalTranscript: handleFinal });

    const toggle = () => {
        if (disabled) return;
        if (isListening) {
            stopListening();
        } else {
            resetTranscript();
            startListening();
        }
    };

    const displayText = transcript + interimTranscript;

    // Not supported — show a static badge
    if (!isSpeechRecognitionSupported()) {
        return (
            <div className={`flex items-center gap-2 text-sm text-amber-400 ${className}`}>
                <AlertCircle className="w-4 h-4 flex-shrink-0" />
                <span>Voice input requires Chrome or Edge on desktop.</span>
            </div>
        );
    }

    return (
        <div className={`flex flex-col gap-3 ${className}`}>
            {/* Button row */}
            <div className="flex items-center gap-3">
                {/* Outer pulse ring when listening */}
                <div className="relative flex-shrink-0">
                    {isListening && (
                        <span
                            className={`absolute inset-0 rounded-full bg-red-500/30 animate-ping ${s.pulse}`}
                            aria-hidden="true"
                        />
                    )}
                    <button
                        type="button"
                        onClick={toggle}
                        disabled={disabled}
                        aria-label={isListening ? 'Stop voice input' : 'Start voice input'}
                        aria-pressed={isListening}
                        className={[
                            s.btn,
                            'relative rounded-full transition-all duration-200 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary',
                            disabled
                                ? 'opacity-40 cursor-not-allowed bg-muted'
                                : isListening
                                    ? 'bg-red-500 text-white shadow-lg shadow-red-500/30 hover:bg-red-600'
                                    : 'bg-primary/10 text-primary border border-primary/30 hover:bg-primary/20',
                        ].join(' ')}
                    >
                        {isListening
                            ? <MicOff className={s.icon} />
                            : <Mic className={s.icon} />
                        }
                    </button>
                </div>

                {/* Status label */}
                <span className={`text-sm font-medium ${isListening ? 'text-red-400' : 'text-muted-foreground'}`}>
                    {isListening ? (
                        <span className="flex items-center gap-1.5">
                            <Loader2 className="w-3.5 h-3.5 animate-spin" />
                            Listening…
                        </span>
                    ) : transcript
                        ? 'Click mic to re-record'
                        : 'Click mic to speak your answer'
                    }
                </span>

                {/* Clear button */}
                {transcript && !isListening && (
                    <button
                        type="button"
                        onClick={() => { resetTranscript(); onTranscriptChange?.(''); }}
                        className="ml-auto text-xs text-muted-foreground hover:text-foreground transition-colors underline underline-offset-2"
                        aria-label="Clear transcript"
                    >
                        Clear
                    </button>
                )}
            </div>

            {/* Transcript area */}
            {showTranscript && (
                <div
                    role="status"
                    aria-live="polite"
                    aria-atomic="false"
                    className={[
                        'min-h-[80px] rounded-xl border p-4 text-sm leading-relaxed transition-colors',
                        isListening
                            ? 'border-red-500/40 bg-red-500/5'
                            : displayText
                                ? 'border-border bg-muted/40'
                                : 'border-dashed border-border/60 bg-transparent',
                    ].join(' ')}
                >
                    {displayText ? (
                        <>
                            <span className="text-foreground">{transcript}</span>
                            {interimTranscript && (
                                <span className="text-muted-foreground italic">{interimTranscript}</span>
                            )}
                        </>
                    ) : (
                        <span className="text-muted-foreground/60">{placeholder}</span>
                    )}
                </div>
            )}

            {/* Error message */}
            {error && (
                <div
                    role="alert"
                    className="flex items-start gap-2 rounded-lg bg-destructive/10 border border-destructive/20 p-3 text-sm text-destructive"
                >
                    <AlertCircle className="w-4 h-4 flex-shrink-0 mt-0.5" />
                    <span>{error}</span>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { formatDistanceToNow } from 'date-fns';
import { communityApi } from '../../services/api';
import { 
  Heart, 
  MessageCircle, 
  Send, 
  MoreHorizontal,
  ChevronDown,
  ChevronUp,
  Loader2
} from 'lucide-react';
import toast from 'react-hot-toast';
import { SkeletonListItems } from '../ui/Skeleton';

function CommentItem({ comment, currentUser, onReply, onLike, depth = 0 }) {
  const [showReplies, setShowReplies] = useState(depth === 0);
  const [isReplying, setIsReplying] = useState(false);
  const [replyContent, setReplyContent] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const isLiked = comment.likes?.some(l => l.uid === currentUser?.uid);
  const isOwn = comment.author?.uid === currentUser?.uid;
  const likeCount = comment.likes?.length || comment.likeCount || 0;

  const getInitials = (name) => {
    return name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??';
  };

  const handleSubmitReply = async (e) => {
    e.preventDefault();
    if (!replyContent.trim() || isSubmitting) return;

    setIsSubmitting(true);
    try {
      await onReply(comment.id, replyContent.trim());
      setReplyContent('');
      setIsReplying(false);
    } catch (error) {
      toast.error('Failed to post reply');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className={`${depth > 0 ? 'ml-8 border-l-2 border-border pl-4' : ''}`}>
      <div className="flex gap-3 py-3">
        {/* Avatar */}
        <div className="shrink-0">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium">
            {comment.author?.avatar ? (
              <img 
                src={comment.author.avatar} 
                alt={comment.author.name}
                className="w-full h-full rounded-full object-cover"
              />
            ) : (
              getInitials(comment.author?.name)
            )}
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="font-medium text-sm text-foreground">
              {comment.author?.name || 'Anonymous'}
            </span>
            {isOwn && (
              <span className="text-xs bg-primary/20 text-primary px-1.5 py-0.5 rounded">
                You
              </span>
            )}
            <span className="text-xs text-muted-foreground">
              {comment.createdAt ? formatDistanceToNow(new Date(comment.createdAt), { addSuffix: true }) : ''}
            </span>
            {comment.isEdited && (
              <span className="text-xs text-muted-foreground">(edited)</span>
            )}
          </div>

          <p className="text-sm text-foreground mt-1 whitespace-pre-wrap">
            {comment.content}
          </p>

          {/* Actions */}
          <div className="flex items-center gap-4 mt-2">
            <button
              onClick={() => onLike(comment.id)}
              className={`flex items-center gap-1 text-xs transition-colors ${
                isLiked ? 'text-destructive' : 'text-muted-foreground hover:text-destructive'
              }`}
            >
              <Heart className={`w-4 h-4 ${isLiked ? 'fill-current' : ''}`} />
              <span>{likeCount > 0 ? likeCount : ''}</span>
            </button>

            {depth === 0 && (
              <button
                onClick={() => setIsReplying(!isReplying)}
                className="flex items-center gap-1 text-xs text-muted-foreground hover:text-primary"
              >
                <MessageCircle className="w-4 h-4" />
                <span>Reply</span>
              </button>
            )}
          </div>

          {/* Reply Input */}
          {isReplying && (
            <form onSubmit={handleSubmitReply} className="mt-3 flex gap-2">
              <input
                type="text"
                value={replyContent}
                onChange={(e) => setReplyContent(e.target.value)}
                placeholder="Write a reply..."
                className="flex-1 px-3 py-2 text-sm bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                autoFocus
              />
              <button
                type="submit"
                disabled={!replyContent.trim() || isSubmitting}
                className="px-3 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isSubmitting ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                   <>
        <Send className="w-4 h-4" />
        <span className="sr-only">Post Reply</span>
    </>
                )}
              </button>
            </form>
          )}
        </div>
      </div>

      {/* Replies */}
      {comment.replies?.length > 0 && (
        <div className="mt-1">
          <button
            onClick={() => setShowReplies(!showReplies)}
            className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 mb-2 ml-11"
          >
            {showReplies ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
            {showReplies ? 'Hide' : 'Show'} {comment.replies.length} {comment.replies.length === 1 ? 'reply' : 'replies'}
          </button>
          
          {showReplies && (
            <div className="space-y-1">
              {comment.replies.map(reply => (
                <CommentItem
                  key={reply.id || reply._id}
                  comment={reply}
                  currentUser={currentUser}
                  onReply={onReply}
                  onLike={onLike}
                  depth={depth + 1}
                />
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default function CommentSection({ postId, currentUser, onCommentAdded }) {
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [newComment, setNewComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(false);
  const [total, setTotal] = useState(0);

  useEffect(() => {
    fetchComments();
  }, [postId]);

  const fetchComments = async (loadMore = false) => {
    try {
      if (!loadMore) setLoading(true);
      
      const pageToFetch = loadMore ? page + 1 : 1;
      const data = await communityApi.getComments(postId, pageToFetch);
      
      if (loadMore) {
        setComments(prev => [...prev, ...data.comments]);
        setPage(pageToFetch);
      } else {
        setComments(data.comments);
        setPage(1);
      }
      
      setTotal(data.pagination.total);
      setHasMore(data.comments.length === 20 && data.pagination.total > pageToFetch * 20);
    } catch (error) {
      toast.error('Failed to load comments', { id: `community-comments-load-error-${postId}` });
    } finally {
      setLoading(false);
    }
  };

  const handleSubmitComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim() || isSubmitting) return;

    setIsSubmitting(true);
    try {
      const data = await communityApi.createComment(postId, { content: newComment.trim() });
      setComments(prev => [data.comment, ...prev]);
      setNewComment('');
      setTotal(prev => prev + 1);
      onCommentAdded?.();
      toast.success('Comment posted!');
    } catch (error) {
      toast.error('Failed to post comment', { id: `community-post-comment-error-${postId}` });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleReply = async (parentCommentId, content) => {
    const data = await communityApi.createComment(postId, { 
      content, 
      parentCommentId 
    });
    
    // Add reply to the parent comment
    setComments(prev => prev.map(comment => {
      if ((comment.id || comment._id) === parentCommentId) {
        return {
          ...comment,
          replies: [...(comment.replies || []), data.comment],
          replyCount: (comment.replyCount || 0) + 1
        };
      }
      return comment;
    }));
    
    onCommentAdded?.();
  };

  const handleLikeComment = async (commentId) => {
    try {
      const data = await communityApi.toggleLikeComment(commentId);
      
      // Update the comment in state
      const updateCommentLike = (comments) => {
        return comments.map(comment => {
          if ((comment.id || comment._id) === commentId) {
            const newLikes = data.liked
              ? [...(comment.likes || []), { uid: currentUser.uid, name: currentUser.displayName }]
              : (comment.likes || []).filter(l => l.uid !== currentUser.uid);
            return { ...comment, likes: newLikes, likeCount: data.likeCount };
          }
          // Check replies
          if (comment.replies) {
            return { ...comment, replies: updateCommentLike(comment.replies) };
          }
          return comment;
        });
      };
      
      setComments(updateCommentLike);
    } catch (error) {
      toast.error('Failed to like comment', { id: `community-like-comment-error-${commentId}` });
    }
  };

  return (
    <div className="border-t border-border bg-card">
      {/* Comment Input */}
      <div className="p-4 border-b border-border bg-muted/50">
        <form onSubmit={handleSubmitComment} className="flex gap-2">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium shrink-0">
            {currentUser?.photoURL ? (
              <img 
                src={currentUser.photoURL} 
                alt={currentUser.displayName}
                className="w-full h-full rounded-full object-cover"
              />
            ) : (
              currentUser?.displayName?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??'
            )}
          </div>
          <input
            type="text"
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
            placeholder="Write a comment..."
            className="flex-1 px-4 py-2 bg-muted border border-border rounded-full text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
          />
          <button
            type="submit"
            disabled={!newComment.trim() || isSubmitting}
            className="px-4 py-2 bg-primary text-primary-foreground rounded-full hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {isSubmitting ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <>
                <Send className="w-4 h-4" />
                <span className="hidden sm:inline">Post Comment </span>
              </>
            )}
          </button>
        </form>
      </div>

      {/* Comments List */}
      <div className="max-h-96 overflow-y-auto">
        {loading ? (
          <div className="px-4 py-4">
            <SkeletonListItems count={3} />
          </div>
        ) : comments.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            <MessageCircle className="w-12 h-12 mx-auto mb-2 text-muted-foreground/60" />
            <p>No comments yet. Be the first to comment!</p>
          </div>
        ) : (
          <div className="px-4 divide-y divide-border">
            {comments.map(comment => (
              <CommentItem
                key={comment.id || comment._id}
                comment={comment}
                currentUser={currentUser}
                onReply={handleReply}
                onLike={handleLikeComment}
              />
            ))}
          </div>
        )}

        {/* Load More */}
        {hasMore && !loading && (
          <div className="p-4 text-center">
            <button
              onClick={() => fetchComments(true)}
              className="text-sm text-primary hover:text-primary/80 font-medium"
            >
              Load more comments ({total - comments.length} remaining)
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { useSocket } from '../../hooks/useSocket';
import { communityApi } from '../../services/api';
import { formatDistanceToNow } from 'date-fns';
import { Search, Plus, Circle, X } from 'lucide-react';

export default function DirectMessages() {
  const { user } = useAuth();
  const { subscribe, onlineUsers, startConversation } = useSocket();
  
  const [conversations, setConversations] = useState([]);
  const [selectedConversation, setSelectedConversation] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showNewDM, setShowNewDM] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Fetch conversations on mount
  const fetchConversations = useCallback(async () => {
    try {
      setLoading(true);
      const data = await communityApi.getConversations();
      setConversations(data.conversations);
    } catch (error) {
      console.error('Failed to fetch conversations:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchConversations();
  }, [fetchConversations]);

  // Subscribe to new DMs
  useEffect(() => {
    const unsubNewDM = subscribe('new_direct_message', ({ message, conversation }) => {
      const convId = conversation.id || conversation._id;
      // Update conversations list
      setConversations(prev => {
        const exists = prev.find(c => (c.id || c._id) === convId);
        if (exists) {
          return prev.map(c => (c.id || c._id) === convId ? conversation : c);
        }
        return [conversation, ...prev];
      });

      // Update messages if viewing this conversation
      const selectedId = selectedConversation?.id || selectedConversation?._id;
      if (selectedId === convId) {
        setMessages(prev => [...prev, message]);
      }
    });

    return () => unsubNewDM();
  }, [subscribe, selectedConversation]);

  const fetchMessages = async (conversationId) => {
    try {
      const data = await communityApi.getConversationMessages(conversationId);
      setMessages(data.messages);
    } catch (error) {
      console.error('Failed to fetch messages:', error);
    }
  };

  const handleSelectConversation = (conv) => {
    const convId = conv.id || conv._id;
    setSelectedConversation(conv);
    fetchMessages(convId);
  };

  const handleStartConversation = (targetUser) => {
    startConversation({
      receiverId: targetUser.uid,
      receiverName: targetUser.name,
      receiverEmail: targetUser.email
    });
    setShowNewDM(false);
  };

  const getInitials = (name) => {
    return name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??';
  };

  // Filter online users for new DM
  const filteredUsers = onlineUsers.filter(u => 
    u.uid !== user?.uid &&
    (searchQuery === '' || (u.name || '').toLowerCase().includes(searchQuery.toLowerCase()))
  );

  return (
    <div className="h-full flex flex-col">
      {/* Header */}
      <div className="p-4 border-b border-border flex items-center justify-between">
        <h3 className="font-semibold text-foreground">Direct Messages</h3>
        <button
          onClick={() => setShowNewDM(true)}
          className="p-1.5 text-primary hover:bg-primary/20 rounded-lg"
        >
          <Plus className="w-5 h-5" />
        </button>
      </div>

      {/* Conversations List */}
      <div className="flex-1 overflow-y-auto">
        {loading ? (
          <div className="p-4 space-y-3">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="animate-pulse flex gap-3">
                <div className="w-10 h-10 bg-muted rounded-full" />
                <div className="flex-1 space-y-2">
                  <div className="w-24 h-4 bg-muted rounded" />
                  <div className="w-32 h-3 bg-muted rounded" />
                </div>
              </div>
            ))}
          </div>
        ) : conversations.length > 0 ? (
          <div className="py-2">
            {conversations.map(conv => {
              const convId = conv.id || conv._id;
              const selectedId = selectedConversation?.id || selectedConversation?._id;
              const otherUser = conv.otherParticipant;
              const isOnline = conv.isOnline;
              const unreadCount = conv.unreadCount || 0;

              return (
                <button
                  key={convId}
                  onClick={() => handleSelectConversation(conv)}
                  className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors ${
                    selectedId === convId ? 'bg-primary/20' : ''
                  }`}
                >
                  {/* Avatar with online status */}
                  <div className="relative">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-sm font-medium">
                      {otherUser?.avatar ? (
                        <img 
                          src={otherUser.avatar} 
                          alt={otherUser.name}
                          className="w-full h-full rounded-full object-cover"
                        />
                      ) : (
                        getInitials(otherUser?.name)
                      )}
                    </div>
                    <span 
                      className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-background ${
                        isOnline ? 'bg-green-500' : 'bg-muted-foreground/50'
                      }`}
                    />
                  </div>

                  <div className="flex-1 min-w-0 text-left">
                    <div className="flex items-center justify-between">
                      <span className="font-medium text-foreground truncate">
                        {otherUser?.name}
                      </span>
                      {conv.lastMessage?.timestamp && (
                        <span className="text-xs text-muted-foreground">
                          {formatDistanceToNow(new Date(conv.lastMessage.timestamp), { addSuffix: false })}
                        </span>
                      )}
                    </div>
                    <p className="text-sm text-muted-foreground truncate">
                      {conv.lastMessage?.senderId === user?.uid && 'You: '}
                      {conv.lastMessage?.content || 'No messages yet'}
                    </p>
                  </div>

                  {/* Unread badge */}
                  {unreadCount > 0 && (
                    <span className="w-5 h-5 bg-primary text-primary-foreground text-xs rounded-full flex items-center justify-center">
                      {unreadCount > 9 ? '9+' : unreadCount}
                    </span>
                  )}
                </button>
              );
            })}
          </div>
        ) : (
          <div className="p-6 text-center text-muted-foreground">
            <p className="text-sm">No conversations yet</p>
            <button
              onClick={() => setShowNewDM(true)}
              className="mt-2 text-primary hover:text-primary/80 text-sm font-medium"
            >
              Start a conversation
            </button>
          </div>
        )}
      </div>

      {/* New DM Modal */}
      {showNewDM && (
        <div className="fixed inset-0 bg-background/80 flex items-center justify-center z-50 p-4">
          <div className="bg-card border border-border rounded-xl shadow-xl max-w-md w-full">
            <div className="flex items-center justify-between p-4 border-b border-border">
              <h3 className="font-semibold text-foreground">New Message</h3>
              <button
                onClick={() => setShowNewDM(false)}
                className="p-1 text-muted-foreground hover:text-foreground"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-4">
              {/* Search */}
              <div className="relative mb-4">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Search users..."
                  className="w-full pl-10 pr-4 py-2 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary"
                />
              </div>

              {/* Online Users */}
              <div className="max-h-64 overflow-y-auto">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider mb-2">
                  Online Users
                </p>
                {filteredUsers.length > 0 ? (
                  <div className="space-y-1">
                    {filteredUsers.map(u => (
                      <button
                        key={u.uid}
                        onClick={() => handleStartConversation(u)}
                        className="w-full flex items-center gap-3 px-3 py-2 hover:bg-muted rounded-lg"
                      >
                        <div className="relative">
                          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium">
                            {getInitials(u.name)}
                          </div>
                          <Circle className="absolute -bottom-0.5 -right-0.5 w-3 h-3 text-green-500 fill-green-500" />
                        </div>
                        <span className="font-medium text-foreground">{u.name}</span>
                      </button>
                    ))}
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground text-center py-4">
                    No users found
                  </p>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { useState } from 'react';
import { useSocket } from '../../hooks/useSocket';
import { useAuth } from '../../hooks/useAuth';
import { 
  MoreHorizontal, 
  Reply, 
  Smile, 
  Edit2, 
  Trash2, 
  Pin,
  Copy,
  Check
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

const QUICK_REACTIONS = ['👍', '❤️', '😂', '🎉', '🔥', '👏'];

export default function MessageBubble({ message, isOwn, showAvatar, channelId, onOptimisticReaction, onOptimisticEdit, onOptimisticDelete }) {
  const { addReaction, removeReaction, editMessage, deleteMessage } = useSocket();
  const { user } = useAuth();
  const [showActions, setShowActions] = useState(false);
  const [showReactions, setShowReactions] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState(message.content);
  const [copied, setCopied] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);

  const handleReaction = (emoji) => {
    const messageId = message.id || message._id;
    const hasReacted = message.reactions?.some(
      r => r.emoji === emoji && r.users.some(u => u.uid === user?.uid)
    );

    if (hasReacted) {
      // Optimistic update - immediately show removal
      onOptimisticReaction?.({ messageId, emoji, action: 'remove' });
      removeReaction(messageId, emoji);
    } else {
      // Optimistic update - immediately show addition
      onOptimisticReaction?.({ messageId, emoji, action: 'add' });
      addReaction(messageId, emoji);
    }
    setShowReactions(false);
  };

  const handleEdit = () => {
    const messageId = message.id || message._id;
    if (editContent.trim() && editContent !== message.content) {
      // Optimistic update - immediately show edited content
      onOptimisticEdit?.({ messageId, content: editContent.trim() });
      editMessage(messageId, editContent.trim());
    }
    setIsEditing(false);
  };

  const confirmDelete = () => {
    const messageId = message.id || message._id;
    // Optimistic update - immediately show as deleted
    onOptimisticDelete?.({ messageId });
    deleteMessage(messageId);
    setShowConfirmDelete(false);
  };

  const handleCopy = async () => {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(message.content);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      } else {
        // Fallback for older browsers or insecure contexts
        const textarea = document.createElement('textarea');
        textarea.value = message.content;
        textarea.style.position = 'fixed';
        textarea.style.left = '-999999px';
        textarea.setAttribute('readonly', '');
        document.body.appendChild(textarea);
        textarea.select();
        const success = document.execCommand('copy');
        document.body.removeChild(textarea);
        if (success) {
          setCopied(true);
          setTimeout(() => setCopied(false), 2000);
        } else {
          throw new Error('Fallback copy command failed');
        }
      }
    } catch (error) {
      console.error('Failed to copy message:', error);
    }
  };

  const getInitials = (name) => {
    return name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '??';
  };

  const formattedTime = message.createdAt 
    ? formatDistanceToNow(new Date(message.createdAt), { addSuffix: true }) 
    : '';

  if (message.isDeleted) {
    return (
      <div className={`flex gap-3 ${isOwn ? 'flex-row-reverse' : ''}`}>
        <div className="w-8" />
        <div className="bg-muted rounded-lg px-4 py-2 text-muted-foreground italic text-sm">
          This message was deleted
        </div>
      </div>
    );
  }

  return (
    <div 
      className={`group flex gap-3 hover:bg-muted/50 -mx-2 px-2 py-1 rounded-lg ${
        isOwn ? 'flex-row-reverse' : ''
      }`}
      onMouseEnter={() => setShowActions(true)}
      onMouseLeave={() => {
        setShowActions(false);
        setShowReactions(false);
      }}
    >
      {/* Avatar */}
      {showAvatar ? (
        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-xs font-medium shrink-0">
          {message.sender.avatar ? (
            <img 
              src={message.sender.avatar} 
              alt={message.sender.name}
              className="w-full h-full rounded-full object-cover"
            />
          ) : (
            getInitials(message.sender.name)
          )}
        </div>
      ) : (
        <div className="w-8 shrink-0" />
      )}

      {/* Message Content */}
      <div className={`flex-1 min-w-0 ${isOwn ? 'text-right' : ''}`}>
        {showAvatar && (
          <div className={`flex items-baseline gap-2 mb-0.5 ${isOwn ? 'flex-row-reverse' : ''}`}>
            <span className="font-medium text-sm text-foreground">
              {message.sender.name}
            </span>
            <span className="text-xs text-muted-foreground">{formattedTime}</span>
          </div>
        )}

        {/* Reply Preview */}
        {message.replyToPreview && (
          <div className={`mb-1 ${isOwn ? 'ml-auto' : 'mr-auto'} max-w-sm`}>
            <div className="text-xs text-muted-foreground bg-muted rounded px-2 py-1 border-l-2 border-primary">
              <span className="font-medium">{message.replyToPreview.senderName}</span>
              <p className="truncate">{message.replyToPreview.content}</p>
            </div>
          </div>
        )}

        {/* Message Bubble */}
        <div className={`relative inline-block ${isOwn ? 'text-left' : ''}`}>
          {isEditing ? (
            <div className="flex gap-2">
              <input
                type="text"
                value={editContent}
                onChange={(e) => setEditContent(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleEdit()}
                className="flex-1 px-3 py-1.5 bg-muted border border-border rounded-lg text-sm text-foreground focus:ring-2 focus:ring-primary"
                autoFocus
              />
              <button
                onClick={handleEdit}
                className="px-3 py-1 bg-primary text-primary-foreground rounded-lg text-sm"
              >
                Save
              </button>
              <button
                onClick={() => setIsEditing(false)}
                className="px-3 py-1 bg-muted-foreground/20 text-foreground rounded-lg text-sm"
              >
                Cancel
              </button>
            </div>
          ) : (
            <div
              className={`rounded-2xl px-4 py-2 max-w-lg ${
                isOwn 
                  ? 'bg-primary text-primary-foreground rounded-br-md' 
                  : 'bg-card border border-border text-foreground rounded-bl-md'
              }`}
            >
           <ReactMarkdown
  remarkPlugins={[remarkGfm]}
  disallowedElements={['img']}
  components={{
    a: ({ node, ...props }) => (
      <a {...props} target="_blank" rel="noopener noreferrer" />
    ),
  }}
  className="prose prose-invert prose-sm max-w-none break-words text-sm"
>
  {message.content}
</ReactMarkdown>
              {message.isEdited && (
                <span className={`text-xs ${isOwn ? 'text-primary-foreground/70' : 'text-muted-foreground'}`}>
                  (edited)
                </span>
              )}
            </div>
          )}

          {/* Attachments */}
          {message.attachments?.length > 0 && (
            <div className="mt-2 space-y-2">
              {message.attachments.map((attachment, index) => (
                <div key={index} className="inline-block">
                  {attachment.type?.startsWith('image/') ? (
                    <img 
                      src={attachment.url} 
                      alt={attachment.name}
                      className="max-w-xs rounded-lg"
                    />
                  ) : (
                    <a
                      href={attachment.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center gap-2 px-3 py-2 bg-muted rounded-lg text-sm text-foreground hover:bg-muted/80"
                    >
                      📎 {attachment.name}
                    </a>
                  )}
                </div>
              ))}
            </div>
          )}

          {/* Reactions */}
          {message.reactions?.length > 0 && (
            <div className={`flex gap-1 mt-1 flex-wrap ${isOwn ? 'justify-end' : ''}`}>
              {message.reactions.map((reaction, index) => (
                <button
                  key={index}
                  onClick={() => handleReaction(reaction.emoji)}
                  className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs transition-colors ${
                    reaction.users.some(u => u.uid === user?.uid)
                      ? 'bg-primary/20 text-primary border border-primary/50'
                      : 'bg-muted text-muted-foreground hover:bg-muted/80'
                  }`}
                >
                  <span>{reaction.emoji}</span>
                  <span>{reaction.users.length}</span>
                </button>
              ))}
            </div>
          )}

          {/* Action Buttons */}
          {showActions && !isEditing && (
            <div 
              className={`absolute ${isOwn ? 'left-0 -translate-x-full' : 'right-0 translate-x-full'} top-0 px-2`}
            >
              <div className="flex items-center gap-1 bg-card border border-border rounded-lg shadow-sm p-1">
                {/* Quick Reaction */}
                <div className="relative">
                  <button
                    onClick={() => setShowReactions(!showReactions)}
                    className="p-1.5 text-muted-foreground hover:text-foreground hover:bg-muted rounded"
                  >
                    <Smile className="w-4 h-4" />
                  </button>

                  {showReactions && (
                    <div className="absolute bottom-full mb-1 left-0 bg-card border border-border rounded-lg shadow-lg p-1 flex gap-1">
                      {QUICK_REACTIONS.map(emoji => (
                        <button
                          key={emoji}
                          onClick={() => handleReaction(emoji)}
                          className="p-1 hover:bg-muted rounded text-lg"
                        >
                          {emoji}
                        </button>
                      ))}
                    </div>
                  )}
                </div>

                {/* Copy */}
                <button 
                  onClick={handleCopy}
                  className="p-1.5 text-muted-foreground hover:text-foreground hover:bg-muted rounded"
                >
                  {copied ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                </button>

                {/* Edit & Delete (only for own messages) */}
                {isOwn && (
                  <>
                    <button
                      onClick={() => setIsEditing(true)}
                      className="p-1.5 text-muted-foreground hover:text-foreground hover:bg-muted rounded"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    {showConfirmDelete ? (
                      <div className="flex items-center gap-1 bg-destructive/10 rounded p-0.5">
                        <button
                          onClick={confirmDelete}
                          className="text-[10px] text-destructive hover:underline px-1"
                        >
                          Confirm
                        </button>
                        <button
                          onClick={() => setShowConfirmDelete(false)}
                          className="text-[10px] text-muted-foreground hover:underline px-1"
                        >
                          Cancel
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => setShowConfirmDelete(true)}
                        className="p-1.5 text-muted-foreground hover:text-destructive hover:bg-destructive/10 rounded"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    )}
                  </>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { formatDistanceToNow, format } from 'date-fns';
import {
  Heart,
  MessageCircle,
  Share2,
  Bookmark,
  Eye,
  ChevronDown,
  ChevronUp,
  Clock,
  X
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import CommentSection from './CommentSection';

export default function PostCard({
  post,
  currentUser,
  onLike,
  onCommentAdded,
  onCancelSchedule
}) {
  const [showFullContent, setShowFullContent] = useState(false);
  const [showComments, setShowComments] = useState(false);
  const [commentCount, setCommentCount] = useState(post.commentCount || 0);

  const isOwn = post.author.uid === currentUser?.uid;

  const isLiked = post.likes?.some(
    l => l.uid === currentUser?.uid
  );

  const contentPreviewLength = 300;

  const shouldTruncate =
    post.content.length > contentPreviewLength;

  const rawPreview = post.content.slice(
    0,
    contentPreviewLength
  );

  const safePreview = rawPreview
    .replace(/\s+\S*$/, '')
    .trim();

  const previewText =
    safePreview.length > 0
      ? safePreview
      : rawPreview;

  const handleCommentAdded = () => {
    setCommentCount(prev => prev + 1);
    onCommentAdded?.();
  };

  const getInitials = name => {
    return (
      name
        ?.split(' ')
        .map(n => n[0])
        .join('')
        .toUpperCase()
        .slice(0, 2) || '??'
    );
  };

  const getCategoryStyle = category => {
    const styles = {
      experience: 'bg-blue-500/20 text-blue-400',
      interview: 'bg-purple-500/20 text-purple-400',
      tips: 'bg-yellow-500/20 text-yellow-400',
      question: 'bg-green-500/20 text-green-400',
      'success-story': 'bg-pink-500/20 text-pink-400',
      resource: 'bg-orange-500/20 text-orange-400',
      discussion: 'bg-muted text-muted-foreground'
    };

    return styles[category] || styles.discussion;
  };

  const getCategoryIcon = category => {
    const icons = {
      experience: '💼',
      interview: '🎤',
      tips: '💡',
      question: '❓',
      'success-story': '🎉',
      resource: '📚',
      discussion: '💬'
    };

    return icons[category] || '💬';
  };

  const handleShare = async () => {
    const postId = post.id || post._id;

    try {
      await navigator.share({
        title: post.title,
        text: post.content.substring(0, 100) + '...',
        url:
          window.location.origin +
          `/community/post/${postId}`
      });
    } catch {
      navigator.clipboard.writeText(
        window.location.origin +
          `/community/post/${postId}`
      );
    }
  };

  return (
    <article className="bg-card border border-border rounded-xl hover:border-primary/30 transition-all duration-300 shadow-sm overflow-hidden group">
      {/* Header */}
      <div className="p-4 pb-0">
        <div className="flex items-start justify-between">
          <div className="flex items-center gap-3">
            {/* Avatar */}
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-primary-foreground text-sm font-medium">
              {post.author.avatar ? (
                <img
                  src={post.author.avatar}
                  alt={post.author.name}
                  className="w-full h-full rounded-full object-cover"
                />
              ) : (
                getInitials(post.author.name)
              )}
            </div>

            <div>
              <div className="flex items-center gap-2">
                <span className="font-medium text-foreground">
                  {post.author.name}
                </span>

                {post.author.jobRole && (
                  <span className="text-xs text-muted-foreground">
                    • {post.author.jobRole}
                  </span>
                )}
              </div>

              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                <span>
                  {formatDistanceToNow(
                    new Date(post.createdAt),
                    { addSuffix: true }
                  )}
                </span>

                {post.isEdited && (
                  <span>• edited</span>
                )}

                <span className="flex items-center gap-1">
                  <Eye className="w-3 h-3" />
                  {post.views || 0}
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* Category */}
        <div className="mt-3 flex items-center gap-2 flex-wrap">
          <span
            className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${getCategoryStyle(
              post.category
            )}`}
          >
            {getCategoryIcon(post.category)}
            {post.category?.replace('-', ' ')}
          </span>

          {post.isPinned && (
            <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-amber-500/20 text-amber-400">
              📌 Pinned
            </span>
          )}

          {post.status === 'scheduled' &&
            post.scheduledAt && (
              <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-sky-500/20 text-sky-400">
                <Clock className="w-3 h-3" />
                Scheduled ·{' '}
                {format(
                  new Date(post.scheduledAt),
                  'MMM d, h:mm a'
                )}
              </span>
            )}

          {post.status === 'draft' && (
            <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-neutral-600/40 text-neutral-400">
              Draft
            </span>
          )}
        </div>

        {/* Scheduled Banner */}
        {post.status === 'scheduled' &&
          post.scheduledAt &&
          isOwn &&
          onCancelSchedule && (
            <div className="mt-2 flex items-center justify-between px-3 py-2 bg-sky-500/10 border border-sky-500/20 rounded-lg">
              <p className="text-xs text-sky-400">
                This post will publish automatically on{' '}
                <span className="font-medium">
                  {format(
                    new Date(post.scheduledAt),
                    "MMM d, yyyy 'at' h:mm a"
                  )}
                </span>
              </p>

              <button
                onClick={() =>
                  onCancelSchedule(
                    post.id || post._id
                  )
                }
                className="flex items-center gap-1 text-xs text-neutral-400 hover:text-red-400 ml-3 flex-shrink-0 transition-colors"
              >
                <X className="w-3.5 h-3.5" />
                Cancel
              </button>
            </div>
          )}
      </div>

      {/* Content */}
      <div className="p-4 py-3">
        <h3 className="text-lg font-semibold text-foreground mb-2 line-clamp-2">
          {post.title}
        </h3>

        <div className="prose prose-sm max-w-none text-muted-foreground dark:prose-invert">
          {shouldTruncate &&
          !showFullContent ? (
            <>
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                disallowedElements={['script', 'iframe', 'style']}
                components={{
                  a: ({ node, ...props }) => (
                    <a {...props} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline" />
                  ),
                }}
              >
                {previewText + '...'}
              </ReactMarkdown>

              <button
                onClick={() =>
                  setShowFullContent(true)
                }
                className="text-primary hover:text-primary/80 font-medium text-sm"
              >
                Read more
              </button>
            </>
          ) : (
            <>
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                disallowedElements={['script', 'iframe', 'style']}
                components={{
                  a: ({ node, ...props }) => (
                    <a {...props} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline" />
                  ),
                }}
              >
                {post.content}
              </ReactMarkdown>
              {shouldTruncate && (
                <button
                  onClick={() => setShowFullContent(false)}
                  className="text-primary hover:text-primary/80 font-medium text-sm mt-2 block"
                >
                  Show less
                </button>
              )}
            </>
          )}
        </div>
      </div>

      {/* Attachments */}
      {post.attachments?.length > 0 && (
        <div className="px-4 pb-3">
          <div className="flex flex-wrap gap-3">
            {post.attachments.map((att, index) => {
              const ext = att.name
                ?.split('.')
                .pop()
                ?.toLowerCase();

              const icon = {
                pdf: '📄',
                doc: '📝',
                docx: '📝',
                ppt: '📊',
                pptx: '📊',
                txt: '📃',
                png: '🖼️',
                jpg: '🖼️',
                jpeg: '🖼️',
                gif: '🖼️',
                webp: '🖼️'
              }[ext] || '📎';

              // Image preview
              if (
                att.type?.startsWith('image/') &&
                att.url
              ) {
                return (
                  <div
                    key={index}
                    className="flex-shrink-0"
                  >
                    <img
                      src={att.url}
                      alt={att.name}
                      className="max-h-64 rounded-xl border border-border object-cover"
                    />
                  </div>
                );
              }

              // Clickable document card
              if (att.url) {
                return (
                  <a
                    key={index}
                    href={att.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="block"
                  >
                    <div className="flex items-center gap-3 px-4 py-3 bg-muted border border-border rounded-xl text-sm text-foreground hover:border-primary/40 hover:bg-muted/80 transition-colors cursor-pointer">
                      <span className="text-2xl flex-shrink-0">
                        {icon}
                      </span>

                      <div className="min-w-0">
                        <p className="font-medium truncate max-w-[200px]">
                          {att.name}
                        </p>

                        <p className="text-xs text-muted-foreground uppercase">
                          {ext} file
                        </p>
                      </div>
                    </div>
                  </a>
                );
              }

              // Fallback card
              return (
                <div
                  key={index}
                  className="flex items-center gap-3 px-4 py-3 bg-muted border border-border rounded-xl text-sm text-foreground"
                >
                  <span className="text-2xl flex-shrink-0">
                    {icon}
                  </span>

                  <div className="min-w-0">
                    <p className="font-medium truncate max-w-[200px]">
                      {att.name}
                    </p>

                    <p className="text-xs text-muted-foreground uppercase">
                      {ext} file
                    </p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Actions */}
      <div className="px-4 py-3 border-t border-border flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button
            onClick={() =>
              onLike(post.id || post._id)
            }
            className={`flex items-center gap-1.5 text-sm transition-colors ${
              isLiked
                ? 'text-red-500'
                : 'text-muted-foreground hover:text-red-500'
            }`}
          >
            <Heart
              className={`w-5 h-5 ${
                isLiked ? 'fill-current' : ''
              }`}
            />

            <span>
              {Math.max(
                0,
                post.likes?.length ||
                  post.likeCount ||
                  0
              )}
            </span>
          </button>

          {/* Comments */}
          <button
            onClick={() =>
              setShowComments(!showComments)
            }
            className={`flex items-center gap-1.5 text-sm transition-colors ${
              showComments
                ? 'text-primary'
                : 'text-muted-foreground hover:text-primary'
            }`}
          >
            <MessageCircle
              className={`w-5 h-5 ${
                showComments
                  ? 'fill-primary/20'
                  : ''
              }`}
            />

            <span>{commentCount}</span>

            {showComments ? (
              <ChevronUp className="w-4 h-4" />
            ) : (
              <ChevronDown className="w-4 h-4" />
            )}
          </button>

          {/* Share */}
          <button
            onClick={handleShare}
            className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-primary"
          >
            <Share2 className="w-5 h-5" />
          </button>
        </div>

        <button
          onClick={handleShare}
          className="p-1.5 rounded-lg hover:bg-muted text-muted-foreground hover:text-foreground transition-colors"
          title="Share Post"
        >
          <Share2 className="w-4 h-4" />
        </button>
      </div>

      {/* Comments Section */}
      {showComments && (
        <CommentSection
          postId={post.id || post._id}
          currentUser={currentUser}
          onCommentAdded={
            handleCommentAdded
          }
        />
      )}
    </article>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '../../hooks/useAuth';
import { useSocket } from '../../hooks/useSocket';
import { communityApi } from '../../services/api';
import PostCard from './PostCard';
import PostEditor from './PostEditor';
import {
  Plus,
  TrendingUp,
  Clock,
  Heart,
  Filter,
  Search,
  X,
  ChevronDown,
  ChevronUp
} from 'lucide-react';
import toast from 'react-hot-toast';

const CATEGORIES = [
  { value: 'all', label: 'All Posts', icon: '📋' },
  { value: 'experience', label: 'Experience', icon: '💼' },
  { value: 'interview', label: 'Interview', icon: '🎤' },
  { value: 'tips', label: 'Tips & Tricks', icon: '💡' },
  { value: 'question', label: 'Questions', icon: '❓' },
  { value: 'success-story', label: 'Success Stories', icon: '🎉' },
  { value: 'resource', label: 'Resources', icon: '📚' },
  { value: 'discussion', label: 'Discussion', icon: '💬' },
];

export default function PostsFeed() {
  const { user } = useAuth();
  const { subscribe, subscribePosts, unsubscribePosts, isConnected } = useSocket();
  
  const [posts, setPosts] = useState([]);
  const [scheduledPosts, setScheduledPosts] = useState([]);
  const [showScheduled, setShowScheduled] = useState(true);
  const [loading, setLoading] = useState(true);
  const [showEditor, setShowEditor] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [sortBy, setSortBy] = useState('latest');
  const [searchQuery, setSearchQuery] = useState('');
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Fetch scheduled posts helper
  const fetchScheduledPosts = useCallback(async () => {
    try {
      const data = await communityApi.getScheduledPosts();
      setScheduledPosts(data.posts || []);
    } catch {
      // Silently ignore — not critical
    }
  }, []);

  // Fetch posts helper
  const fetchPosts = useCallback(async (pageToFetch, isLoadMore) => {
    try {
      if (!isLoadMore) {
        setLoading(true);
      }

      const params = {
        page: pageToFetch,
        limit: 20,
        sortBy,
        ...(selectedCategory !== 'all' && { category: selectedCategory })
      };

      const data = await communityApi.getPosts(params);
      
      if (isLoadMore) {
        setPosts(prev => [...prev, ...data.posts]);
      } else {
        setPosts(data.posts);
      }
      
      setHasMore(data.pagination.hasMore);
    } catch (error) {
      toast.error('Failed to load posts');
    } finally {
      setLoading(false);
    }
  }, [sortBy, selectedCategory]);

  const handleLoadMore = () => {
    const nextPage = page + 1;
    setPage(nextPage);
    fetchPosts(nextPage, true);
  };

  // Fetch posts on mount and when filters change
  useEffect(() => {
    setPage(1);
    fetchPosts(1, false);
  }, [selectedCategory, sortBy, fetchPosts]);

  // Refetch scheduled posts whenever the logged-in user changes
  useEffect(() => {
    if (user) {
      fetchScheduledPosts();
    } else {
      setScheduledPosts([]);
    }
  }, [user, fetchScheduledPosts]);

  // Subscribe to real-time updates
  useEffect(() => {
    subscribePosts();

    const unsubNewPost = subscribe('new_post', ({ post }) => {
      setPosts(prev => {
        const postId = post.id || post._id;
        if (prev.some(p => (p.id || p._id) === postId)) {
          return prev;
        }
        return [post, ...prev];
      });
    });

    const unsubLikeUpdated = subscribe('post_like_updated', ({ postId, likeCount, likes }) => {
      // Only update if it's from another user's action (prevents duplicate updates from our own likes)
      setPosts(prev => prev.map(post => {
        const pId = post.id || post._id;
        if (pId === postId) {
          // Check if the like count is different to avoid unnecessary re-renders
          if (post.likeCount !== likeCount) {
            return { ...post, likeCount, likes };
          }
        }
        return post;
      }));
    });

    const unsubCommentAdded = subscribe('comment_added', ({ postId, commentCount }) => {
      setPosts(prev => prev.map(post => {
        const pId = post.id || post._id;
        return pId === postId ? { ...post, commentCount } : post;
      }));
    });

    return () => {
      unsubscribePosts();
      unsubNewPost();
      unsubLikeUpdated();
      unsubCommentAdded();
    };
  }, [subscribe, subscribePosts, unsubscribePosts]);


const handleCreatePost = async (postData) => {
  if (isSubmitting) return; // Prevent double-click submissions

  setIsSubmitting(true);

  try {
    const data = await communityApi.createPost(postData);

    if (data.post.status === 'scheduled') {
      setScheduledPosts(prev => {
        const postId = data.post.id || data.post._id;

        if (prev.some(p => (p.id || p._id) === postId)) {
          return prev;
        }

        return [data.post, ...prev].sort(
          (a, b) =>
            new Date(a.scheduledAt) -
            new Date(b.scheduledAt)
        );
      });

      setShowEditor(false);

      toast.success('Post scheduled successfully!');
    } else {
      // Insert immediately for responsive UX.
      // Socket listener already has duplicate protection.
      setPosts(prev => {
        const postId =
          data.post.id || data.post._id;

        if (
          prev.some(
            p => (p.id || p._id) === postId
          )
        ) {
          return prev;
        }

        return [data.post, ...prev];
      });

      setShowEditor(false);

      toast.success(
        'Post created successfully!'
      );
    }
  } catch (error) {
    toast.error(error.message);
  } finally {
    setIsSubmitting(false);
  }
};

  const handleCancelScheduled = async (postId) => {
    try {
      await communityApi.cancelScheduledPost(postId);
      setScheduledPosts(prev => prev.filter(p => (p.id || p._id) !== postId));
      toast.success('Scheduled post cancelled');
    } catch (error) {
      toast.error(error.message || 'Failed to cancel scheduled post');
    }
  };

  const handleLikePost = async (postId) => {
    // Optimistic update - immediately show the change
    setPosts(prev => prev.map(post => {
      const pId = post.id || post._id;
      if (pId === postId) {
        const currentLikes = post.likes || [];
        const isCurrentlyLiked = currentLikes.some(l => l.uid === user?.uid);
        
        if (isCurrentlyLiked) {
          // Unlike - remove user from likes
          return {
            ...post,
            likes: currentLikes.filter(l => l.uid !== user?.uid),
            likeCount: Math.max(0, (post.likeCount || currentLikes.length) - 1)
          };
        } else {
          // Like - add user to likes
          return {
            ...post,
            likes: [...currentLikes, { uid: user?.uid, name: user?.displayName || user?.name }],
            likeCount: (post.likeCount || currentLikes.length) + 1
          };
        }
      }
      return post;
    }));

    try {
      // Call API in background - socket will confirm the update
      await communityApi.toggleLikePost(postId);
    } catch (error) {
      // Revert on error - toggle back
      setPosts(prev => prev.map(post => {
        const pId = post.id || post._id;
        if (pId === postId) {
          const currentLikes = post.likes || [];
          const isCurrentlyLiked = currentLikes.some(l => l.uid === user?.uid);
          
          if (isCurrentlyLiked) {
            return {
              ...post,
              likes: currentLikes.filter(l => l.uid !== user?.uid),
              likeCount: Math.max(0, (post.likeCount || currentLikes.length) - 1)
            };
          } else {
            return {
              ...post,
              likes: [...currentLikes, { uid: user?.uid, name: user?.displayName || user?.name }],
              likeCount: (post.likeCount || currentLikes.length) + 1
            };
          }
        }
        return post;
      }));
      toast.error('Failed to like post');
    }
  };

  const handleDeletePost = async (postId) => {
    try {
      await communityApi.deletePost(postId);
      setPosts(prev => prev.filter(post => {
        const pId = post.id || post._id;
        return pId !== postId;
      }));
      toast.success('Post deleted');
    } catch (error) {
      toast.error(error.message);
    }
  };

  // Filter posts by search
  const filteredPosts = searchQuery
    ? posts.filter(post => 
        post.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        post.content.toLowerCase().includes(searchQuery.toLowerCase()) ||
        post.tags?.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()))
      )
    : posts;

  return (
    <div className="h-full flex flex-col bg-background">
      {/* Header */}
      <div className="bg-background border-b border-border px-6 py-4">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-bold text-foreground">Community Discussions</h2>
          <button
            onClick={() => setShowEditor(true)}
            className="flex items-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
          >
            <Plus className="w-4 h-4" />
            New Post
          </button>
        </div>

        {/* Filters */}
        <div className="flex flex-wrap gap-3 items-center">
          {/* Sort Options */}
          <div className="flex gap-1 bg-muted p-1 rounded-lg">
            <button
              onClick={() => setSortBy('latest')}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                sortBy === 'latest' ? 'bg-card shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <Clock className="w-4 h-4" />
              Latest
            </button>
            <button
              onClick={() => setSortBy('popular')}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                sortBy === 'popular' ? 'bg-card shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <Heart className="w-4 h-4" />
              Popular
            </button>
            <button
              onClick={() => setSortBy('trending')}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                sortBy === 'trending' ? 'bg-card shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <TrendingUp className="w-4 h-4" />
              Trending
            </button>
          </div>

          {/* Search */}
          <div className="relative flex-1 min-w-[200px] max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search posts..."
              className="w-full pl-10 pr-4 py-2 bg-muted border border-border rounded-lg text-sm text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-primary"
            />
            {searchQuery && (
              <button
                onClick={() => setSearchQuery('')}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
              >
                <X className="w-4 h-4" />
              </button>
            )}
          </div>
        </div>

        {/* Category Tabs */}
        <div className="flex gap-2 mt-4 overflow-x-auto pb-2">
          {CATEGORIES.map(cat => (
            <button
              key={cat.value}
              onClick={() => setSelectedCategory(cat.value)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm whitespace-nowrap transition-colors ${
                selectedCategory === cat.value
                  ? 'bg-primary/20 text-primary font-medium'
                  : 'bg-muted text-muted-foreground hover:bg-muted/80'
              }`}
            >
              <span>{cat.icon}</span>
              {cat.label}
            </button>
          ))}
        </div>
      </div>

      {/* Posts List */}
      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-3xl mx-auto space-y-4">
          {/* Scheduled posts section — only shown to the post author */}
          {scheduledPosts.length > 0 && (
            <div className="border border-sky-500/20 rounded-xl overflow-hidden">
              <button
                onClick={() => setShowScheduled(prev => !prev)}
                className="w-full flex items-center justify-between px-4 py-3 bg-sky-500/10 hover:bg-sky-500/15 transition-colors"
              >
                <div className="flex items-center gap-2 text-sky-400 text-sm font-medium">
                  <Clock className="w-4 h-4" />
                  Scheduled Posts ({scheduledPosts.length})
                </div>
                {showScheduled
                  ? <ChevronUp className="w-4 h-4 text-sky-400" />
                  : <ChevronDown className="w-4 h-4 text-sky-400" />
                }
              </button>
              {showScheduled && (
                <div className="divide-y divide-neutral-800/50 bg-neutral-900/50">
                  {scheduledPosts.map(post => {
                    const postId = post.id || post._id;
                    return (
                      <PostCard
                        key={postId}
                        post={post}
                        currentUser={user}
                        onLike={() => {}}
                        onCancelSchedule={handleCancelScheduled}
                      />
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {loading ? (
            [...Array(3)].map((_, i) => (
              <div key={i} className="bg-muted border border-border rounded-xl p-6 animate-pulse">
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-10 h-10 bg-muted-foreground/20 rounded-full" />
                  <div className="space-y-2">
                    <div className="w-32 h-4 bg-muted-foreground/20 rounded" />
                    <div className="w-24 h-3 bg-muted-foreground/20 rounded" />
                  </div>
                </div>
                <div className="space-y-2">
                  <div className="w-3/4 h-5 bg-muted-foreground/20 rounded" />
                  <div className="w-full h-4 bg-muted-foreground/20 rounded" />
                  <div className="w-2/3 h-4 bg-muted-foreground/20 rounded" />
                </div>
              </div>
            ))
          ) : filteredPosts.length > 0 ? (
            <>
              {filteredPosts.map(post => {
                const postId = post.id || post._id;
                return (
                  <PostCard
                    key={postId}
                    post={post}
                    currentUser={user}
                    onLike={handleLikePost}
                    onDelete={handleDeletePost}
                    onCancelSchedule={handleCancelScheduled}
                    onCommentAdded={() => {
                      // Update comment count in local state
                      setPosts(prev => prev.map(p => {
                        const pId = p.id || p._id;
                        return pId === postId 
                          ? { ...p, commentCount: (p.commentCount || 0) + 1 }
                          : p;
                      }));
                    }}
                  />
                );
              })}

              {hasMore && (
                <motion.button
                  onClick={handleLoadMore}
                  className="w-full py-3 text-primary hover:text-primary/80 font-medium cursor-pointer"
                >
                  Load more posts
                </motion.button>
              )}
            </>
          ) : (
            <div className="text-center py-12">
              <p className="text-4xl mb-3">📝</p>
              <h3 className="text-lg font-medium text-foreground">No posts yet</h3>
              <p className="text-muted-foreground mt-1">Be the first to share your thoughts!</p>
              <button
                onClick={() => setShowEditor(true)}
                className="mt-4 px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90"
              >
                Create Post
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Post Editor Modal */}
      {showEditor && (
        <PostEditor
          onClose={() => setShowEditor(false)}
          onSubmit={handleCreatePost}
        />
      )}
    </div>
  );
}

