import React, { useMemo, useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import Hero from './Hero';
import About from './About';
import Skills from './Skills';
import Projects from './Projects';
import Experience from './Experience';
import Testimonials from './Testimonials';
import FooterContact from './FooterContact';

// Required data import per issue description
import data from '../../../../data/dummy_data.json';

const colors = ['#E3000F', '#00509E', '#FFD700', '#000000', '#FFFFFF'];

const BauhausPortfolioIntegrated = () => {
  // Bauhaus Primary Palette
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const update = () => setIsMobile(typeof window !== 'undefined' && window.innerWidth < 768);
    update();
    window.addEventListener('resize', update);
    return () => window.removeEventListener('resize', update);
  }, []);

  // Generate static random values for background shapes so they don't jump on re-renders
  // Optimized for mobile performance (removed blur filters which break mobile renderers)
  const backgroundShapes = useMemo(() => {
    const brightCount = isMobile ? 8 : 20;
    const darkCount = isMobile ? 5 : 12;

    const brightShapes = Array.from({ length: brightCount }).map((_, i) => {
      const size = Math.random() * 60 + 20; // Slightly smaller base sizes for mobile
      const isTriangle = Math.random() > 0.7;
      return {
        id: `bright-${i}`,
        kind: 'bright',
        size,
        color: colors[Math.floor(Math.random() * 3)],
        isCircle: Math.random() > 0.5,
        isTriangle,
        left: `${Math.random() * 100}%`,
        top: `${Math.random() * 100}%`,
        // shorter durations = faster motion
        duration: Math.random() * (isMobile ? 6 : 10) + (isMobile ? 4 : 6),
        delay: Math.random() * -20
      };
    });

    const darkShapes = Array.from({ length: darkCount }).map((_, i) => {
      const size = Math.random() * 100 + 40;
      const points = [
        [0, 10], [18, 0], [44, 8], [70, 2], [100, 18], [92, 52], [100, 78], [72, 100], [38, 92], [12, 100], [0, 74], [8, 42]
      ]
        .map(([x, y]) => `${x}% ${y}%`)
        .join(', ');

      return {
        id: `dark-${i}`,
        kind: 'dark',
        size,
        color: ['#111111', '#171717', '#222222', '#2B2B2B'][i % 4],
        left: `${Math.random() * 100}%`,
        top: `${Math.random() * 100}%`,
        // shorten dark shape cycles for snappier motion
        duration: Math.random() * (isMobile ? 8 : 12) + (isMobile ? 6 : 8),
        delay: Math.random() * -28,
        clipPath: `polygon(${points})`
      };
    });

    return [...brightShapes, ...darkShapes];
  }, [isMobile]);

  // (nameLetters and section variants were moved into the extracted components)

  return (
    <div className="relative min-h-screen bg-[#F4F0EC] text-black overflow-x-hidden font-sans selection:bg-black selection:text-white">
      
      {/* ================= DYNAMIC BACKGROUND ================= */}
      {/* Force hardware acceleration on mobile using transform-gpu */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none z-0 transform-gpu">
        {backgroundShapes.map((shape) => (
          <motion.div
            key={shape.id}
            className="absolute will-change-transform"
            style={{
              width: shape.isTriangle ? 0 : shape.size,
              height: shape.isTriangle ? 0 : shape.size,
              backgroundColor: shape.kind === 'dark' ? shape.color : (shape.isTriangle ? 'transparent' : shape.color),
              borderRadius: shape.kind === 'dark' ? '28% 72% 63% 37% / 46% 39% 61% 54%' : (shape.isCircle && !shape.isTriangle ? '50%' : '0%'),
              borderLeft: shape.kind === 'dark' ? 'none' : (shape.isTriangle ? `${shape.size / 2}px solid transparent` : 'none'),
              borderRight: shape.kind === 'dark' ? 'none' : (shape.isTriangle ? `${shape.size / 2}px solid transparent` : 'none'),
              borderBottom: shape.kind === 'dark' ? 'none' : (shape.isTriangle ? `${shape.size}px solid ${shape.color}` : 'none'),
              left: shape.left,
              top: shape.top,
              clipPath: shape.kind === 'dark' ? shape.clipPath : undefined,
              opacity: shape.kind === 'dark' ? 0.15 : 0.2, // Slightly bumped opacity
              mixBlendMode: 'multiply',
              transformOrigin: 'center'
            }}
            animate={{
              y: shape.kind === 'dark' ? [0, -80, 20, 0] : [0, -100, 0],
              x: shape.kind === 'dark' ? [0, 30, -10, 0] : [0, 0, 0],
              rotate: shape.kind === 'dark' ? [0, 90, 180, 360] : [0, 360],
              scale: shape.kind === 'dark' ? [1, 1.1, 0.95, 1] : [1, 1.2, 1],
            }}
            transition={{
              duration: shape.duration,
              delay: shape.delay,
              repeat: Infinity,
              ease: "linear"
            }}
          />
        ))}
      </div>

      {/* ================= MAIN CONTENT WRAPPER ================= */}
      <div className="relative z-10 w-full max-w-7xl mx-auto bg-[#F4F0EC]/90 md:bg-[#F4F0EC]/80 backdrop-blur-sm border-x-0 md:border-x-4 border-black flex flex-col md:shadow-[24px_0px_0px_0px_rgba(0,0,0,1)]">

        <Hero colors={colors} />
        <About />
        <Skills colors={colors} />
        <Projects />
        <Experience />
        <Testimonials />
        <FooterContact />

      </div>
    </div>
  );
};

export default BauhausPortfolioIntegrated;

import React, { useState, useRef, useEffect } from "react";
import data from "../../../../data/dummy_data.json";
import { Send, Sparkles } from "lucide-react";

export default function ChatbotPortfolio() {
  const [messages, setMessages] = useState([
    {
      type: "bot",
      content: {
        type: "intro",
        text: `Hey 👋 I'm the portfolio assistant for ${data.personal.name}. Ask me about About, Skills, Projects, Experience, Testimonials, or Contact.`,
      },
    },
  ]);

  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const pushMessage = (msg) => {
    setMessages((prev) => [...prev, msg]);
  };

  const generateResponse = (text) => {
    const msg = text.toLowerCase();

    // ABOUT
    if (msg.includes("about")) {
      return {
        type: "bot",
        content: {
          type: "about",
          name: data.personal.name,
          title: data.personal.title,
          bio: data.personal.bio,
          location: data.personal.location,
          avatar: data.personal.avatar,
        },
      };
    }

    // SKILLS
    if (msg.includes("skill")) {
      return {
        type: "bot",
        content: {
          type: "skills",
          skills: data.skills,
        },
      };
    }

    // PROJECTS
    if (msg.includes("project")) {
      return {
        type: "bot",
        content: {
          type: "projects",
          projects: data.projects,
        },
      };
    }

    // EXPERIENCE
    if (msg.includes("experience")) {
      return {
        type: "bot",
        content: {
          type: "experience",
          experience: data.experience,
        },
      };
    }

    // TESTIMONIALS
    if (msg.includes("testimonial")) {
      return {
        type: "bot",
        content: {
          type: "testimonials",
          testimonials: data.testimonials,
        },
      };
    }

    // CONTACT
    if (msg.includes("contact")) {
      return {
        type: "bot",
        content: {
          type: "contact",
          socials: data.socials,
        },
      };
    }

    return {
      type: "bot",
      content: {
        type: "help",
        text: "Try asking: about, skills, projects, experience, testimonials, contact 👀",
      },
    };
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMsg = {
      type: "user",
      content: { type: "text", text: input },
    };

    const botMsg = generateResponse(input);

    setMessages((prev) => [...prev, userMsg, botMsg]);
    setInput("");
  };

  // ---------------- UI RENDERERS ----------------

  const renderBotMessage = (content) => {
    switch (content.type) {
      case "about":
        return (
          <div className="space-y-2">
            <p className="font-semibold text-cyan-400">{content.name}</p>
            <p className="text-sm text-gray-300">{content.title}</p>
            <p className="text-gray-400">{content.bio}</p>
            <p className="text-xs text-gray-500">📍 {content.location}</p>
          </div>
        );

      case "skills":
        return (
          <div className="space-y-2">
            <p className="font-semibold text-cyan-400 mb-2">Skills</p>
            {content.skills.map((s, i) => (
              <div key={i}>
                <div className="flex justify-between text-xs text-gray-300">
                  <span>{s.name}</span>
                  <span>{s.level}%</span>
                </div>
                <div className="w-full h-2 bg-gray-800 rounded">
                  <div
                    className="h-2 bg-cyan-500 rounded"
                    style={{ width: `${s.level}%` }}
                  />
                </div>
              </div>
            ))}
          </div>
        );

      case "projects":
        return (
          <div className="space-y-3">
            <p className="font-semibold text-cyan-400">Projects</p>
            {content.projects.map((p, i) => (
              <div key={i} className="p-3 bg-gray-900 rounded-xl border border-gray-800">
                <p className="font-semibold">{p.title}</p>
                <p className="text-xs text-gray-400">{p.description}</p>
                <p className="text-[10px] text-gray-500 mt-1">
                  {p.techStack?.join(", ")}
                </p>
              </div>
            ))}
          </div>
        );

      case "experience":
        return (
          <div className="space-y-3">
            <p className="font-semibold text-cyan-400">Experience</p>
            {content.experience.map((e, i) => (
              <div key={i} className="border-l-2 border-cyan-600 pl-3">
                <p className="font-semibold">{e.role}</p>
                <p className="text-xs text-gray-400">
                  {e.company} • {e.period}
                </p>
                <p className="text-sm text-gray-300">{e.description}</p>
              </div>
            ))}
          </div>
        );

      case "testimonials":
        return (
          <div className="space-y-3">
            <p className="font-semibold text-cyan-400">Testimonials</p>
            {content.testimonials.map((t, i) => (
              <div key={i} className="bg-gray-900 p-3 rounded-xl">
                <p className="text-gray-300 italic">"{t.text}"</p>
                <p className="text-xs text-gray-500 mt-1">
                  — {t.name}, {t.role}
                </p>
              </div>
            ))}
          </div>
        );

      case "contact":
        return (
          <div className="space-y-2">
            <p className="font-semibold text-cyan-400">Contact</p>
            <p className="text-sm text-gray-300">Let’s connect 👇</p>
            <p className="text-xs text-gray-400">Email: {content.socials.email}</p>
            <p className="text-xs text-gray-400">GitHub: {content.socials.github}</p>
            <p className="text-xs text-gray-400">LinkedIn: {content.socials.linkedin}</p>
          </div>
        );

      default:
        return <p className="text-gray-400">{content.text}</p>;
    }
  };

  const suggestions = ["About", "Skills", "Projects", "Experience", "Testimonials", "Contact"];

  return (
    <div className="h-screen flex flex-col bg-gray-950 text-white">
      {/* HEADER */}
      <div className="p-4 border-b border-gray-800 text-center">
        <h1 className="text-xl font-bold text-cyan-400 flex items-center justify-center gap-2">
          <Sparkles size={18} /> {data.personal.name}
        </h1>
        <p className="text-sm text-gray-400">{data.personal.title}</p>
      </div>

      {/* CHAT */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`flex ${msg.type === "user" ? "justify-end" : "justify-start"}`}
          >
            <div
              className={`max-w-[80%] p-3 rounded-2xl text-sm whitespace-pre-line ${msg.type === "user"
                  ? "bg-cyan-600"
                  : "bg-gray-800 border border-gray-700"
                }`}
            >
              {msg.type === "user"
                ? msg.content.text
                : renderBotMessage(msg.content)}
            </div>
          </div>
        ))}
        <div ref={chatEndRef} />
      </div>

      {/* FIX: SUGGESTIONS (added spacing + visual separation) */}
      <div className="px-4 py-3 border-t border-gray-800 bg-gray-950/60 backdrop-blur flex flex-wrap gap-2">
        {suggestions.map((s, i) => (
          <button
            key={i}
            onClick={() => setInput(s)}
            className="text-xs px-3 py-1 bg-gray-800 rounded-full hover:bg-gray-700 transition"
          >
            {s}
          </button>
        ))}
      </div>

      {/* INPUT (fixed spacing + better separation) */}
      <div className="p-4 border-t border-gray-800 flex gap-2 bg-gray-950">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
          placeholder="Ask about me..."
          className="flex-1 px-4 py-2 rounded-xl bg-gray-900 border border-gray-700"
        />
        <button
          onClick={handleSend}
          className="bg-cyan-600 px-4 py-2 rounded-xl hover:bg-cyan-700"
        >
          <Send size={18} />
        </button>
      </div>
    </div>
  );
}

