import React from 'react';
import { motion } from 'framer-motion';
import { Layout, Server, Cpu, Palette, Code2 } from 'lucide-react';
import data from '../../../../data/dummy_data.json';

export default function Skills() {
  const { skills } = data;

  // Group skills by category
  const groupedSkills = skills.reduce((acc, skill) => {
    const category = skill.category || 'General';
    if (!acc[category]) {
      acc[category] = [];
    }
    acc[category].push(skill);
    return acc;
  }, {});

  const getCategoryIcon = (category) => {
    switch (category.toLowerCase()) {
      case 'frontend':
        return Layout;
      case 'backend':
        return Server;
      case 'devops':
        return Cpu;
      case 'design':
        return Palette;
      default:
        return Code2;
    }
  };

  const getCategoryGlow = (category) => {
    switch (category.toLowerCase()) {
      case 'frontend':
        return 'group-hover:border-purple-500/40 group-hover:shadow-purple-500/5';
      case 'backend':
        return 'group-hover:border-blue-500/40 group-hover:shadow-blue-500/5';
      case 'devops':
        return 'group-hover:border-pink-500/40 group-hover:shadow-pink-500/5';
      case 'design':
        return 'group-hover:border-cyan-500/40 group-hover:shadow-cyan-500/5';
      default:
        return 'group-hover:border-indigo-500/40 group-hover:shadow-indigo-500/5';
    }
  };

  const getProgressColor = (category) => {
    switch (category.toLowerCase()) {
      case 'frontend':
        return 'bg-gradient-to-r from-purple-500 to-indigo-500';
      case 'backend':
        return 'bg-gradient-to-r from-blue-500 to-cyan-500';
      case 'devops':
        return 'bg-gradient-to-r from-pink-500 to-rose-500';
      case 'design':
        return 'bg-gradient-to-r from-cyan-500 to-emerald-500';
      default:
        return 'bg-gradient-to-r from-indigo-500 to-purple-500';
    }
  };

  const containerVariants = {
    hidden: {},
    visible: {
      transition: {
        staggerChildren: 0.1,
      },
    },
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, ease: 'easeOut' },
    },
  };

  return (
    <section id="skills" className="py-24 px-4 max-w-7xl mx-auto relative z-10">
      <div className="text-center mb-16">
        <h2 className="text-3xl md:text-5xl font-bold mb-4 tracking-tight">
          My{' '}
          <span className="bg-gradient-to-r from-pink-400 to-blue-500 bg-clip-text text-transparent">
            Skills
          </span>
        </h2>
        <div className="w-16 h-1 bg-gradient-to-r from-pink-500 to-blue-500 mx-auto rounded-full" />
      </div>

      <motion.div
        variants={containerVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, margin: '-50px' }}
        className="grid grid-cols-1 md:grid-cols-2 gap-8"
      >
        {Object.entries(groupedSkills).map(([category, items], idx) => {
          const IconComponent = getCategoryIcon(category);
          const glowClass = getCategoryGlow(category);
          const progressColor = getProgressColor(category);

          return (
            <motion.div
              key={category}
              variants={cardVariants}
              className={`group p-8 rounded-3xl bg-gray-900/30 border border-white/5 backdrop-blur-md transition-all duration-500 hover:bg-gray-900/50 hover:shadow-2xl ${glowClass}`}
            >
              <div className="flex items-center gap-4 mb-6">
                <div className="p-3 rounded-2xl bg-white/5 border border-white/10 text-white group-hover:text-purple-400 transition-colors">
                  <IconComponent className="w-6 h-6" />
                </div>
                <h3 className="text-xl font-bold text-white tracking-wide">
                  {category}
                </h3>
              </div>

              <div className="space-y-6">
                {items.map((skill, index) => (
                  <div key={index} className="space-y-2">
                    <div className="flex justify-between items-center text-sm font-medium">
                      <span className="text-gray-300 group-hover:text-white transition-colors">
                        {skill.name}
                      </span>
                      <span className="text-gray-400">{skill.level}%</span>
                    </div>

                    <div className="h-2 w-full bg-gray-950 rounded-full overflow-hidden border border-white/5">
                      <motion.div
                        initial={{ width: 0 }}
                        whileInView={{ width: `${skill.level}%` }}
                        viewport={{ once: true }}
                        transition={{ duration: 1.2, ease: 'easeOut', delay: index * 0.05 }}
                        className={`h-full rounded-full ${progressColor}`}
                      />
                    </div>
                  </div>
                ))}
              </div>
            </motion.div>
          );
        })}
      </motion.div>
    </section>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X, ChevronUp } from 'lucide-react';
import data from '../../../../data/dummy_data.json';

import Hero from './Hero';
import About from './About';
import Skills from './Skills';
import Projects from './Projects';
import Experience from './Experience';
import Testimonials from './Testimonials';
import Contact from './Contact';

export default function DarkMeshGradient() {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeSection, setActiveSection] = useState('home');
  const [showScrollTop, setShowScrollTop] = useState(false);

  const navItems = [
    { id: 'home', label: 'Home' },
    { id: 'about', label: 'About' },
    { id: 'skills', label: 'Skills' },
    { id: 'projects', label: 'Projects' },
    { id: 'experience', label: 'Experience' },
    { id: 'testimonials', label: 'Reviews' },
    { id: 'contact', label: 'Contact' },
  ];

  useEffect(() => {
    let ticking = false;

    const handleScroll = () => {
      if (!ticking) {
        window.requestAnimationFrame(() => {
          const scrollY = window.scrollY;

          setShowScrollTop(scrollY > 500);

          const scrollPosition = scrollY + 200;
          let currentSection = activeSection;

          for (const item of navItems) {
            const el = document.getElementById(item.id);
            if (!el) continue;

            const top = el.offsetTop;
            const height = el.offsetHeight;

            if (scrollPosition >= top && scrollPosition < top + height) {
              currentSection = item.id;
              break;
            }
          }

          if (currentSection !== activeSection) {
            setActiveSection(currentSection);
          }

          ticking = false;
        });

        ticking = true;
      }
    };

    window.addEventListener('scroll', handleScroll);

    // initialize state immediately
    handleScroll();

    return () => window.removeEventListener('scroll', handleScroll);
  }, [activeSection]);

  const scrollToSection = (id) => {
    setIsMobileMenuOpen(false);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="relative min-h-screen bg-gray-950 text-gray-100 font-sans selection:bg-purple-500/30 overflow-x-hidden scroll-smooth">

      {/* BACKGROUND BLOBS */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">

        <motion.div
          animate={{ x: [0, 60, -40, 0], y: [0, -80, 50, 0], scale: [1, 1.15, 0.9, 1] }}
          transition={{ duration: 18, repeat: Infinity, ease: 'easeInOut' }}
          className="absolute top-1/4 left-[10%] w-96 h-96 md:w-[500px] md:h-[500px] bg-purple-600/15 rounded-full blur-[120px] mix-blend-screen"
        />

        <motion.div
          animate={{ x: [0, -50, 70, 0], y: [0, 90, -60, 0], scale: [1, 0.85, 1.1, 1] }}
          transition={{ duration: 22, repeat: Infinity, ease: 'easeInOut' }}
          className="absolute top-1/2 right-[10%] w-[350px] h-[350px] md:w-[450px] md:h-[450px] bg-pink-600/15 rounded-full blur-[130px] mix-blend-screen"
        />

        <motion.div
          animate={{ x: [0, 80, -50, 0], y: [0, -40, 70, 0], scale: [1, 1.1, 0.85, 1] }}
          transition={{ duration: 20, repeat: Infinity, ease: 'easeInOut' }}
          className="absolute bottom-1/4 left-[25%] w-[380px] h-[380px] md:w-[480px] md:h-[480px] bg-blue-600/15 rounded-full blur-[125px] mix-blend-screen"
        />
      </div>

      {/* HEADER */}
      <header className="fixed top-0 left-0 right-0 z-50 bg-gray-950/40 backdrop-blur-md border-b border-white/5">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">

          <button
            onClick={() => scrollToSection('home')}
            className="text-xl font-bold bg-gradient-to-r from-purple-400 to-pink-500 bg-clip-text text-transparent"
          >
            {data.personal.name}
          </button>

          {/* Desktop Nav */}
          <nav className="hidden md:flex items-center gap-1">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => scrollToSection(item.id)}
                className={`px-4 py-2 rounded-full text-sm font-semibold transition-all duration-300 ${
                  activeSection === item.id
                    ? 'bg-white/10 text-white'
                    : 'text-gray-400 hover:text-white'
                }`}
              >
                {item.label}
              </button>
            ))}
          </nav>

          {/* Mobile Button */}
          <button
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            aria-label="Toggle menu"
            aria-expanded={isMobileMenuOpen}
            aria-controls="dark-mesh-mobile-nav"
            className="p-2.5 rounded-xl bg-white/5 border border-white/10 md:hidden"
          >
            {isMobileMenuOpen ? <X /> : <Menu />}
          </button>
        </div>
      </header>

      {/* MOBILE MENU */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            id="dark-mesh-mobile-nav"
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="fixed top-20 left-0 right-0 z-40 bg-gray-950/95 border-b border-white/10 py-6 px-6 md:hidden flex flex-col gap-3"
          >
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => scrollToSection(item.id)}
                className="w-full text-left px-5 py-3 rounded-xl text-base font-semibold text-gray-300 hover:text-white hover:bg-white/5"
              >
                {item.label}
              </button>
            ))}
          </motion.div>
        )}
      </AnimatePresence>

      {/* MAIN */}
      <main className="relative z-10 max-w-7xl mx-auto w-full pt-20">
        <Hero />
        <About />
        <Skills />
        <Projects />
        <Experience />
        <Testimonials />
        <Contact />
      </main>

      {/* SCROLL TO TOP */}
      <AnimatePresence>
        {showScrollTop && (
          <motion.button
            onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
            className="fixed bottom-8 right-8 z-50 p-4 rounded-xl bg-purple-600 text-white"
            aria-label="Scroll to top"
          >
            <ChevronUp />
          </motion.button>
        )}
      </AnimatePresence>

    </div>
  );
}

