                  className="p-3 bg-slate-950 text-slate-400 border border-slate-900 rounded-lg hover:bg-slate-900 hover:text-cyan-400 hover:border-slate-800 transition-all duration-300 shadow-inner"
                >
                  <Icon size={18} />
                </motion.a>
              );
            })}
          </div>

        </div>
      </div>
    </header>
  );
};

export default Hero;

