function Hero() {
  const personal = data.personal ?? {};
  const social = data.socials ?? {};
  const stats = data.stats ?? {};

  const containerVariants = {
    hidden: {},
    show: { transition: { staggerChildren: 0.12, delayChildren: 2.5 } },
