  );
}

import { useEffect, useRef, useState } from "react";

/**
 * Parses a stat string like "10K+", "95%", "2.5x", "50K+"
 * Returns { numeric: number, suffix: string }
 */
function parseStat(value) {
  if (value === undefined || value === null) return { numeric: null, suffix: "" };
  const strValue = String(value);
  const match = strValue.match(/^([\d.]+)([A-Za-z%+x]*)$/);
  if (!match) return { numeric: null, suffix: strValue };
  return { numeric: parseFloat(match[1]), suffix: match[2] };
}

/**
 * Easing function: ease-out cubic for natural deceleration
 */
function easeOutCubic(t) {
  return 1 - Math.pow(1 - t, 3);
}

/**
 * AnimatedCounter
 * Props:
 *   value (string|number) — the stat string, e.g. "10K+", "95%", "2.5x"
 *   duration (number)      — animation duration in ms, default 2000
 */
export default function AnimatedCounter({ value, duration = 2000 }) {
  const [display, setDisplay] = useState("0");
  const [, setTrigger] = useState(0); // Dummy state to force re-render if needed, but not used here
  const ref = useRef(null);
  const rafId = useRef(null);
  const hasAnimatedRef = useRef(false);

  const { numeric, suffix } = parseStat(value);

  // Reset animation state when the target value changes
  useEffect(() => {
    hasAnimatedRef.current = false;
    setDisplay("0");
  }, [value]);

  useEffect(() => {
    if (numeric === null || hasAnimatedRef.current) {
      if (numeric === null) setDisplay(String(value));
      return;
    }

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !hasAnimatedRef.current) {
          hasAnimatedRef.current = true;
          observer.disconnect();

          const startTime = performance.now();
          const isDecimal = numeric % 1 !== 0;
          const safeDuration = Math.max(duration, 1);

          function step(currentTime) {
            const elapsed = currentTime - startTime;
            const progress = Math.min(elapsed / safeDuration, 1);
            const easedProgress = easeOutCubic(progress);
            const current = easedProgress * numeric;

            setDisplay(
              isDecimal ? current.toFixed(1) : Math.floor(current).toString()
            );

            if (progress < 1) {
              rafId.current = requestAnimationFrame(step);
            } else {
              setDisplay(isDecimal ? numeric.toFixed(1) : numeric.toString());
            }
          }

          rafId.current = requestAnimationFrame(step);
        }
      },
      { threshold: 0.3 }
    );

    if (ref.current) observer.observe(ref.current);
    
    return () => {
      observer.disconnect();
      if (rafId.current) cancelAnimationFrame(rafId.current);
    };
  }, [numeric, duration, value]);


  if (numeric === null) return <span ref={ref}>{String(value)}</span>;

  return (
    <span ref={ref}>
      {display}
      {suffix}
    </span>
  );
}

import { cn } from "../../lib/utils";
import { Link, useLocation } from "react-router-dom";
import { useState, createContext, useContext } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { Menu, X } from "lucide-react";

import { SidebarContext } from "../../context/SidebarContext";

// Internal convenience — components within this file consume the context directly.
/**
 * Internal custom hook to retrieve the Sidebar context.
 * Throws an error if used outside a SidebarProvider.
 *
 * @returns {object} The Sidebar context object.
 */
function useSidebarInternal() {
    const context = useContext(SidebarContext);
    if (!context) {
        throw new Error("useSidebar must be used within a SidebarProvider");
    }
    return context;
}

/**
 * Context Provider component that wraps children and holds state for the Sidebar.
 *
 * @param {object} props - The component props.
 * @param {React.ReactNode} props.children - The children elements.
 * @param {boolean} [props.open] - Controlled open/close state.
 * @param {Function} [props.setOpen] - Callback function to update open state.
 * @param {boolean} [props.animate=true] - Whether to animate transition.
 * @returns {React.JSX.Element} The rendered Provider component.
 */
export const SidebarProvider = ({
    children,
    open: openProp,
    setOpen: setOpenProp,
    animate = true,
}) => {
    const [openState, setOpenState] = useState(false);

    const open = openProp !== undefined ? openProp : openState;
    const setOpen = setOpenProp !== undefined ? setOpenProp : setOpenState;

    return (
        <SidebarContext.Provider value={{ open, setOpen, animate }}>
            {children}
        </SidebarContext.Provider>
    );
};

/**
 * Sidebar component that initializes the SidebarProvider context.
 *
 * @param {object} props - The component props.
 * @param {React.ReactNode} props.children - The children elements.
 * @param {boolean} [props.open] - Controlled open/close state.
 * @param {Function} [props.setOpen] - Callback function to update open state.
 * @param {boolean} [props.animate=true] - Whether to animate transition.
 * @returns {React.JSX.Element} The rendered Sidebar component.
 */
export const Sidebar = ({
    children,
    open,
    setOpen,
    animate,
}) => {
    return (
        <SidebarProvider open={open} setOpen={setOpen} animate={animate}>
            {children}
        </SidebarProvider>
    );
};

/**
 * Component that renders both Desktop and Mobile views of the Sidebar.
 *
 * @param {object} props - The component props.
 * @returns {React.JSX.Element} The rendered SidebarBody.
 */
export const SidebarBody = (props) => {
    return (
        <>
            <DesktopSidebar {...props} />
            <MobileSidebar {...props} />
        </>
    );
};

/**
 * Desktop sidebar component with expand/collapse animations on hover.
 *
 * @param {object} props - The component props.
 * @param {string} [props.className] - Extra class name custom styling.
 * @param {React.ReactNode} props.children - Child elements.
 * @returns {React.JSX.Element} The rendered DesktopSidebar.
 */
export const DesktopSidebar = ({
    className,
    children,
    ...props
}) => {
    const { open, setOpen, animate } = useSidebarInternal();
    return (
        <motion.div
            className={cn(
                "h-full px-3 py-4 hidden md:flex md:flex-col bg-card border-r border-border w-[280px] shrink-0 overflow-x-hidden",
                className
            )}
            animate={{
                width: animate ? (open ? "280px" : "80px") : "280px",
            }}
            transition={{
                duration: 0.3,
                ease: "easeInOut",
            }}
            onMouseEnter={() => setOpen(true)}
            onMouseLeave={() => setOpen(false)}
            {...props}
        >
            {children}
        </motion.div>
    );
};

/**
 * Mobile sidebar component with toggle menu bar and responsive slide-out drawer overlay.
 *
 * @param {object} props - The component props.
