};

/**
 * Navigation item link within the Sidebar.
 *
 * @param {object} props - The component props.
 * @param {object} props.link - The link item data (label, href, icon).
 * @param {string} [props.className] - Extra class name custom styling.
 * @param {boolean} [props.active] - Override active link styling status.
 * @param {Function} [props.onClick] - Click callback handler.
 * @returns {React.JSX.Element} The rendered SidebarLink.
 */
export const SidebarLink = ({
    link,
    className,
    active,
    onClick,
    ...props
}) => {
    const { open, animate } = useSidebarInternal();
    const location = useLocation();
    const isActive = active !== undefined ? active : location.pathname === link.href;

    return (
        <Link
            to={link.href}
            onClick={onClick}
            className={cn(
                "nav-link w-full group/sidebar transition-all duration-200",
                !open && animate ? "justify-center px-0" : "justify-start px-3",
                isActive ? "nav-link-active" : "nav-link-inactive",
                className
            )}
            {...props}
        >
            <div className="shrink-0">
                {link.icon}
            </div>
            <motion.span
                animate={{
                    display: animate ? (open ? "inline-block" : "none") : "inline-block",
                    opacity: animate ? (open ? 1 : 0) : 1,
                }}
                transition={{
                    duration: 0.2,
                }}
                className="text-sm font-medium whitespace-pre"
            >
                {link.label}
            </motion.span>
        </Link>
    );
};

/**
 * Divider line component that animates dynamically when Sidebar collapses.
 *
 * @returns {React.JSX.Element} The rendered SidebarDivider.
 */
export const SidebarDivider = () => {
    const { open, animate } = useSidebarInternal();
    return (
        <motion.div
            animate={{
                opacity: animate ? (open ? 1 : 0.3) : 1,
            }}
            className="h-px bg-border my-4"
        />
    );
};

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { GitBranch, FileCode, Network, ShieldAlert, Sparkles, CheckCircle2, Loader2 } from 'lucide-react';
import { cn } from '../../lib/utils';

const AnalysisProgress = ({ status }) => {
  const [activeStep, setActiveStep] = useState(0);

  const steps = [
    { icon: GitBranch, label: 'Cloning repository' },
    { icon: FileCode, label: 'Scanning files & languages' },
    { icon: Network, label: 'Building dependency graph' },
    { icon: ShieldAlert, label: 'Detecting risks' },
    { icon: Sparkles, label: 'Generating AI insights' }
  ];

  useEffect(() => {
    if (status !== 'analyzing') return;
    
    // Simulate progress through the steps since backend doesn't send SSE events for progress yet
    let currentStep = 0;
    const interval = setInterval(() => {
      currentStep++;
      if (currentStep < steps.length) {
        setActiveStep(currentStep);
      } else {
        clearInterval(interval);
      }
    }, 2000);

    return () => clearInterval(interval);
  }, [status]);

  if (status !== 'analyzing') return null;

  return (
    <div className="fixed inset-0 z-50 bg-[#050505]/80 backdrop-blur-sm flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-md bg-[#111] border border-white/10 rounded-3xl p-8 shadow-2xl relative overflow-hidden">
        
        {/* Glow effects */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[200%] h-32 bg-cyan-500/20 blur-[100px] pointer-events-none" />
        
        <h2 className="text-2xl font-bold text-white text-center mb-8">Analyzing Codebase</h2>
        
        <div className="space-y-6 relative z-10">
          {steps.map((step, i) => {
            const isActive = i === activeStep;
            const isPast = i < activeStep;
            
            return (
              <div key={i} className="flex items-center gap-4">
                <div className={cn(
                  "w-10 h-10 rounded-full flex items-center justify-center shrink-0 transition-colors duration-500",
                  isPast ? "bg-green-500/20 text-green-400 border border-green-500/30" :
                  isActive ? "bg-cyan-500/20 text-cyan-400 border border-cyan-500/30" :
                  "bg-white/5 text-slate-500 border border-white/5"
                )}>
                  {isPast ? <CheckCircle2 className="w-5 h-5" /> :
                   isActive ? <Loader2 className="w-5 h-5 animate-spin" /> :
                   <step.icon className="w-5 h-5" />}
                </div>
                
                <span className={cn(
                  "font-medium transition-colors duration-500",
                  isPast ? "text-slate-300" :
                  isActive ? "text-white" :
                  "text-slate-500"
                )}>
                  {step.label}
                </span>
              </div>
            );
          })}
        </div>
        
        {/* Progress Bar */}
        <div className="mt-10 h-2 bg-white/5 rounded-full overflow-hidden">
          <motion.div 
            className="h-full bg-gradient-to-r from-cyan-500 to-violet-500"
            initial={{ width: '0%' }}
            animate={{ width: `${((activeStep + 1) / steps.length) * 100}%` }}
            transition={{ duration: 0.5 }}
          />
        </div>
      </div>
    </div>
  );
};

export default AnalysisProgress;

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { 
  ReactFlow, Controls, MiniMap, Background, 
  useNodesState, useEdgesState, Panel
} from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import dagre from 'dagre';
import { Box, FileCode, Search, Maximize } from 'lucide-react';
import { useProjectVisualizerStore } from '../../stores/useProjectVisualizerStore';
import ModuleNode from './ModuleNode';
import FileNode from './FileNode';
import { cn } from '../../lib/utils';

const nodeTypes = {
  moduleNode: ModuleNode,
  fileNode: FileNode
};

const getLayoutedElements = (nodes, edges, direction = 'TB', isFileNode = false) => {
  const dagreGraph = new dagre.graphlib.Graph();
  dagreGraph.setDefaultEdgeLabel(() => ({}));
  
  const nodeWidth = isFileNode ? 200 : 220;
  const nodeHeight = isFileNode ? 70 : 100;

  dagreGraph.setGraph({ rankdir: direction, ranksep: 100, nodesep: 50 });

  nodes.forEach((node) => {
    dagreGraph.setNode(node.id, { width: nodeWidth, height: nodeHeight });
  });

  edges.forEach((edge) => {
    dagreGraph.setEdge(edge.source, edge.target);
  });

  dagre.layout(dagreGraph);

  const newNodes = nodes.map((node) => {
    const nodeWithPosition = dagreGraph.node(node.id);
    return {
      ...node,
      position: {
        x: nodeWithPosition.x - nodeWidth / 2,
        y: nodeWithPosition.y - nodeHeight / 2,
      },
    };
  });

  return { nodes: newNodes, edges };
};

const ArchitectureCanvas = () => {
  const { 
    moduleGraph, fileGraph, viewMode, setViewMode, 
    setSelectedModule, setSelectedFile, selectedModule, selectedFile 
  } = useProjectVisualizerStore();
  
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Initial layout and view changes
  useEffect(() => {
    const rawNodes = viewMode === 'modules' ? moduleGraph.nodes : fileGraph.nodes;
    const rawEdges = viewMode === 'modules' ? moduleGraph.edges : fileGraph.edges;
    
    if (!rawNodes || rawNodes.length === 0) return;
    
    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(
      rawNodes, 
      rawEdges, 
      'TB',
      viewMode === 'files'
    );
    
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);
  }, [moduleGraph, fileGraph, viewMode, setNodes, setEdges]);

  // Handle selection state visually
  useEffect(() => {
    setNodes(nds => nds.map(n => ({
      ...n,
      selected: viewMode === 'modules' 
        ? selectedModule?.name === n.id 
        : selectedFile?.relativePath === n.id
    })));
  }, [selectedModule, selectedFile, viewMode, setNodes]);

  // Handle Search Filtering (Highlights nodes)
  useEffect(() => {
    if (!searchQuery) {
      setNodes(nds => nds.map(n => ({ ...n, hidden: false, style: { opacity: 1 } })));
      setEdges(eds => eds.map(e => ({ ...e, hidden: false, style: { ...e.style, opacity: 1 } })));
      return;
    }
    
    const lowerQ = searchQuery.toLowerCase();
    
    setNodes(nds => nds.map(n => {
      const match = viewMode === 'modules' 
        ? n.data.name.toLowerCase().includes(lowerQ)
        : n.data.fileName.toLowerCase().includes(lowerQ);
        
      return { ...n, style: { ...n.style, opacity: match ? 1 : 0.2 } };
    }));
    
  }, [searchQuery, viewMode, setNodes, setEdges]);

  const onNodeClick = useCallback((_, node) => {
    if (node.type === 'moduleNode') {
      setSelectedModule(node.data);
    } else if (node.type === 'fileNode') {
      setSelectedFile(node.data);
    }
  }, [setSelectedModule, setSelectedFile]);

  if (!nodes || nodes.length === 0) {
    return (
      <div className="w-full h-full min-h-[500px] flex items-center justify-center bg-black/40 border border-white/5 rounded-2xl">
        <div className="text-slate-500 flex flex-col items-center">
          <Maximize className="w-12 h-12 mb-4 opacity-20" />
          <p>No graph data available</p>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full h-full min-h-[600px] bg-black/40 border border-white/5 rounded-2xl overflow-hidden relative">
      
      {/* Top Bar overlays */}
      <div className="absolute top-4 left-4 right-4 z-10 flex items-center justify-between pointer-events-none">
        
        {/* View Toggles */}
        <div className="bg-[#0f172a]/90 backdrop-blur border border-white/10 rounded-lg p-1 flex gap-1 pointer-events-auto">
          <button
            onClick={() => setViewMode('modules')}
            className={cn(
              "px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-2 transition-colors",
              viewMode === 'modules' ? "bg-cyan-500/20 text-cyan-400" : "text-slate-400 hover:text-white hover:bg-white/5"
            )}
          >
            <Box className="w-4 h-4" /> Modules
          </button>
          <button
            onClick={() => setViewMode('files')}
            className={cn(
              "px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-2 transition-colors",
              viewMode === 'files' ? "bg-violet-500/20 text-violet-400" : "text-slate-400 hover:text-white hover:bg-white/5"
            )}
          >
            <FileCode className="w-4 h-4" /> Files
          </button>
        </div>

        {/* Search */}
        <div className="bg-[#0f172a]/90 backdrop-blur border border-white/10 rounded-lg p-2 flex items-center w-64 pointer-events-auto">
          <Search className="w-4 h-4 text-slate-400 mx-2" />
          <input 
            type="text"
            placeholder="Search nodes..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="bg-transparent border-none outline-none text-sm w-full text-white placeholder-slate-500"
          />
        </div>
      </div>

      <ReactFlow
        nodes={nodes}
        edges={edges}
        style={{ width: '100%', height: '100%' }}
        className="w-full h-full"
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onNodeClick={onNodeClick}
        nodeTypes={nodeTypes}
        fitView
        fitViewOptions={{ padding: 0.2 }}
        minZoom={0.1}
        maxZoom={2}
        proOptions={{ hideAttribution: true }}
      >
        <Background color="#333" gap={20} size={1} />
        <Controls className="bg-[#0f172a] border-slate-700 fill-white text-white" />
        <MiniMap 
          nodeColor={(n) => {
            if (n.type === 'moduleNode') return '#06b6d4';
            return '#3178c6';
          }}
          className="bg-[#0f172a] border-slate-700 !bottom-4 !right-4 rounded-lg overflow-hidden"
          maskColor="rgba(0,0,0, 0.7)"
        />
      </ReactFlow>
    </div>
  );
};

export default ArchitectureCanvas;

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Box, FileCode, Search, BrainCircuit, ArrowRight } from 'lucide-react';
import { useProjectVisualizerStore } from '../../stores/useProjectVisualizerStore';
import { cn } from '../../lib/utils';
import EnhancedFileViewer from './EnhancedFileViewer';

const ModuleInspector = () => {
