import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../hooks/useAuth';
import { initializeSocket, disconnectSocket, getSocket, socketEvents } from '../services/socket';
import { SocketContext } from './SocketContext';

/**
 * Provider component that handles real-time web socket connections,
 * status updates of online users, and push notifications.
 *
 * @param {object} props - The component props.
 * @param {React.ReactNode} props.children - The children elements.
 * @returns {React.JSX.Element} The rendered Provider component.
 */
export function SocketProvider({ children }) {
  const { user } = useAuth();
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const unreadCount = notifications.filter((n) => !n.read).length;


  /**
   * Pushes a new notification to the state stack.
   *
   * @param {string} type - The notification type.
   * @param {object} data - Metadata payload of the notification.
   */
  const pushNotification = useCallback((type, data) => {
    setNotifications((prev) =>
      [
        {
          id: `${type}-${Date.now()}-${Math.random()}`,
          type,
          data,
          read: false,
          timestamp: new Date(),
        },
        ...prev,
      ].slice(0, 50)
    );
  }, []);

  /**
   * Marks a specific notification as read.
   *
   * @param {string} id - The notification ID.
   */
  const markRead = useCallback((id) => {
    setNotifications((prev) =>
      prev.map((n) => (n.id === id ? { ...n, read: true } : n))
    );
  }, []);

  /**
   * Marks all notifications as read.
   */
  const markAllRead = useCallback(() => {
    setNotifications((prev) =>
     prev.map((n) => ({ ...n, read: true }))
    );
  }, []);

  /**
   * Dismisses a specific notification.
   *
   * @param {string} id - The notification ID.
   */
  const dismissNotification = useCallback((id) => {
    setNotifications((prev) =>
      prev.filter((n) => n.id !== id)
    );
  }, []);

  /**
   * Clears all notifications.
   */
  const clearNotifications = useCallback(() => {
    setNotifications([]);
  }, []);

  // Initialize socket when user logs in
  useEffect(() => {
    let mounted = true;
    let cleanupHandlers = () => {};

    const setupSocket = async () => {
      if (user) {
        const socketInstance = await initializeSocket();
        if (mounted && socketInstance) {
          setSocket(socketInstance);

          const handleConnect = () => setIsConnected(true);
          const handleDisconnect = () => setIsConnected(false);
          const handleOnlineUsers = ({ users }) => setOnlineUsers(users);
          const handleUserOnline = ({ uid, name }) => {
            setOnlineUsers(prev => {
              if (!prev.some(u => u.uid === uid)) {
                return [...prev, { uid, name, status: 'online' }];
              }
              return prev;
            });
          };
          const handleUserOffline = ({ uid }) => {
            setOnlineUsers(prev => prev.filter(u => u.uid !== uid));
          };
          const handleStatusChanged = ({ uid, status }) => {
            setOnlineUsers(prev =>
              prev.map(u => u.uid === uid ? { ...u, status } : u)
            );
          };


          const handleNotification = (data) =>
            pushNotification('notification', data);

          const handleJobAlertNewJobs = (data) =>
             pushNotification('job_alert_new_jobs', data);

          const handleJobAlertEmailSent = (data) =>
            pushNotification('job_alert_email_sent', data);

          const handleJobAlertEmailFailed = (data) =>
            pushNotification('job_alert_email_failed', data);

          socketInstance.on('connect', handleConnect);
          socketInstance.on('disconnect', handleDisconnect);
          socketInstance.on('online_users', handleOnlineUsers);
          socketInstance.on('user_online', handleUserOnline);
          socketInstance.on('user_offline', handleUserOffline);
          socketInstance.on('user_status_changed', handleStatusChanged);
          socketInstance.on('notification', handleNotification);
          socketInstance.on('job_alert_new_jobs', handleJobAlertNewJobs);
          socketInstance.on('job_alert_email_sent', handleJobAlertEmailSent);
          socketInstance.on('job_alert_email_failed', handleJobAlertEmailFailed);

          if (socketInstance.connected) handleConnect();

          cleanupHandlers = () => {
            socketInstance.off('connect', handleConnect);
            socketInstance.off('disconnect', handleDisconnect);
            socketInstance.off('online_users', handleOnlineUsers);
            socketInstance.off('user_online', handleUserOnline);
            socketInstance.off('user_offline', handleUserOffline);
            socketInstance.off('user_status_changed', handleStatusChanged);
            socketInstance.off('notification', handleNotification);
            socketInstance.off('job_alert_new_jobs', handleJobAlertNewJobs);
            socketInstance.off('job_alert_email_sent', handleJobAlertEmailSent);
            socketInstance.off('job_alert_email_failed', handleJobAlertEmailFailed);
          };

          // Get initial online users
          socketEvents.getOnlineUsers();
        }
      } else {
        disconnectSocket();
        setSocket(null);
        setIsConnected(false);
        setOnlineUsers([]);
        setNotifications([]);
      }
    };

    setupSocket();

    return () => {
      mounted = false;
      cleanupHandlers();
      if (!user) {
        disconnectSocket();
      }
    };
  }, [user]);

  /**
   * Subscribes to a socket event with a callback, returning an unsubscribe cleanup function.
   *
   * @param {string} event - The socket event name.
   * @param {Function} callback - The event handler callback function.
   * @returns {Function} An unsubscribe function to remove the listener.
   */
  const subscribe = useCallback((event, callback) => {
    const currentSocket = getSocket();
    if (currentSocket) {
      currentSocket.on(event, callback);
      return () => currentSocket.off(event, callback);
    }
    return () => {};
  }, [socket]);

  /**
   * Emits a socket event with data to the server.
   *
   * @param {string} event - The socket event name.
   * @param {object} data - The message payload to emit.
   */
  const emit = useCallback((event, data) => {
    const currentSocket = getSocket();
    if (currentSocket?.connected) {
      currentSocket.emit(event, data);
    }
  }, [socket]);

  const value = {
    socket,
    isConnected,
    onlineUsers,
    notifications,
    unreadCount,
    markRead,
    markAllRead,
    dismissNotification,
    clearNotifications,
    subscribe,
    emit,
    ...socketEvents
  };

  return (
    <SocketContext.Provider value={value}>
      {children}
    </SocketContext.Provider>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';

let faceLandmarksDetectionPromise = null;

const loadTensorFlow = async () => {
    if (!faceLandmarksDetectionPromise) {
        faceLandmarksDetectionPromise = (async () => {
            const tf = await import('@tensorflow/tfjs');
            const fld = await import('@tensorflow-models/face-landmarks-detection');
            await tf.ready();
            return fld;
        })();
    }
    return faceLandmarksDetectionPromise;
};

const calculateConfidenceMetrics = (predictions, frameWidth = 640, frameHeight = 480) => {
    if (!predictions || predictions.length === 0) {
        return {
            faceDetected: false,
            confidence: 0,
            eyeContact: 0,
            headStability: 0,
            overallScore: 0
        };
    }

    const face = predictions[0];
    const keypoints = face.keypoints;

    const leftEye = keypoints.filter(k => k.name?.includes('leftEye'));
    const rightEye = keypoints.filter(k => k.name?.includes('rightEye'));
    const nose = keypoints.find(k => k.name === 'noseTip');

    let eyeContact = 70;
    if (leftEye.length > 0 && rightEye.length > 0) {
        const leftCenter = leftEye.reduce((acc, p) => ({ x: acc.x + p.x, y: acc.y + p.y }), { x: 0, y: 0 });
        const rightCenter = rightEye.reduce((acc, p) => ({ x: acc.x + p.x, y: acc.y + p.y }), { x: 0, y: 0 });
        leftCenter.x /= leftEye.length;
        leftCenter.y /= leftEye.length;
        rightCenter.x /= rightEye.length;
        rightCenter.y /= rightEye.length;

        const eyeDistance = Math.abs(rightCenter.x - leftCenter.x);
        const eyeSymmetry = Math.abs(leftCenter.y - rightCenter.y);
        eyeContact = Math.min(100, Math.max(0, 100 - eyeSymmetry * 2));
    }

    let headStability = 80;
    if (nose) {
        const centerX = frameWidth / 2;
        const centerY = frameHeight / 2;
        const deviation = Math.sqrt(Math.pow(nose.x - centerX, 2) + Math.pow(nose.y - centerY, 2));
        headStability = Math.max(0, 100 - deviation * 0.3);
    }

    const confidence = face.box ? Math.min(100, (face.box.width * face.box.height) / 500) : 70;

    const overallScore = Math.round((eyeContact * 0.3) + (headStability * 0.3) + (confidence * 0.4));

    return {
        faceDetected: true,
        confidence: Math.round(confidence),
        eyeContact: Math.round(eyeContact),
        headStability: Math.round(headStability),
        overallScore
    };
};

export const useFaceDetection = (videoRef, isActive = false) => {
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);
    const [metrics, setMetrics] = useState({
        faceDetected: false,
        confidence: 0,
        eyeContact: 0,
        headStability: 0,
        overallScore: 0
    });
    const [modelReady, setModelReady] = useState(false);

    const detectorRef = useRef(null);
    const animationFrameRef = useRef(null);
    const metricsHistoryRef = useRef([]);

    const initializeDetector = useCallback(async () => {
        try {
            setIsLoading(true);
            setError(null);

            const fld = await loadTensorFlow();
            const model = fld.SupportedModels.MediaPipeFaceMesh;
            const detectorConfig = {
                runtime: 'tfjs',
                refineLandmarks: true,
                maxFaces: 1
            };

            detectorRef.current = await fld.createDetector(model, detectorConfig);
            setModelReady(true);
            setIsLoading(false);
        } catch (err) {
            console.error('Failed to initialize face detector:', err);
            setError('Failed to load face detection model');
            setIsLoading(false);
        }
    }, []);

    const detectFace = useCallback(async () => {
        if (!detectorRef.current || !videoRef.current || !isActive) return;

        const video = videoRef.current;
        if (video.readyState < 2) {
            animationFrameRef.current = requestAnimationFrame(detectFace);
            return;
        }

        try {
            const predictions = await detectorRef.current.estimateFaces(video, { flipHorizontal: true });
            const frameWidth = video.videoWidth || video.clientWidth || 640;
            const frameHeight = video.videoHeight || video.clientHeight || 480;
            const newMetrics = calculateConfidenceMetrics(predictions, frameWidth, frameHeight);

            metricsHistoryRef.current.push(newMetrics);
            if (metricsHistoryRef.current.length > 30) {
                metricsHistoryRef.current.shift();
            }

            setMetrics(newMetrics);
        } catch (err) {
            console.error('Face detection error:', err);
        }

        animationFrameRef.current = requestAnimationFrame(detectFace);
    }, [videoRef, isActive]);

    const getAverageMetrics = useCallback(() => {
        const history = metricsHistoryRef.current;
        if (history.length === 0) {
            return { averageConfidence: 0, eyeContactPercentage: 0, headMovementStability: 0, overallExpressionScore: 0 };
        }

        const validHistory = history.filter(m => m.faceDetected);
        if (validHistory.length === 0) {
            return { averageConfidence: 0, eyeContactPercentage: 0, headMovementStability: 0, overallExpressionScore: 0 };
        }

        return {
            averageConfidence: Math.round(validHistory.reduce((sum, m) => sum + m.confidence, 0) / validHistory.length),
            eyeContactPercentage: Math.round(validHistory.reduce((sum, m) => sum + m.eyeContact, 0) / validHistory.length),
            headMovementStability: Math.round(validHistory.reduce((sum, m) => sum + m.headStability, 0) / validHistory.length),
            overallExpressionScore: Math.round(validHistory.reduce((sum, m) => sum + m.overallScore, 0) / validHistory.length)
        };
    }, []);

    const resetMetrics = useCallback(() => {
        metricsHistoryRef.current = [];
        setMetrics({ faceDetected: false, confidence: 0, eyeContact: 0, headStability: 0, overallScore: 0 });
    }, []);

    useEffect(() => {
        initializeDetector();

        return () => {
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current);
            }
            if (detectorRef.current) {
                detectorRef.current.dispose?.();
            }
        };
    }, [initializeDetector]);

    useEffect(() => {
        if (isActive && modelReady) {
            detectFace();
        } else if (animationFrameRef.current) {
            cancelAnimationFrame(animationFrameRef.current);
        }

        return () => {
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current);
            }
        };
    }, [isActive, modelReady, detectFace]);

    return {
        isLoading,
        error,
        metrics,
        modelReady,
        getAverageMetrics,
        resetMetrics
    };
};

export default useFaceDetection;

import { useSearchParams } from 'react-router-dom';
import { useState, useEffect, useRef, useCallback } from 'react';
import { useAuth } from '../hooks/useAuth';
import { useSocket } from '../hooks/useSocket';
import { communityApi } from '../services/api';
import ChannelList from '../components/community/ChannelList';
import ChatWindow from '../components/community/ChatWindow';
import MembersList from '../components/community/MembersList';
import PostsFeed from '../components/community/PostsFeed';
import DirectMessages from '../components/community/DirectMessages';
import {
  MessageSquare,
  Users,
  FileText,
  Mail,
  Menu,
  X,
  Plus,
  Search,
  Hash
} from 'lucide-react';
import toast from 'react-hot-toast';
import { SkeletonListItems, SkeletonPostList } from '../components/ui/Skeleton';
import { motion, AnimatePresence } from 'framer-motion';

export default function Community() {
  const { user } = useAuth();
  const { isConnected, onlineUsers, subscribe, joinChannel, leaveChannel } = useSocket();
  const [searchParams, setSearchParams] = useSearchParams();

  // View state
  const [activeView, setActiveView] = useState(searchParams.get('view') || 'channels'); // channels, posts, dms
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [membersOpen, setMembersOpen] = useState(true);

  // Sync activeView with search parameter changes
  useEffect(() => {
    const view = searchParams.get('view');
    if (view && ['channels', 'posts', 'dms'].includes(view)) {
      setActiveView(view);
    }
  }, [searchParams]);

  // Update URL search parameters when tab is clicked
  const handleTabChange = (view) => {
    setActiveView(view);
    setSearchParams({ view });
  };

  // Channel state
  const [channels, setChannels] = useState([]);
  const [activeChannel, setActiveChannel] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loadingChannels, setLoadingChannels] = useState(true);
  const [loadingMessages, setLoadingMessages] = useState(false);

  // Modal state
  const [showCreateChannel, setShowCreateChannel] = useState(false);

  // Handle optimistic message - immediately show in UI
  const handleOptimisticMessage = useCallback((optimisticMessage) => {
    setMessages(prev => [...prev, optimisticMessage]);
    // Update channel's last message
    setChannels(prev => prev.map(ch => {
      const chId = ch.id || ch._id;
      return chId === optimisticMessage.channelId
        ? { ...ch, lastMessage: { content: optimisticMessage.content, senderName: optimisticMessage.sender.name, timestamp: optimisticMessage.createdAt } }
        : ch;
    }));
  }, []);

  // Handle optimistic reaction - immediately show in UI
  const handleOptimisticReaction = useCallback(({ messageId, emoji, action }) => {
    setMessages(prev => prev.map(msg => {
      const msgId = msg.id || msg._id;
      if (msgId !== messageId) return msg;

      let reactions = [...(msg.reactions || [])];
      const reactionIndex = reactions.findIndex(r => r.emoji === emoji);

      if (action === 'add') {
        if (reactionIndex >= 0) {
          // Add user to existing reaction
          const userAlreadyReacted = reactions[reactionIndex].users.some(u => u.uid === user?.uid);
          if (!userAlreadyReacted) {
            reactions[reactionIndex] = {
              ...reactions[reactionIndex],
              users: [...reactions[reactionIndex].users, { uid: user?.uid, name: user?.name || user?.displayName }]
            };
          }
        } else {
          // Create new reaction
          reactions.push({
            emoji,
            users: [{ uid: user?.uid, name: user?.name || user?.displayName }]
          });
        }
      } else if (action === 'remove') {
        if (reactionIndex >= 0) {
          reactions[reactionIndex] = {
            ...reactions[reactionIndex],
            users: reactions[reactionIndex].users.filter(u => u.uid !== user?.uid)
          };
          if (reactions[reactionIndex].users.length === 0) {
            reactions = reactions.filter(r => r.emoji !== emoji);
          }
        }
      }

      return { ...msg, reactions };
    }));
  }, [user]);

  // Handle optimistic edit - immediately show in UI
  const handleOptimisticEdit = useCallback(({ messageId, content }) => {
    setMessages(prev => prev.map(msg => {
      const msgId = msg.id || msg._id;
      return msgId === messageId
        ? { ...msg, content, isEdited: true, editedAt: new Date().toISOString() }
        : msg;
    }));
  }, []);

  // Handle optimistic delete - immediately show in UI
  const handleOptimisticDelete = useCallback(({ messageId }) => {
    setMessages(prev => prev.map(msg => {
      const msgId = msg.id || msg._id;
      return msgId === messageId ? { ...msg, isDeleted: true } : msg;
    }));
  }, []);

  // Socket event handlers - must be defined before the useEffect that uses them
  const handleNewMessage = useCallback((data) => {
    const channelId = activeChannel?.id || activeChannel?._id;
    if (data.channelId === channelId) {
      // Check if this is a confirmation of our optimistic message
      if (data.tempId) {
        // Replace optimistic message with confirmed one
        setMessages(prev => prev.map(msg =>
          (msg.id === data.tempId || msg._id === data.tempId)
            ? { ...data, isOptimistic: false }
            : msg
        ));
      } else if (data.sender?.uid !== user?.uid) {
        // Only add if it's from another user (we already have our own messages)
        setMessages(prev => [...prev, data]);
      }
    }
    // Update channel's last message
    setChannels(prev => prev.map(ch => {
      const chId = ch.id || ch._id;
      return chId === data.channelId
        ? { ...ch, lastMessage: { content: data.content, senderName: data.sender.name, timestamp: data.createdAt } }
        : ch;
    }));
  }, [activeChannel, user]);

  const handleChannelMessages = useCallback((data) => {
    const channelId = activeChannel?.id || activeChannel?._id;
    if (data.channelId === channelId) {
      setMessages(data.messages);
      setLoadingMessages(false);
    }
  }, [activeChannel]);

  const handleNewChannel = useCallback(({ channel }) => {
    setChannels(prev => [...prev, channel]);
  }, []);

  // Handle message confirmation from server - replace optimistic message with confirmed one
  const handleMessageConfirmed = useCallback((data) => {
    const channelId = activeChannel?.id || activeChannel?._id;
    if (data.channelId === channelId && data.tempId) {
      setMessages(prev => prev.map(msg =>
        (msg.id === data.tempId || msg._id === data.tempId)
          ? { ...data, isOptimistic: false }
          : msg
      ));
    }
  }, [activeChannel]);

  const handleMessageEdited = useCallback(({ messageId, content, editedAt }) => {
    setMessages(prev => prev.map(msg => {
      const msgId = msg.id || msg._id;
      return msgId === messageId ? { ...msg, content, isEdited: true, editedAt } : msg;
    }));
  }, []);

  const handleMessageDeleted = useCallback(({ messageId }) => {
    setMessages(prev => prev.filter(msg => {
      const msgId = msg.id || msg._id;
      return msgId !== messageId;
    }));
  }, []);

  const handleReactionUpdated = useCallback(({ messageId, reactions }) => {
    setMessages(prev => prev.map(msg => {
      const msgId = msg.id || msg._id;
      return msgId === messageId ? { ...msg, reactions } : msg;
    }));
  }, []);

  const fetchChannels = useCallback(async () => {
    try {
      setLoadingChannels(true);
      const data = await communityApi.getChannels();
      setChannels(data.channels);
      // Auto-select first channel
      setActiveChannel(current => current || data.channels[0] || null);
    } catch (error) {
      toast.error('Failed to load channels', { id: 'community-channels-load-error' });
    } finally {
      setLoadingChannels(false);
    }
  }, []);

  // Fetch channels on mount
  useEffect(() => {
    fetchChannels();
  }, [fetchChannels]);

  // Subscribe to socket events
  useEffect(() => {
    const unsubNewMessage = subscribe('new_message', handleNewMessage);
    const unsubChannelMessages = subscribe('channel_messages', handleChannelMessages);
    const unsubNewChannel = subscribe('new_channel', handleNewChannel);
    const unsubMessageConfirmed = subscribe('message_confirmed', handleMessageConfirmed);
    const unsubMessageEdited = subscribe('message_edited', handleMessageEdited);
    const unsubMessageDeleted = subscribe('message_deleted', handleMessageDeleted);
    const unsubReactionUpdated = subscribe('message_reaction_updated', handleReactionUpdated);

    return () => {
      unsubNewMessage();
      unsubChannelMessages();
      unsubNewChannel();
      unsubMessageConfirmed();
      unsubMessageEdited();
      unsubMessageDeleted();
      unsubReactionUpdated();
    };
  }, [subscribe, handleNewMessage, handleChannelMessages, handleNewChannel, handleMessageConfirmed, handleMessageEdited, handleMessageDeleted, handleReactionUpdated]);

  // Join channel when selected
  useEffect(() => {
    if (activeChannel) {
      const channelId = activeChannel.id || activeChannel._id;
      setLoadingMessages(true);
      joinChannel(channelId);
      return () => leaveChannel(channelId);
    }
  }, [activeChannel, joinChannel, leaveChannel]);

  const handleChannelSelect = (channel) => {
    const activeId = activeChannel?.id || activeChannel?._id;
    const newId = channel.id || channel._id;
    if (activeId !== newId) {
      setActiveChannel(channel);
      setMessages([]);
      setLoadingMessages(true);
    }
  };

  const handleCreateChannel = async (channelData) => {
    try {
      const data = await communityApi.createChannel(channelData);
      setChannels(prev => [...prev, data.channel]);
      setActiveChannel(data.channel);
      setShowCreateChannel(false);
      toast.success('Channel created!');
    } catch (error) {
      toast.error(error.message, { id: 'community-create-channel-error' });
    }
  };

  return (
    <div className="h-full bg-background">
      <div className="h-full flex">
        {/* Left Sidebar - Channels/Navigation */}
<div className={`${sidebarOpen ? 'w-72' : 'w-0'} bg-background border-r border-border flex flex-col transition-all duration-300 overflow-hidden shrink-0`}>          {/* View Tabs */}
          <div className="p-3 border-b border-border">
<div className="flex gap-1 bg-muted p-1 rounded-lg w-full">
                <button
                onClick={() => handleTabChange('channels')}
                className={`flex-1 flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-colors ${activeView === 'channels' ? 'bg-card text-foreground shadow-sm' : 'text-muted-foreground hover:text-foreground'
                  }`}
              >
                <MessageSquare className="w-4 h-4" />
                <span className="inline">Chat</span>
              </button>
              <button
                onClick={() => handleTabChange('posts')}
                className={`flex-1 flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-colors ${activeView === 'posts' ? 'bg-card text-foreground shadow-sm' : 'text-muted-foreground hover:text-foreground'
                  }`}
              >
                <FileText className="w-4 h-4" />
                <span className="inline">Posts</span>
              </button>
              <button
                onClick={() => handleTabChange('dms')}
                className={`flex-1 flex items-center justify-center gap-1.5 py-2 px-3 rounded-md text-sm font-medium transition-colors ${activeView === 'dms' ? 'bg-card text-foreground shadow-sm' : 'text-muted-foreground hover:text-foreground'
                  }`}
              >
                <Mail className="w-4 h-4" />
                <span className="inline">DMs</span>
              </button>
            </div>
          </div>

          {/* Connection Status */}
          <div className="px-4 py-2 border-b border-border">
            <div className="flex items-center gap-2 text-xs">
              <span className={`w-2 h-2 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`}></span>
              <span className="text-muted-foreground">{isConnected ? 'Connected' : 'Disconnected'}</span>
              <span className="text-muted-foreground/50 ml-auto">{onlineUsers.length} online</span>
            </div>
          </div>

          {/* Channel List or DM List */}
          <div className="flex-1 overflow-y-auto">
            {activeView === 'channels' && (
              <ChannelList
                channels={channels}
                activeChannel={activeChannel}
                onSelectChannel={handleChannelSelect}
                onCreateChannel={() => setShowCreateChannel(true)}
                loading={loadingChannels}
              />
            )}
            {activeView === 'dms' && (
              <DirectMessages />
            )}
          </div>
        </div>

        {/* Sidebar Toggle */}
        <button
          onClick={() => setSidebarOpen(!sidebarOpen)}
          className="absolute left-0 top-1/2 -translate-y-1/2 z-10 bg-card border border-border rounded-r-lg p-1.5 shadow-md hover:bg-muted lg:hidden"
        >
          {sidebarOpen ? <X className="w-4 h-4 text-foreground" /> : <Menu className="w-4 h-4 text-foreground" />}
        </button>

        {/* Main Content */}
        <div className="flex-1 flex flex-col min-w-0 bg-background">
          {activeView === 'channels' && activeChannel ? (
            <ChatWindow
              channel={activeChannel}
              messages={messages}
              currentUser={user}
              onOptimisticMessage={handleOptimisticMessage}
              onOptimisticReaction={handleOptimisticReaction}
              onOptimisticEdit={handleOptimisticEdit}
              onOptimisticDelete={handleOptimisticDelete}
              loading={loadingMessages}
            />
          ) : activeView === 'posts' ? (
            <PostsFeed />
          ) : activeView === 'dms' ? (
            <div className="flex-1 flex items-center justify-center text-muted-foreground bg-background min-w-0">
              <div className="text-center px-6">
                <Mail className="w-12 h-12 mx-auto mb-3 text-muted-foreground/30" />
                <p className="text-muted-foreground">Select a conversation to start messaging</p>
              </div>
            </div>
          ) : (
            <div className="flex-1 flex items-center justify-center text-muted-foreground">
              <div className="text-center">
                <MessageSquare className="w-12 h-12 mx-auto mb-3 text-muted-foreground/30" />
                <p className="text-muted-foreground">Select a channel to start chatting</p>
              </div>
            </div>
          )}
        </div>

        {/* Right Sidebar - Members */}
        {activeView === 'channels' && (
          <div className={`${membersOpen ? 'w-60' : 'w-0'} bg-background border-l border-border transition-all duration-300 overflow-hidden hidden lg:block`}>
            <MembersList
              channel={activeChannel}
              onlineUsers={onlineUsers}
            />
          </div>
        )}

        {/* Members Toggle */}
        {activeView === 'channels' && (
          <button
            onClick={() => setMembersOpen(!membersOpen)}
            className="absolute right-0 top-1/2 -translate-y-1/2 z-10 bg-card border border-border rounded-l-lg p-1.5 shadow-md hover:bg-muted hidden lg:block"
          >
            <Users className="w-4 h-4 text-foreground" />
          </button>
        )}

        {/* Create Channel Modal */}
        {showCreateChannel && (
          <CreateChannelModal
            onClose={() => setShowCreateChannel(false)}
            onCreate={handleCreateChannel}
          />
        )}
      </div>
    </div>
  );
}

// Create Channel Modal Component
function CreateChannelModal({ onClose, onCreate }) {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('general');
  const [type, setType] = useState('public');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    try {
      await onCreate({ name, description, category, type });
    } finally {
      setLoading(false);
    }
  };

  const categories = [
    { value: 'general', label: '💬 General' },
    { value: 'job-hunting', label: '🔍 Job Hunting' },
    { value: 'interview-prep', label: '🎯 Interview Prep' },
    { value: 'resume-tips', label: '📄 Resume Tips' },
    { value: 'networking', label: '🤝 Networking' },
    { value: 'other', label: '📌 Other' }
  ];

  return (
    <div className="fixed inset-0 bg-background/80 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <div className="bg-card border border-border rounded-xl shadow-xl max-w-md w-full p-6">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-foreground flex items-center gap-2">
            <Hash className="w-5 h-5 text-primary" />
            Create Channel
          </h2>
          <button onClick={onClose} className="text-muted-foreground hover:text-foreground transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-muted-foreground mb-1">
              Channel Name
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g., frontend-devs"
              className="w-full px-3 py-2 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-transparent"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-muted-foreground mb-1">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="What's this channel about?"
              rows={2}
              className="w-full px-3 py-2 bg-muted border border-border rounded-lg text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary focus:border-transparent"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-muted-foreground mb-1">
              Category
            </label>
            <select
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              className="w-full px-3 py-2 bg-muted border border-border rounded-lg text-foreground focus:ring-2 focus:ring-primary focus:border-transparent"
            >
              {categories.map(cat => (
                <option key={cat.value} value={cat.value}>{cat.label}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-muted-foreground mb-2">
              Visibility
            </label>
            <div className="flex gap-4">
              <label className="flex items-center gap-2 cursor-pointer">
                <input
                  type="radio"
                  name="type"
                  value="public"
                  checked={type === 'public'}
                  onChange={(e) => setType(e.target.value)}
                  className="text-primary"
                />
                <span className="text-sm text-foreground">Public</span>
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                <input
                  type="radio"
                  name="type"
                  value="private"
                  checked={type === 'private'}
                  onChange={(e) => setType(e.target.value)}
                  className="text-primary"
                />
                <span className="text-sm text-foreground">Private</span>
              </label>
            </div>
          </div>

          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 border border-border rounded-lg text-foreground hover:bg-muted transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading || !name.trim()}
              className="flex-1 px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 font-medium disabled:opacity-50 transition-colors"
            >
              {loading ? 'Creating...' : 'Create Channel'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react'
import { Link } from 'react-router-dom'
import toast from 'react-hot-toast'
import { motion } from 'framer-motion'
import {
  FileText,
  Briefcase,
  Search,
  Plus,
  ArrowRight,
  CheckCircle2,
  Send,
  Star,
  MessageSquare,
  Zap,
  Target,
  TrendingUp,
  Clock,
  Users,
  Sparkles,
  GraduationCap,
  Bell,
  Mic,
  Globe,
  Github,
  Flame,
  Code2
} from 'lucide-react'
import { resumeApi, jobTrackerApi, portfolioApi, userProfileApi } from '../services/api'
import Button from '../components/Button'
import { 
  SkeletonDashboardActions, 
  SkeletonStatCards, 
  SkeletonJobList,
  SkeletonList 
} from '../components/ui/Skeleton'
import { getGithubUsername } from '../utils/github'

const STATUS_CONFIG = {
  saved: { label: 'Saved', color: 'bg-muted text-muted-foreground border border-border', icon: Star },
  applied: { label: 'Applied', color: 'bg-primary/10 text-primary border border-primary/20', icon: Send },
  interviewing: { label: 'Interviewing', color: 'bg-secondary/10 text-secondary border border-secondary/20', icon: MessageSquare },
  offered: { label: 'Offered', color: 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20', icon: CheckCircle2 }
}

export default function Dashboard() {
  const [resumes, setResumes] = useState([])
  const [trackedJobs, setTrackedJobs] = useState([])
  const [loading, setLoading] = useState(true)
  const [fetchError, setFetchError] = useState('')
  const [jobStats, setJobStats] = useState({
    total: 0,
    saved: 0,
    applied: 0,
    interviewing: 0,
    offered: 0
  })
  const [portfolioCount, setPortfolioCount] = useState(0)
  const [candidateName, setCandidateName] = useState('')
  const [githubOverview, setGithubOverview] = useState({
    connected: false,
    loading: false,
    stats: null
  })
  const fetchRequestId = useRef(0)
  const isMounted = useRef(false)

  useEffect(() => {
    isMounted.current = true
    fetchData()

    return () => {
      isMounted.current = false
      fetchRequestId.current += 1
    }
  }, [])

  const fetchData = async () => {
    const requestId = fetchRequestId.current + 1
    fetchRequestId.current = requestId
    const canUpdate = () => isMounted.current && fetchRequestId.current === requestId

    try {
      const [resumeRes, jobsRes, portfolioRes, userProfileRes] = await Promise.all([
        resumeApi.getAll().catch(() => ({ resumes: [] })),
        jobTrackerApi.getAll().catch(() => ({ trackedJobs: [] })),
        portfolioApi.getAll().catch(() => ({ portfolioItems: [] })),
        userProfileApi.getMyProfile().catch(() => null)
      ])

      if (!canUpdate()) return

      const fetchedResumes = Array.isArray(resumeRes.data) ? resumeRes.data : (resumeRes.resumes || resumeRes.data?.resumes || [])
      setResumes(fetchedResumes)
      const jobs = jobsRes.trackedJobs || []
      setTrackedJobs(jobs)

      const portfolios =
        portfolioRes.portfolios ||
        portfolioRes.data?.portfolios ||
        portfolioRes.data ||
        [];

      setPortfolioCount(portfolios.length)
      const githubUsername = getGithubUsername(
        userProfileRes?.profile?.github ||
        userProfileRes?.data?.github ||
        userProfileRes?.github
      )
      const rawName = userProfileRes?.profile?.name || userProfileRes?.data?.name || userProfileRes?.name || ''
      setCandidateName(rawName.trim())

      if (githubUsername) {
        setGithubOverview({ connected: true, loading: true, stats: null })
        resumeApi.previewGitHub(githubUsername)
          .then((githubRes) => {
            if (!canUpdate()) return

            const preview = githubRes.preview || githubRes.data || githubRes
            setGithubOverview({
              connected: true,
              loading: false,
              stats: buildGithubStats(preview)
            })
          })
          .catch(() => {
            if (!canUpdate()) return

            setGithubOverview({ connected: true, loading: false, stats: null })
          })
      } else {
        setGithubOverview({ connected: false, loading: false, stats: null })
      }

      const stats = {
        total: jobs.length,
        saved: jobs.filter(j => j.status === 'saved').length,
        applied: jobs.filter(j => j.status === 'applied').length,
        interviewing: jobs.filter(j => j.status === 'interviewing').length,
        offered: jobs.filter(j => j.status === 'offered').length
      }
      setJobStats(stats)
    } catch (error) {
      if (!canUpdate()) return

      console.error('Failed to fetch data:', error)
      setFetchError('Failed to load your dashboard. Please try again.')
      toast.error('Failed to load dashboard data')
    } finally {
      if (!canUpdate()) return

      setLoading(false)
    }
  }

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric'
    })
  }

  const buildGithubStats = (profile = {}) => {
    const repositorySource = profile.topRepositories || profile.repositories || profile.repos
    const repositories = Array.isArray(repositorySource) ? repositorySource : []
    const languageSource =
      profile.topLanguages ||
      profile.languages ||
      repositories.map((repo) => repo.language).filter(Boolean)

    const topLanguages = Array.isArray(languageSource)
      ? languageSource
      : Object.entries(languageSource || {})
        .sort((a, b) => Number(b[1]) - Number(a[1]))
        .map(([language]) => language)

    const totalStars = profile.totalStars ??
      profile.stars ??
      repositories.reduce((sum, repo) => sum + Number(repo.stars || repo.stargazers_count || 0), 0)

    return {
      totalRepos: profile.totalRepos ?? profile.public_repos ?? profile.publicRepos ?? repositories.length,
      totalStars,
      topLanguages: topLanguages.slice(0, 3),
      currentStreak: profile.currentStreak ?? profile.streak?.currentStreak ?? profile.current_streak ?? null
    }
  }

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.05 }
    }
  }

  const itemVariants = {
    hidden: { opacity: 0, y: 10 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.4 } }
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <motion.div
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          className="mb-10 p-8 glass rounded-3xl glow border-border/50 relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 -mr-20 -mt-20 w-64 h-64 bg-primary/10 rounded-full blur-3xl animate-pulse"></div>
          <h1 className="text-4xl md:text-5xl font-black text-foreground mb-3 tracking-tight">
            Welcome back{candidateName ? <span className="gradient-text">, {candidateName}</span> : <span className="gradient-text"> Pilot</span>}
          </h1>
          <p className="text-lg text-muted-foreground font-medium max-w-2xl">Your career dashboard is ready. Track applications, enhance resumes, and land your dream job with AI insights.</p>
        </motion.div>

        {loading ? (
          <div className="space-y-10">
            {/* Quick Actions Skeleton */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4 }}
            >
              <SkeletonDashboardActions />
            </motion.div>

            {/* Stats Skeleton */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, delay: 0.1 }}
            >
              <SkeletonStatCards count={5} />
            </motion.div>

            {/* Recent Applications & Resumes Skeleton */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, delay: 0.2 }}
              className="grid lg:grid-cols-2 gap-10"
            >
              <div>
                <div className="mb-6 h-8 bg-muted rounded-lg w-1/3 animate-pulse" />
                <SkeletonList count={3} />
              </div>
              <div>
                <div className="mb-6 h-8 bg-muted rounded-lg w-1/3 animate-pulse" />
                <SkeletonList count={3} />
              </div>
            </motion.div>
          </div>
        ) : (
          <motion.div variants={containerVariants} initial="hidden" animate="visible">
            {fetchError && (
              <div className="mb-8 rounded-2xl border border-destructive/20 bg-destructive/5 px-6 py-4 text-sm text-destructive flex items-center justify-between backdrop-blur-md">
                <span className="font-semibold">{fetchError}</span>
                <button
                  onClick={fetchData}
                  className="px-4 py-1.5 bg-destructive text-foreground rounded-lg font-bold hover:opacity-90 transition-opacity"
                >
                  Retry
                </button>
              </div>
            )}

            {/* Modular Hubs */}
            <motion.div variants={itemVariants} className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-5 mb-10">
              {[
                { to: '/hub/resume', icon: FileText, label: 'Resume Builder', desc: 'Create, parse, and optimize ATS resumes.', sub: `${resumes.length} resumes`, color: 'primary', badge: 'AI' },
                { to: '/hub/jobs', icon: Briefcase, label: 'Job Finder', desc: 'Search jobs, set alerts, and track applications.', sub: `${jobStats.total} tracked`, color: 'primary' },
                { to: '/hub/portfolio', icon: Globe, label: 'Portfolio Builder', desc: 'Sync repos and deploy portfolios instantly.', sub: `${portfolioCount} portfolios`, color: 'secondary' },
                { to: '/hub/career', icon: GraduationCap, label: 'Career Growth', desc: 'AI mock interviews, email & profile tuning.', sub: '4 tools', color: 'emerald-500', badge: 'AI' },
                { to: '/dashboard/analytics', icon: TrendingUp, label: 'Interview Analytics', desc: 'Visualize mock interview performance trends and scores.', sub: 'Real-time metrics', color: 'emerald-500', badge: 'AI' },
                { to: '/hub/community', icon: Users, label: 'Community Hub', desc: 'Group chat, public posts, and direct DMs.', sub: 'Connect', color: 'primary' },
              ].map((hub, idx) => (
                <motion.div key={idx} variants={itemVariants}>
                  <Link to={hub.to} className="group block h-full">
                    <div className="relative p-6 rounded-3xl bg-card border border-border overflow-hidden transition-all duration-300 hover:border-primary/40 hover:shadow-xl hover:shadow-primary/5 hover:-translate-y-1 h-full flex flex-col justify-between">
                      {/* Hover glow effect */}
                      <div className="absolute inset-0 bg-gradient-to-br from-primary/5 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none" />
                      
                      {/* Badge */}
                      {hub.badge && (
                        <div className="absolute top-4 right-4 px-2 py-0.5 bg-primary/10 rounded-full text-[9px] text-primary font-black uppercase tracking-wider border border-primary/20">
                          {hub.badge}
                        </div>
                      )}

                      <div>
                        {/* Icon */}
                        <div className={`w-14 h-14 bg-${hub.color}/10 border border-${hub.color}/20 rounded-2xl flex items-center justify-center mb-5 group-hover:scale-110 group-hover:bg-${hub.color}/15 transition-all duration-300`}>
                          <hub.icon className={`w-7 h-7 text-${hub.color}`} />
                        </div>
                        
                        {/* Content */}
                        <h3 className="text-lg font-black text-foreground mb-2 group-hover:text-primary transition-colors">{hub.label}</h3>
                        <p className="text-muted-foreground text-xs font-semibold leading-relaxed mb-4">{hub.desc}</p>
                      </div>

                      {/* Footer Info */}
                      <div className="flex items-center justify-between text-[11px] font-bold text-muted-foreground pt-4 border-t border-border/40 mt-auto">
                        <span className="uppercase tracking-wider">{hub.sub}</span>
                        <span className="text-primary opacity-0 group-hover:opacity-100 group-hover:translate-x-0.5 transition-all flex items-center gap-0.5">
                          Open <ArrowRight className="w-3 h-3" />
                        </span>
                      </div>
                    </div>
                  </Link>
                </motion.div>
              ))}
            </motion.div>

            {/* Stats Row */}
            <motion.div variants={itemVariants} className="grid grid-cols-2 md:grid-cols-6 gap-5 mb-10">
              {[
                {
                  icon: Star,
                  value: jobStats.saved,
                  label: "Saved",
                  color: "text-muted-foreground",
                  bg: "bg-muted",
                },
                {
                  icon: Send,
                  value: jobStats.applied,
                  label: "Applied",
                  color: "text-primary",
                  bg: "bg-primary/10",
                },
                {
                  icon: MessageSquare,
                  value: jobStats.interviewing,
                  label: "Interviewing",
                  color: "text-secondary",
                  bg: "bg-secondary/10",
                },
                {
                  icon: CheckCircle2,
                  value: jobStats.offered,
                  label: "Offers",
                  color: "text-emerald-500",
                  bg: "bg-emerald-500/10",
                },
                {
                  icon: FileText,
                  value: resumes.length,
                  label: "Resumes",
                  color: "text-primary",
                  bg: "bg-primary/10",
                },
                {
                  icon: Globe,
                  value: portfolioCount,
                  label: "Portfolios",
                  color: "text-purple-500",
                  bg: "bg-purple-500/10",
                  link: "/portfolio",
                },
              ].map((stat, idx) => {
                const content = (
                  <div className="p-6 rounded-2xl bg-card border border-border text-center hover:border-primary/30 transition-all shadow-sm group">
                    <div className={`w-12 h-12 ${stat.bg} rounded-xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform`}>
                      <stat.icon className={`w-6 h-6 ${stat.color}`} />
                    </div>

                    <p className="text-3xl font-black text-foreground">
                      {stat.value}
                    </p>

                    <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest mt-1">
                      {stat.label}
                    </p>
                  </div>
                );

                return stat.link ? (
                  <motion.div key={idx} variants={itemVariants}>
                    <Link to={stat.link}>
                      {content}
                    </Link>
                  </motion.div>
                ) : (
                  <motion.div key={idx} variants={itemVariants}>
                    {content}
                  </motion.div>
                );
              })}
            </motion.div>

            {/* GitHub Overview */}
            <motion.div variants={itemVariants} className="mb-10">
              {githubOverview.connected ? (
                <div className="rounded-2xl bg-card border border-border p-5 shadow-sm">
                  <div className="flex flex-col gap-5 lg:flex-row lg:items-center lg:justify-between">
                    <div className="flex items-start gap-4">
                      <div className="w-12 h-12 rounded-xl bg-muted flex items-center justify-center shrink-0">
                        <Github className="w-6 h-6 text-foreground" />
                      </div>
                      <div>
                        <div className="flex flex-wrap items-center gap-3">
                          <h2 className="text-lg font-black text-foreground">GitHub Overview</h2>
                          {githubOverview.loading && (
                            <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">
                              Syncing
                            </span>
                          )}
                        </div>
                        <p className="text-xs font-semibold text-muted-foreground mt-1">
                          Your repository snapshot at a glance.
                        </p>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 lg:min-w-[560px]">
                      {[
                        { icon: Github, label: 'Repos', value: githubOverview.stats?.totalRepos ?? '-' },
                        { icon: Star, label: 'Stars', value: githubOverview.stats?.totalStars ?? '-' },
                        { icon: Code2, label: 'Languages', value: githubOverview.stats?.topLanguages?.join(', ') || '-' },
                        { icon: Flame, label: 'Streak', value: githubOverview.stats?.currentStreak !== null && githubOverview.stats?.currentStreak !== undefined ? `${githubOverview.stats.currentStreak}d` : '-' },
                      ].map((item) => (
                        <div key={item.label} className="rounded-xl border border-border bg-background/50 px-3 py-3 min-w-0">
                          <div className="flex items-center gap-2 text-muted-foreground mb-1">
                            <item.icon className="w-3.5 h-3.5 shrink-0" />
                            <span className="text-[10px] font-black uppercase tracking-widest">{item.label}</span>
                          </div>
                          <p className="text-sm font-black text-foreground truncate">{item.value}</p>
                        </div>
                      ))}
                    </div>

                    <Link to="/github" className="inline-flex items-center justify-center gap-2 rounded-xl bg-primary/10 px-4 py-2 text-sm font-black text-primary hover:bg-primary/15 transition-colors shrink-0">
                      View Details <ArrowRight className="w-4 h-4" />
                    </Link>
                  </div>
                </div>
              ) : (
                <div className="rounded-2xl border border-primary/20 bg-primary/5 px-5 py-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                  <div className="flex items-center gap-3">
                    <Github className="w-5 h-5 text-primary shrink-0" />
                    <p className="text-sm font-bold text-foreground">Connect GitHub to see repository stats on your dashboard.</p>
                  </div>
                  <Link to="/profile" className="inline-flex items-center justify-center gap-2 rounded-xl bg-primary px-4 py-2 text-xs font-black text-primary-foreground hover:bg-primary/90 transition-colors">
                    Connect GitHub <ArrowRight className="w-3.5 h-3.5" />
                  </Link>
                </div>
              )}
            </motion.div>

            <div className="grid lg:grid-cols-2 gap-10">
              {/* Recent Applications */}
              <motion.div variants={itemVariants}>
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-black text-foreground flex items-center gap-3">
                    <Clock className="w-6 h-6 text-primary" />
                    Recent Applications
                  </h2>
                  <Link to="/job-tracker" className="group text-primary hover:text-primary/80 text-sm font-bold flex items-center gap-1 transition-all">
                    View all <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                  </Link>
                </div>

                {trackedJobs.length === 0 ? (
                  <div className="rounded-[2rem] glass border border-primary/20 text-center py-16 glow relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-br from-primary/5 to-transparent"></div>
                    <div className="w-16 h-16 bg-primary/10 rounded-2xl flex items-center justify-center mx-auto mb-6 relative z-10 animate-bounce">
                      <Briefcase className="w-8 h-8 text-primary" />
                    </div>
                    <h3 className="text-xl font-bold text-foreground mb-2 relative z-10">No applications yet</h3>
                    <p className="text-muted-foreground text-sm mb-6 max-w-xs mx-auto font-medium relative z-10">Start searching for jobs to track your applications</p>
                    <Link to="/jobs" className="relative z-10">
                      <Button variant="primary" className="font-bold px-8 shadow-lg shadow-primary/25 hover:shadow-primary/40 transition-all-300 hover:-translate-y-0.5">Search Jobs</Button>
                    </Link>
                  </div>
                ) : (
                  <div className="rounded-[2rem] bg-card border border-border overflow-hidden shadow-sm">
                    <div className="divide-y divide-border">
                      {/** * GSSoC Optimization: Defensive structural evaluation on the active data view slice.
                       * Prevents layout container voids if the array slice metrics index is altered.
                       */}
                      {(() => {
                        const displayedJobs = trackedJobs.slice(0, 5);

                        if (displayedJobs.length > 0) {
                          return displayedJobs.map((job, index) => {
                            const statusConfig = STATUS_CONFIG[job.status] || STATUS_CONFIG.saved;
                            const StatusIcon = statusConfig.icon;
                            return (
                              <div key={job.id || index} className="p-5 hover:bg-muted/50 transition-all group">
