    <div className="h-full min-h-[calc(100vh-4rem)] flex flex-col bg-[#050816] overflow-hidden text-slate-200">
      
      {/* Top Bar */}
      <div className="h-16 border-b border-white/10 bg-[#0b1120] flex items-center justify-between px-6 shrink-0">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-500/10 rounded-lg">
            <GitMerge className="w-5 h-5 text-blue-500" />
          </div>
          <h1 className="text-lg font-bold">Codebase Analyzer</h1>
        </div>

        <div className="flex-1 flex justify-center mx-8 relative">
           <span className="text-slate-400 font-mono text-sm">{repoUrl || 'No Repository Loaded'}</span>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => navigate('/repo-analyzer/dashboard')}
            className="px-3 py-1.5 text-sm font-medium rounded-md bg-slate-800 hover:bg-slate-700 text-slate-300 transition-all cursor-pointer mr-2"
          >
            Back to Dashboard
          </button>
          <span className="text-sm text-slate-400 font-medium">Mode:</span>
          <div className="flex items-center bg-[#0f172a] rounded-lg p-1 border border-slate-700">
            <button
              onClick={() => setIsInterviewMode(false)}
              className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all cursor-pointer ${!isInterviewMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}
            >
              QA Engine
            </button>
            <button
              onClick={() => setIsInterviewMode(true)}
              className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all cursor-pointer ${isInterviewMode ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Interview
            </button>
          </div>
        </div>
      </div>

      {/* Main Content Split */}
      <div className="flex-1 flex overflow-hidden">
        
        {/* Left: Graph Canvas */}
        <div className="flex-1 relative border-r border-white/10">
          {!repoUrl ? (
            <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500">
              <GitMerge className="w-16 h-16 mb-4 opacity-50" />
              <p className="text-lg font-medium text-slate-300">No Repository Loaded</p>
              <p className="text-sm mt-2 max-w-md text-center">Paste a GitHub URL above to analyze its dependency graph and chat with the architecture.</p>
            </div>
          ) : (
            <GraphCanvas />
          )}
        </div>

        {/* Right: Drawer + Chat */}
        <div className="w-[450px] shrink-0 flex flex-col bg-[#050816]">
          <AnimatePresence>
            {selectedFile && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: '50%', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                className="shrink-0 border-b border-white/10"
              >
                <FileDrawer />
              </motion.div>
            )}
          </AnimatePresence>
          
          <div className="flex-1 overflow-hidden">
            <ChatPanel />
          </div>
        </div>

      </div>
    </div>
  );
}

import React, { useRef, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useNavigate } from 'react-router-dom'
import {
  ArrowLeft, ArrowRight, CheckCircle, Plus, Trash2,
  Save, FileText, User, Briefcase, GraduationCap, Code, Star
} from 'lucide-react'
import { resumeApi } from '../services/api'
import { toast } from 'react-hot-toast'
import { cn } from '@/lib/utils'
import PhoneInput from '../components/PhoneInput'
import {
  validatePersonalStep,
  validateEducationStep,
  validateExperienceStep,
  hasErrors,
} from '../utils/resumeValidation'

const STEPS = [
  { id: 'personal',   title: 'Personal Info', icon: User },
  { id: 'education',  title: 'Education',     icon: GraduationCap },
  { id: 'experience', title: 'Experience',    icon: Briefcase },
  { id: 'projects',   title: 'Projects',      icon: Code },
  { id: 'skills',     title: 'Skills',        icon: Star },
  { id: 'preview',    title: 'Preview',       icon: FileText },
]

// ─────────────────── small helpers ───────────────────────────────────────────
/** Red border class when an error exists for a field key. */
function errBorder(errors, key) {
  return errors?.[key] ? 'border-red-500 focus:ring-red-400/30' : 'border-border'
}

/** Inline error message below a field. */
function FieldError({ msg }) {
  if (!msg) return null
  return (
    <p className="text-red-500 text-sm mt-1" role="alert">{msg}</p>
  )
}

// ─────────────────── component ───────────────────────────────────────────────
export default function ResumeBuilder() {
  const navigate   = useNavigate()
  const firstErrRef = useRef(null)

  const [currentStep, setCurrentStep] = useState(0)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [targetRole, setTargetRole]   = useState('')

  // ── form state ──────────────────────────────────────────────────────────────
  const [personal, setPersonal] = useState({
    name: '', email: '', phone: '', linkedin: '', github: '', portfolio: '', summary: '',
  })
  // phone is stored split: country code + digit string
  const [phoneCode,   setPhoneCode]   = useState('+91')
  const [phoneDigits, setPhoneDigits] = useState('')

  const [education, setEducation] = useState([
    { school: '', degree: '', field: '', startDate: '', endDate: '', gpa: '', description: '' }
  ])
  const [experience, setExperience] = useState([
    { title: '', company: '', location: '', startDate: '', endDate: '', current: false, description: '' }
  ])
  const [projects, setProjects] = useState([
    { name: '', tech: '', link: '', description: '' }
  ])
  const [skills, setSkills] = useState('')

  // ── error state ─────────────────────────────────────────────────────────────
  const [personalErrors,   setPersonalErrors]   = useState({})
  const [educationErrors,  setEducationErrors]  = useState([])   // array per entry
  const [experienceErrors, setExperienceErrors] = useState([])   // array per entry

  // ── helpers: update array entries immutably ─────────────────────────────────
  function updateEdu(index, key, value) {
    setEducation(prev => {
      const next = [...prev]
      next[index] = { ...next[index], [key]: value }
      return next
    })
    // Clear the matching error on change
    setEducationErrors(prev => {
      const next = [...prev]
      if (next[index]) { next[index] = { ...next[index], [key]: '' } }
      return next
    })
  }

  function updateExp(index, key, value) {
    setExperience(prev => {
      const next = [...prev]
      next[index] = { ...next[index], [key]: value }
      return next
    })
    setExperienceErrors(prev => {
      const next = [...prev]
      if (next[index]) { next[index] = { ...next[index], [key]: '' } }
      return next
    })
  }

  function updatePersonal(key, value) {
    setPersonal(prev => ({ ...prev, [key]: value }))
    if (personalErrors[key]) {
      setPersonalErrors(prev => ({ ...prev, [key]: '' }))
    }
  }

  // ── list management ──────────────────────────────────────────────────────────
  const addEducation    = () => setEducation(p => [...p, { school: '', degree: '', field: '', startDate: '', endDate: '', gpa: '', description: '' }])
  const removeEducation = i  => { setEducation(p => p.filter((_, idx) => idx !== i)); setEducationErrors(p => p.filter((_, idx) => idx !== i)) }

  const addExperience    = () => setExperience(p => [...p, { title: '', company: '', location: '', startDate: '', endDate: '', current: false, description: '' }])
  const removeExperience = i  => { setExperience(p => p.filter((_, idx) => idx !== i)); setExperienceErrors(p => p.filter((_, idx) => idx !== i)) }

  const addProject    = () => setProjects(p => [...p, { name: '', tech: '', link: '', description: '' }])
  const removeProject = i  => setProjects(p => p.filter((_, idx) => idx !== i))

  // ── step validation ──────────────────────────────────────────────────────────
  function validateCurrentStep() {
    switch (currentStep) {
      case 0: {
        const errs = validatePersonalStep(personal, targetRole, phoneDigits)
        setPersonalErrors(errs)
        return !hasErrors(errs)
      }
      case 1: {
        const errs = validateEducationStep(education)
        setEducationErrors(errs)
        return !hasErrors(errs)
      }
      case 2: {
        const errs = validateExperienceStep(experience)
        setExperienceErrors(errs)
        return !hasErrors(errs)
      }
      default:
        return true
    }
  }

  function handleNext() {
    if (!validateCurrentStep()) {
      // Focus first invalid field
      setTimeout(() => {
        const el = document.querySelector('[aria-invalid="true"], .border-red-500')
        el?.focus()
        el?.scrollIntoView({ behavior: 'smooth', block: 'center' })
      }, 50)
      return
    }
    setCurrentStep(s => Math.min(s + 1, STEPS.length - 1))
  }

  const handlePrev = () => setCurrentStep(s => Math.max(s - 1, 0))

  // ── markdown preview & generate ──────────────────────────────────────────────
  const generateMarkdown = () => {
    // Compose full phone string
    const fullPhone = phoneDigits ? `${phoneCode} ${phoneDigits}` : ''
    let md = `# ${personal.name || 'Your Name'}\n\n`

    const contact = []
    if (personal.email)     contact.push(`[${personal.email}](mailto:${personal.email})`)
    if (fullPhone)          contact.push(fullPhone)
    if (personal.linkedin)  contact.push(`[LinkedIn](${personal.linkedin})`)
    if (personal.github)    contact.push(`[GitHub](${personal.github})`)
    if (personal.portfolio) contact.push(`[Portfolio](${personal.portfolio})`)
    md += `${contact.join(' | ')}\n\n`

    if (personal.summary) md += `## SUMMARY\n\n${personal.summary}\n\n`

    if (education.some(e => e.school)) {
      md += `## EDUCATION\n\n`
      education.forEach(e => {
        if (!e.school) return
        md += `**${e.degree}${e.field ? ' in ' + e.field : ''}** | ${e.school} | ${e.startDate} - ${e.endDate}\n`
        if (e.gpa) md += `- GPA: ${e.gpa}\n`
        if (e.description) md += `- ${e.description}\n`
        md += '\n'
      })
    }

    if (experience.some(e => e.title)) {
      md += `## EXPERIENCE\n\n`
      experience.forEach(e => {
        if (!e.title) return
        md += `**${e.title}** | ${e.company} | ${e.location} | ${e.startDate} - ${e.current ? 'Present' : e.endDate}\n`
        const bullets = e.description.split('\n').filter(b => b.trim())
        bullets.forEach(b => { md += `- ${b.replace(/^- /, '').trim()}\n` })
        md += '\n'
      })
    }

    if (projects.some(p => p.name)) {
      md += `## PROJECTS\n\n`
      projects.forEach(p => {
        if (!p.name) return
        md += `**${p.name}** | ${p.tech}\n`
        const bullets = p.description.split('\n').filter(b => b.trim())
        bullets.forEach(b => { md += `- ${b.replace(/^- /, '').trim()}\n` })
        if (p.link) md += `- [Project Link](${p.link})\n`
        md += '\n'
      })
    }

    if (skills) md += `## SKILLS\n\n${skills}\n\n`

    return md
  }

  const handleGenerate = async () => {
    try {
      setIsSubmitting(true)
      const markdown = generateMarkdown()
      const response = await resumeApi.create({
        originalText: markdown,
        jobRole: targetRole || 'Software Engineer',
        title:   `${personal.name || 'My'} Resume - ${new Date().toLocaleDateString()}`,
      })
      toast.success('Resume created successfully!')
      navigate(`/enhance/${response.data.id}`)
    } catch (error) {
      toast.error(error.message || 'Failed to create resume')
    } finally {
      setIsSubmitting(false)
    }
  }

  // ── shared input class builder ────────────────────────────────────────────────
  const inputCls = (errorKey, errors = personalErrors) =>
    cn(
      'w-full bg-background/50 border rounded-xl px-4 py-2 transition-colors',
      'focus:outline-none focus:ring-2 focus:ring-primary/30',
      errors?.[errorKey] ? 'border-red-500 focus:ring-red-400/30' : 'border-border'
    )

  const inputClsArr = (errors) => (errorKey) =>
    cn(
      'w-full bg-background/50 border rounded-lg px-4 py-2 transition-colors',
      'focus:outline-none focus:ring-2 focus:ring-primary/30',
      errors?.[errorKey] ? 'border-red-500 focus:ring-red-400/30' : 'border-border'
    )

  // ── step renderers ────────────────────────────────────────────────────────────
  const renderStep = () => {
    switch (currentStep) {

      /* ── Step 0: Personal Info ── */
      case 0:
        return (
          <div className="space-y-4">
            <h2 className="text-2xl font-semibold mb-6">Personal Information</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

              {/* Full Name */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="name">
                  Full Name <span className="text-red-500">*</span>
                </label>
                <input
                  id="name"
                  type="text"
                  className={inputCls('name')}
                  value={personal.name}
                  onChange={e => updatePersonal('name', e.target.value)}
                  placeholder="John Doe"
                  aria-invalid={!!personalErrors.name}
                  aria-describedby={personalErrors.name ? 'name-error' : undefined}
                />
                <FieldError msg={personalErrors.name} />
              </div>

              {/* Target Job Role */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="targetRole">
                  Target Job Role <span className="text-red-500">*</span>
                </label>
                <input
                  id="targetRole"
                  type="text"
                  className={inputCls('targetRole')}
                  value={targetRole}
                  onChange={e => {
                    setTargetRole(e.target.value)
                    if (personalErrors.targetRole) setPersonalErrors(p => ({ ...p, targetRole: '' }))
                  }}
                  placeholder="Software Engineer"
                  aria-invalid={!!personalErrors.targetRole}
                />
                <FieldError msg={personalErrors.targetRole} />
              </div>

              {/* Email */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="email">
                  Email <span className="text-red-500">*</span>
                </label>
                <input
                  id="email"
                  type="email"
                  className={inputCls('email')}
                  value={personal.email}
                  onChange={e => updatePersonal('email', e.target.value)}
                  placeholder="john@example.com"
                  aria-invalid={!!personalErrors.email}
                />
                <FieldError msg={personalErrors.email} />
              </div>

              {/* Phone */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="phone-number">
                  Phone <span className="text-red-500">*</span>
                </label>
                <PhoneInput
                  countryCode={phoneCode}
                  onCountryChange={code => {
                    setPhoneCode(code)
                    if (personalErrors.phone) setPersonalErrors(p => ({ ...p, phone: '' }))
                  }}
                  digits={phoneDigits}
                  onDigitsChange={d => {
                    setPhoneDigits(d)
                    if (personalErrors.phone) setPersonalErrors(p => ({ ...p, phone: '' }))
                  }}
                  error={personalErrors.phone}
                />
              </div>

              {/* LinkedIn */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="linkedin">LinkedIn URL</label>
                <input
                  id="linkedin"
                  type="url"
                  className={inputCls('linkedin')}
                  value={personal.linkedin}
                  onChange={e => updatePersonal('linkedin', e.target.value)}
                  placeholder="https://www.linkedin.com/in/johndoe"
                  aria-invalid={!!personalErrors.linkedin}
                />
                <FieldError msg={personalErrors.linkedin} />
              </div>

              {/* GitHub */}
              <div>
                <label className="block text-sm font-medium mb-1" htmlFor="github">GitHub URL</label>
                <input
                  id="github"
                  type="url"
                  className={inputCls('github')}
                  value={personal.github}
                  onChange={e => updatePersonal('github', e.target.value)}
                  placeholder="https://github.com/johndoe"
                  aria-invalid={!!personalErrors.github}
                />
                <FieldError msg={personalErrors.github} />
              </div>
            </div>

            {/* Summary */}
            <div className="pt-2">
              <label className="block text-sm font-medium mb-1" htmlFor="summary">Professional Summary</label>
              <textarea
                id="summary"
                className="w-full bg-background/50 border border-border rounded-xl px-4 py-2 min-h-[100px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                value={personal.summary}
                onChange={e => updatePersonal('summary', e.target.value)}
                placeholder="A brief summary of your professional background..."
              />
            </div>
          </div>
        )

      /* ── Step 1: Education ── */
      case 1:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Education</h2>
            {education.map((edu, index) => {
              const errs = educationErrors[index] || {}
              const ic = inputClsArr(errs)
              return (
                <div key={index} className="bg-background/30 p-5 rounded-xl border border-border relative">
                  <button
                    onClick={() => removeEducation(index)}
                    className="absolute top-4 right-4 text-muted-foreground hover:text-red-500 transition-colors"
                    aria-label="Remove education entry"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        School <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('school')}
                        value={edu.school}
                        onChange={e => updateEdu(index, 'school', e.target.value)}
                        placeholder="University Name"
                        aria-invalid={!!errs.school}
                      />
                      <FieldError msg={errs.school} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Degree <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('degree')}
                        value={edu.degree}
                        onChange={e => updateEdu(index, 'degree', e.target.value)}
                        placeholder="B.S., M.S., etc."
                        aria-invalid={!!errs.degree}
                      />
                      <FieldError msg={errs.degree} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">Field of Study</label>
                      <input
                        type="text"
                        className={ic('field')}
                        value={edu.field}
                        onChange={e => updateEdu(index, 'field', e.target.value)}
                        placeholder="Computer Science"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">GPA (Optional)</label>
                      <input
                        type="text"
                        className={ic('gpa')}
                        value={edu.gpa}
                        onChange={e => updateEdu(index, 'gpa', e.target.value)}
                        placeholder="3.8/4.0"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Start Date <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="month"
                        className={ic('startDate')}
                        value={edu.startDate}
                        onChange={e => updateEdu(index, 'startDate', e.target.value)}
                        aria-invalid={!!errs.startDate}
                      />
                      <FieldError msg={errs.startDate} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        End Date <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="month"
                        className={ic('endDate')}
                        value={edu.endDate}
                        onChange={e => updateEdu(index, 'endDate', e.target.value)}
                        aria-invalid={!!errs.endDate}
                      />
                      <FieldError msg={errs.endDate} />
                    </div>

                  </div>
                </div>
              )
            })}
            <button onClick={addEducation} className="flex items-center gap-2 text-primary hover:text-primary/80 transition-colors">
              <Plus className="w-4 h-4" /> Add Education
            </button>
          </div>
        )

      /* ── Step 2: Experience ── */
      case 2:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Experience</h2>
            {experience.map((exp, index) => {
              const errs = experienceErrors[index] || {}
              const ic = inputClsArr(errs)
              return (
                <div key={index} className="bg-background/30 p-5 rounded-xl border border-border relative">
                  <button
                    onClick={() => removeExperience(index)}
                    className="absolute top-4 right-4 text-muted-foreground hover:text-red-500 transition-colors"
                    aria-label="Remove experience entry"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Job Title <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('title')}
                        value={exp.title}
                        onChange={e => updateExp(index, 'title', e.target.value)}
                        placeholder="Software Engineer"
                        aria-invalid={!!errs.title}
                      />
                      <FieldError msg={errs.title} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">
                        Company <span className="text-red-500">*</span>
                      </label>
                      <input
                        type="text"
                        className={ic('company')}
                        value={exp.company}
                        onChange={e => updateExp(index, 'company', e.target.value)}
                        placeholder="Tech Corp"
                        aria-invalid={!!errs.company}
                      />
                      <FieldError msg={errs.company} />
                    </div>

                    <div>
                      <label className="block text-sm font-medium mb-1">Location</label>
                      <input
                        type="text"
                        className={ic('location')}
                        value={exp.location}
                        onChange={e => updateExp(index, 'location', e.target.value)}
                        placeholder="San Francisco, CA"
                      />
                    </div>

                    {/* Date row */}
                    <div className="flex items-start gap-4 md:col-span-2">
                      <div className="flex-1">
                        <label className="block text-sm font-medium mb-1">
                          Start Date <span className="text-red-500">*</span>
                        </label>
                        <input
                          type="month"
                          className={ic('startDate')}
                          value={exp.startDate}
                          onChange={e => updateExp(index, 'startDate', e.target.value)}
                          aria-invalid={!!errs.startDate}
                        />
                        <FieldError msg={errs.startDate} />
                      </div>
                      <div className="flex-1">
                        <label className="block text-sm font-medium mb-1">End Date</label>
                        <input
                          type="month"
                          disabled={exp.current}
                          className={cn(ic('endDate'), 'disabled:opacity-50 disabled:cursor-not-allowed')}
                          value={exp.current ? '' : exp.endDate}
                          onChange={e => updateExp(index, 'endDate', e.target.value)}
                          aria-invalid={!!errs.endDate}
                        />
                        <FieldError msg={errs.endDate} />
                      </div>
                    </div>

                    {/* Currently working here */}
                    <div className="md:col-span-2 flex items-center gap-2">
                      <input
                        type="checkbox"
                        id={`current-${index}`}
                        checked={exp.current}
                        onChange={e => {
                          updateExp(index, 'current', e.target.checked)
                          if (e.target.checked) updateExp(index, 'endDate', '')
                        }}
                        className="rounded border-border accent-primary"
                      />
                      <label htmlFor={`current-${index}`} className="text-sm">I currently work here</label>
                    </div>

                    <div className="md:col-span-2">
                      <label className="block text-sm font-medium mb-1">Description (Bullet points)</label>
                      <textarea
                        className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 min-h-[100px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                        value={exp.description}
                        onChange={e => updateExp(index, 'description', e.target.value)}
                        placeholder={`- Developed feature X resulting in Y% improvement\n- Led a team of...`}
                      />
                    </div>

                  </div>
                </div>
              )
            })}
            <button onClick={addExperience} className="flex items-center gap-2 text-primary hover:text-primary/80 transition-colors">
              <Plus className="w-4 h-4" /> Add Experience
            </button>
          </div>
        )

      /* ── Step 3: Projects ── */
      case 3:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Projects</h2>
            {projects.map((proj, index) => (
              <div key={index} className="bg-background/30 p-5 rounded-xl border border-border relative">
                <button
                  onClick={() => removeProject(index)}
                  className="absolute top-4 right-4 text-muted-foreground hover:text-red-500 transition-colors"
                  aria-label="Remove project"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">Project Name</label>
                    <input
                      type="text"
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.name}
                      onChange={e => { const n = [...projects]; n[index].name = e.target.value; setProjects(n) }}
                      placeholder="E-commerce App"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Technologies Used</label>
                    <input
                      type="text"
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.tech}
                      onChange={e => { const n = [...projects]; n[index].tech = e.target.value; setProjects(n) }}
                      placeholder="React, Node.js, MongoDB"
                    />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">Link (Optional)</label>
                    <input
                      type="url"
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.link}
                      onChange={e => { const n = [...projects]; n[index].link = e.target.value; setProjects(n) }}
                      placeholder="https://github.com/..."
                    />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">Description (Bullet points)</label>
                    <textarea
                      className="w-full bg-background/50 border border-border rounded-lg px-4 py-2 min-h-[100px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                      value={proj.description}
                      onChange={e => { const n = [...projects]; n[index].description = e.target.value; setProjects(n) }}
                      placeholder="- Built a full-stack application..."
                    />
                  </div>
                </div>
              </div>
            ))}
            <button onClick={addProject} className="flex items-center gap-2 text-primary hover:text-primary/80 transition-colors">
              <Plus className="w-4 h-4" /> Add Project
            </button>
          </div>
        )

      /* ── Step 4: Skills ── */
      case 4:
        return (
          <div className="space-y-4">
            <h2 className="text-2xl font-semibold mb-6">Skills</h2>
            <div>
              <label className="block text-sm font-medium mb-1" htmlFor="skills">Technical Skills &amp; Competencies</label>
              <textarea
                id="skills"
                className="w-full bg-background/50 border border-border rounded-xl px-4 py-2 min-h-[150px] focus:outline-none focus:ring-2 focus:ring-primary/30 transition-colors"
                value={skills}
                onChange={e => setSkills(e.target.value)}
                placeholder={'**Languages:** JavaScript, Python, Java\n**Frameworks:** React, Node.js, Express\n**Tools:** Git, Docker, AWS'}
              />
              <p className="text-xs text-muted-foreground mt-2">Format exactly as you want it to appear (Markdown supported).</p>
            </div>
          </div>
        )

      /* ── Step 5: Preview ── */
      case 5:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold mb-6">Preview &amp; Generate</h2>
            <div className="bg-background border border-border rounded-xl p-6 h-[500px] overflow-y-auto font-mono text-sm whitespace-pre-wrap">
              {generateMarkdown()}
            </div>
          </div>
        )

      default:
        return null
    }
  }

  // ── render ────────────────────────────────────────────────────────────────────
  return (
    <div className="min-h-screen pt-20 pb-12 bg-background flex flex-col">
      <div className="max-w-4xl mx-auto w-full px-4 sm:px-6 lg:px-8 flex-1 flex flex-col">

        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-white/60">
            Resume Builder
          </h1>
          <p className="text-muted-foreground mt-2">Build a professional resume from scratch.</p>
        </div>

        {/* Progress Stepper */}
        <div className="mb-8 flex items-center justify-between relative">
          <div className="absolute left-0 top-1/2 w-full h-0.5 bg-border -z-10 transform -translate-y-1/2" />
          {STEPS.map((step, index) => {
            const isActive    = index === currentStep
            const isCompleted = index < currentStep
            const StepIcon    = step.icon
            return (
              <div key={step.id} className="flex flex-col items-center">
                <div className={cn(
                  'w-10 h-10 rounded-full flex items-center justify-center border-2 transition-colors',
                  isActive    ? 'bg-primary border-primary text-primary-foreground' :
                  isCompleted ? 'bg-primary/20 border-primary text-primary' :
                                'bg-background border-border text-muted-foreground'
                )}>
                  {isCompleted ? <CheckCircle className="w-5 h-5" /> : <StepIcon className="w-5 h-5" />}
                </div>
                <span className={cn(
                  'text-xs mt-2 hidden sm:block',
                  isActive ? 'text-primary font-medium' : 'text-muted-foreground'
                )}>
                  {step.title}
                </span>
              </div>
            )
          })}
        </div>

        {/* Content Area */}
        <div className="flex-1 bg-card/50 backdrop-blur-xl border border-white/5 rounded-3xl p-6 sm:p-8 shadow-2xl relative overflow-hidden">
          <div className="absolute -top-40 -right-40 w-80 h-80 bg-primary/10 rounded-full blur-3xl opacity-50 pointer-events-none" />
          <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-blue-500/10 rounded-full blur-3xl opacity-50 pointer-events-none" />

          <AnimatePresence mode="wait">
            <motion.div
              key={currentStep}
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{ duration: 0.3 }}
              className="relative z-10"
            >
              {renderStep()}
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Navigation Actions */}
        <div className="mt-8 flex justify-between items-center">
          <button
            onClick={handlePrev}
            disabled={currentStep === 0}
            className="px-6 py-2.5 rounded-full bg-secondary text-secondary-foreground hover:bg-secondary/80 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center gap-2"
          >
            <ArrowLeft className="w-4 h-4" /> Back
          </button>

          {currentStep === STEPS.length - 1 ? (
            <button
              onClick={handleGenerate}
              disabled={isSubmitting}
              className="px-6 py-2.5 rounded-full bg-primary text-primary-foreground hover:bg-primary/90 hover:scale-105 active:scale-95 disabled:opacity-50 disabled:hover:scale-100 transition-all shadow-lg shadow-primary/25 flex items-center gap-2 font-medium"
            >
              {isSubmitting ? (
                <>
                  <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin" />
                  Generating...
                </>
              ) : (
                <>
                  <Save className="w-4 h-4" /> Generate &amp; Enhance
                </>
              )}
            </button>
          ) : (
            <button
              onClick={handleNext}
              className="px-6 py-2.5 rounded-full bg-white text-black hover:bg-gray-200 hover:scale-105 active:scale-95 transition-all shadow-lg flex items-center gap-2 font-medium"
            >
              Next <ArrowRight className="w-4 h-4" />
            </button>
          )}
        </div>

      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useParams, Link, useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import toast from 'react-hot-toast'
import ReactMarkdown from 'react-markdown'
import { resumeApi, enhanceApi } from '../services/api'
import Button from '../components/Button'
import Card from '../components/Card'
import CustomSection from '../components/CustomSection'
import { sectionsToMarkdown } from '../components/customSectionUtils'
import { SkeletonList } from '../components/ui/Skeleton'
import ResumeVersions from '../components/ResumeVersions'
import AtsProgressChart from '../components/AtsProgressChart'
import { Loader2 } from 'lucide-react'

export default function ResumeView() {
  const { resumeId } = useParams()
  const navigate = useNavigate()

  const [resume, setResume] = useState(null)
  const [loading, setLoading] = useState(false)
  const [downloading, setDownloading] = useState(false)
  const [activeTab, setActiveTab] = useState('preview') // 'preview' | 'versions' | 'ats'
  const [previewTab, setPreviewTab] = useState('enhanced') // 'enhanced' | 'original'
  const [scoreData, setScoreData] = useState(null)
  const [scoring, setScoring] = useState(false)
  const [scoringStep, setScoringStep] = useState(0)

  useEffect(() => {
    let interval
    if (scoring) {
      interval = setInterval(() => {
        setScoringStep((prev) => (prev + 1) % 4)
      }, 2500)
    } else {
      setScoringStep(0)
    }
    return () => clearInterval(interval)
  }, [scoring])
  // ── Custom sections – persisted per-resume in localStorage ───────────────
  const STORAGE_KEY = `resume_custom_sections_${resumeId}`
  const [customSections, setCustomSections] = useState(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY)
      return saved ? JSON.parse(saved) : []
    } catch {
      return []
    }
  })

  const handleSectionsChange = (sections) => {
    setCustomSections(sections)
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(sections))
    } catch {
      // storage quota exceeded – silently ignore
    }
  }

  useEffect(() => {
    fetchResume()
  }, [resumeId])

  const fetchResume = async () => {
    try {
      const response = await resumeApi.getById(resumeId)
      setResume(response.data)

      // Set default tab based on available content
      if (!response.data.enhancedText) {
        setPreviewTab('original')
      } else {
        setPreviewTab('enhanced')
      }
    } catch (error) {
      toast.error('Failed to load resume')
      navigate('/dashboard')
    } finally {
      setLoading(false)
    }
  }

  const handleCopy = async (text) => {
    try {
      await navigator.clipboard.writeText(text)
      toast.success('Copied to clipboard!')
    } catch (error) {
      console.error('Clipboard copy failed:', error)
      toast.error('Failed to copy to clipboard')
    }
  }

  const handleDownloadPdf = async () => {
    try {
      setDownloading(true)
      const blob = await resumeApi.downloadPdf(resumeId, previewTab)

      // Create download link
      const url = window.URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `${resume?.title || 'resume'}_${previewTab}.pdf`
      document.body.appendChild(a)
      a.click()

      // Cleanup
      window.URL.revokeObjectURL(url)
      document.body.removeChild(a)

      toast.success('PDF downloaded successfully!')
    } catch (error) {
      toast.error(error.message || 'Failed to download PDF')
    } finally {
      setDownloading(false)
    }
  }

  const handleAnalyzeResume = async () => {
    try {
      setScoring(true)

      const resumeText =
        previewTab === 'enhanced'
          ? resume?.enhancedText
          : resume?.originalText

      if (!resumeText || !resumeText.trim()) {
        toast.error('No resume text available to analyze.')
        return
      }

      const result = await enhanceApi.scoreResume(resumeText)

      if (!result.success) {
        throw new Error(result.message || 'Failed to analyze resume')
      }

      setScoreData(result.data)
      toast.success('Resume analyzed successfully!')

      // Log score to ATS history
      try {
        await resumeApi.logAtsHistory(resumeId, {
          jobRole: resume?.jobRole || 'Software Engineer',
          atsScore: result.data.overallScore,
          scoreBreakdown: {
            summary: result.data.sections?.summary?.score || 0,
            skills: result.data.sections?.skills?.score || 0,
            experience: result.data.sections?.experience?.score || 0,
            education: result.data.sections?.education?.score || 0,
            projects: result.data.sections?.projects?.score || 0
          },
          missingKeywords: [],
          improvementsCount: result.data.topSuggestions?.length || 0
        })
      } catch (historyErr) {
        console.error('Failed to log ATS score run:', historyErr)
      }
    } catch (error) {
      console.error('Resume analysis error:', error)

      if (error.message === 'Not authenticated') {
        toast.error('Session expired. Please log in again.')
      } else if (error.status === 429) {
        const retryMsg = error.retryAfter
          ? ` Try again in ${Math.ceil(error.retryAfter / 60)} minutes.`
          : ' Try again tomorrow.'
        toast.error(`Daily AI limit reached.${retryMsg}`)
      } else if (error.status === 401 || error.status === 403) {
        toast.error('Authentication error. Please log in again.')
      } else if (error.status >= 500) {
        toast.error('Analysis service temporarily unavailable. Please try again.')
      } else if (!navigator.onLine || error.message?.includes('Failed to fetch')) {
        toast.error('Network error. Check your connection and try again.')
      } else {
        toast.error(error.message || 'Failed to analyze resume. Please try again.')
      }
    } finally {
      setScoring(false)
    }
  }

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4 }}
            className="space-y-6"
          >
            {/* Header Skeleton */}
            <div className="flex items-start justify-between mb-8">
              <div className="space-y-2">
                <div className="h-8 bg-muted rounded-lg w-1/2 animate-pulse" />
                <div className="h-4 bg-muted rounded-lg w-1/3 animate-pulse" />
              </div>
              <div className="h-10 bg-muted rounded-lg w-32 animate-pulse" />
            </div>

            {/* Tabs Skeleton */}
            <div className="flex gap-4 border-b border-border">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="h-10 bg-muted rounded w-28 animate-pulse" />
              ))}
            </div>

            {/* Content Skeleton */}
            <SkeletonList count={5} />
          </motion.div>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="flex flex-col sm:flex-row justify-between items-start gap-4 mb-6">
          <div>
            <h1 className="text-2xl font-bold text-foreground">{resume?.title}</h1>
            <p className="text-muted-foreground">
              {resume?.jobRole && `Target: ${resume.jobRole}`}
            </p>
            <p className="text-sm text-muted-foreground mt-1">
              Last modified: {formatDate(resume?.lastModified || resume?.createdAt)}
            </p>
          </div>
          <div className="flex gap-2">
            <Link to={`/enhance/${resumeId}`}>
              <Button variant="primary">
                {resume?.enhancedText ? 'Re-enhance' : 'Enhance'}
              </Button>
            </Link>
            <Link to="/dashboard">
              <Button variant="outline">Back to Dashboard</Button>
            </Link>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="border-b border-border mb-6">
          <nav className="flex gap-8">
            <button
              onClick={() => setActiveTab('preview')}
              className={`pb-4 text-sm font-semibold border-b-2 transition-all cursor-pointer ${activeTab === 'preview'
                  ? 'border-primary text-primary'
                  : 'border-transparent text-muted-foreground hover:text-foreground'
                }`}
            >
              Resume Preview
            </button>
            <button
              onClick={() => setActiveTab('versions')}
              className={`pb-4 text-sm font-semibold border-b-2 transition-all cursor-pointer ${activeTab === 'versions'
                  ? 'border-primary text-primary'
                  : 'border-transparent text-muted-foreground hover:text-foreground'
                }`}
            >
              Versions & Snapshots
            </button>
            <button
              onClick={() => setActiveTab('ats')}
              className={`pb-4 text-sm font-semibold border-b-2 transition-all cursor-pointer ${activeTab === 'ats'
                  ? 'border-primary text-primary'
                  : 'border-transparent text-muted-foreground hover:text-foreground'
                }`}
            >
              ATS Progression
            </button>
          </nav>
        </div>

        {/* Content Tabs */}
        {activeTab === 'preview' && (
          <div className="space-y-6">
            <Card>
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6 pb-4 border-b border-border/60">
                <div className="flex items-center gap-3">
                  <h2 className="text-lg font-bold text-foreground">
                    {previewTab === 'enhanced' ? 'AI-Enhanced Resume' : 'Original Resume'}
                  </h2>
                  {resume?.enhancedText && (
                    <div className="flex bg-muted rounded-xl p-0.5 border border-border">
                      <button
                        onClick={() => setPreviewTab('enhanced')}
                        className={`px-3 py-1 text-xs font-semibold rounded-lg transition-all ${
                          previewTab === 'enhanced' ? 'bg-primary text-primary-foreground shadow' : 'text-muted-foreground hover:text-foreground'
                        }`}
                      >
                        AI Enhanced
                      </button>
                      <button
                        onClick={() => setPreviewTab('original')}
                        className={`px-3 py-1 text-xs font-semibold rounded-lg transition-all ${
                          previewTab === 'original' ? 'bg-primary text-primary-foreground shadow' : 'text-muted-foreground hover:text-foreground'
                        }`}
                      >
                        Original
                      </button>
                    </div>
                  )}
                </div>
                <div className="flex gap-2 flex-wrap">
                 <Button
  variant="primary"
  onClick={handleDownloadPdf}
  disabled={downloading}
>
  {downloading ? (
    <div className="flex items-center gap-2">
      <Loader2 className="w-4 h-4 animate-spin" />
      Generating PDF...
    </div>
  ) : (
    'Download PDF'
  )}
</Button>
                  <Button
                    variant="primary"
                    onClick={handleAnalyzeResume}
                    disabled={scoring}
                  >
                    {scoring ? 'Analyzing...' : 'Analyze Resume'}
                  </Button>
                  <Button
                    variant="secondary"
                    onClick={() =>
                      handleCopy(
                        previewTab === 'enhanced'
                          ? resume?.enhancedText
                          : resume?.originalText,
                      )
                    }
                  >
                    Copy to Clipboard
                  </Button>
                  {customSections.length > 0 && (
                    <Button
                      variant="outline"
                      onClick={() => {
                        const base =
                          previewTab === 'enhanced'
                            ? resume?.enhancedText
                            : resume?.originalText
                        handleCopy((base || '') + '\n\n' + sectionsToMarkdown(customSections))
                      }}
                    >
                      Copy with Custom Sections
                    </Button>
                  )}
                </div>
              </div>

              <div className="bg-card border border-border/40 rounded-lg p-6 min-h-96 overflow-auto shadow-lg" style={{ maxWidth: '210mm', margin: '0 auto' }}>
                {previewTab === 'enhanced' && resume?.enhancedText ? (
                  <div className="resume-preview max-w-none text-foreground text-sm leading-tight">
                    <ReactMarkdown
                      components={{
                        h1: ({ node, ...props }) => (
                          <div className="text-foreground text-center py-2 px-4 mb-1 text-2xl font-bold border-b-2 border-black">
                            {props.children}
                          </div>
                        ),
                        h2: ({ node, ...props }) => (
                          <h2 className="text-xs font-bold text-foreground border-b border-black pb-0.5 mt-3 mb-1 uppercase tracking-wide">
                            {props.children}
                          </h2>
                        ),
                        h3: ({ node, ...props }) => (
                          <h3 className="text-xs font-bold text-foreground mt-1.5 mb-0.5">
                            {props.children}
                          </h3>
                        ),
                        p: ({ node, ...props }) => (
                          <p className="text-xs text-foreground mb-0.5 leading-snug">
                            {props.children}
                          </p>
                        ),
                        ul: ({ node, ...props }) => (
                          <ul className="list-none pl-0 space-y-0 mb-1">
                            {props.children}
                          </ul>
                        ),
                        li: ({ node, ...props }) => (
                          <li className="text-xs text-foreground flex items-start gap-1 leading-snug">
                            <span className="text-muted-foreground">◦</span>
                            <span>{props.children}</span>
                          </li>
                        ),
                        strong: ({ node, ...props }) => (
                          <strong className="font-bold text-foreground">
                            {props.children}
                          </strong>
                        ),
                        em: ({ node, ...props }) => (
                          <em className="text-muted-foreground text-xs font-normal">
                            {props.children}
                          </em>
                        ),
                        hr: () => null,
                        a: ({ node, ...props }) => (
                          <a className="text-blue-600 hover:underline text-xs" href={props.href} target="_blank" rel="noopener noreferrer">
                            {props.children}
                          </a>
                        ),
                      }}
                    >
                      {resume.enhancedText}
                    </ReactMarkdown>
                  </div>
                ) : (
                  <pre className="whitespace-pre-wrap text-xs text-foreground/80 font-mono">
                    {resume?.originalText}
                  </pre>
                )}
              </div>
            </Card>

            {/* Animated Scanner Loader during AI Scoring */}
            {scoring && (
              <Card className="mt-6 border-primary/20 bg-primary/5 relative overflow-hidden animate-pulse">
                <div className="flex flex-col items-center py-10 px-4">
                  {/* Animated Glowing ATS Radar Scanner */}
                  <div className="relative w-24 h-24 mb-6">
                    <motion.div
                      animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.8, 0.3] }}
                      transition={{ duration: 2, repeat: Infinity }}
                      className="absolute inset-0 rounded-full bg-primary/20"
                    />
                    <div className="absolute inset-2 rounded-full border-4 border-dashed border-primary/40 animate-spin" />
                    <div className="absolute inset-4 rounded-full border border-primary/60 flex items-center justify-center">
                      <svg className="w-8 h-8 text-primary animate-pulse" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                      </svg>
                    </div>
                  </div>

                  <h3 className="text-xl font-bold text-foreground mb-2">Analyzing Your Resume</h3>
                  
                  {/* Animated active scoring message */}
                  <motion.p
                    key={scoringStep}
                    initial={{ opacity: 0, y: 5 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -5 }}
                    className="text-sm font-semibold text-primary tracking-wide text-center"
                  >
                    {scoringStep === 0 && "🤖 Initializing AI ATS parser..."}
                    {scoringStep === 1 && "🔍 Analyzing keyword relevance & density..."}
                    {scoringStep === 2 && "⚡ Measuring impact statements & formatting..."}
                    {scoringStep === 3 && "📈 Compiling score and suggestions..."}
                  </motion.p>
                  
                  <p className="text-xs text-muted-foreground mt-4 text-center max-w-sm">
                    This might take a few seconds as the AI evaluates your resume against industry benchmarks and formats custom suggestions.
                  </p>
                </div>
              </Card>
            )}

            {scoreData && (
              <Card className="mt-6">
                <h3 className="text-2xl font-bold mb-6">
                  Resume Analysis
                </h3>

                <div className="flex flex-col items-center mb-8">
                  <div className="w-32 h-32 rounded-full border-8 border-primary flex items-center justify-center text-3xl font-bold">
                    {scoreData.overallScore}
                  </div>

                  <p className="mt-3 text-muted-foreground">
                    Overall Resume Score
                  </p>
                </div>

                <div className="space-y-4">
                  {Object.entries(scoreData.sections).map(([section, value]) => (
                    <div key={section}>
                      <div className="flex justify-between mb-1">
                        <span className="capitalize font-medium">
                          {section}
                        </span>
                        <span>{value.score}/100</span>
                      </div>

                      <div className="w-full bg-muted rounded-full h-3">
                        <div
                          className="bg-primary h-3 rounded-full"
                          style={{ width: `${value.score}%` }}
                        />
                      </div>

                      <p className="text-sm text-muted-foreground mt-1">
                        {value.feedback}
                      </p>
                    </div>
                  ))}
                </div>

                <div className="mt-8">
                  <h4 className="font-semibold mb-3">
                    Top Suggestions
                  </h4>

                  <ul className="space-y-2">
                    {scoreData.topSuggestions.map((tip, index) => (
                      <li
                        key={index}
                        className="bg-muted p-3 rounded-lg"
                      >
                        • {tip}
                      </li>
                    ))}
                  </ul>
                </div>
              </Card>
            )}

            {/* Metadata */}
            {resume?.preferences && Object.keys(resume.preferences).length > 0 && (
              <Card className="mt-6">
                <h3 className="text-lg font-medium text-foreground mb-4">Enhancement Settings Used</h3>
                <div className="grid sm:grid-cols-2 gap-4 text-sm">
                  {resume.jobRole && (
                    <div>
                      <span className="text-muted-foreground">Target Role:</span>
                      <span className="ml-2 text-foreground">{resume.jobRole}</span>
                    </div>
                  )}
                  {resume.preferences.yearsOfExperience && (
                    <div>
                      <span className="text-muted-foreground">Experience:</span>
                      <span className="ml-2 text-foreground">
                        {resume.preferences.yearsOfExperience} years
                      </span>
                    </div>
                  )}
                  {resume.preferences.skills?.length > 0 && (
                    <div className="sm:col-span-2">
                      <span className="text-muted-foreground">Skills:</span>
                      <span className="ml-2 text-foreground">
                        {resume.preferences.skills.join(', ')}
                      </span>
                    </div>
                  )}
                  {resume.preferences.industry && (
                    <div>
                      <span className="text-muted-foreground">Industry:</span>
                      <span className="ml-2 text-foreground">{resume.preferences.industry}</span>
                    </div>
                  )}
                  {resume.preferences.profileInfo && (
                    <div className="sm:col-span-2 pt-2 border-t border-border">
                      <span className="text-muted-foreground block mb-2">Profile Links:</span>
                      <div className="flex flex-wrap gap-3">
                        {resume.preferences.profileInfo.linkedinUrl && (
                          <a href={resume.preferences.profileInfo.linkedinUrl} target="_blank" rel="noopener noreferrer" className="text-primary hover:text-primary/80 text-xs">
                            LinkedIn ↗
                          </a>
                        )}
                        {resume.preferences.profileInfo.githubUrl && (
                          <a href={resume.preferences.profileInfo.githubUrl} target="_blank" rel="noopener noreferrer" className="text-primary hover:text-primary/80 text-xs">
                            GitHub ↗
                          </a>
                        )}
                        {resume.preferences.profileInfo.portfolioUrl && (
                          <a href={resume.preferences.profileInfo.portfolioUrl} target="_blank" rel="noopener noreferrer" className="text-primary hover:text-primary/80 text-xs">
                            Portfolio ↗
                          </a>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </Card>
            )}

            {/* Custom Sections */}
            <Card className="mt-6">
              <CustomSection
                sections={customSections}
                onSectionsChange={handleSectionsChange}
              />
            </Card>
          </div>
        )}

        {activeTab === 'versions' && (
          <Card>
            <ResumeVersions
              resumeId={resumeId}
              currentOriginalText={resume?.originalText}
              currentEnhancedText={resume?.enhancedText}
              currentJobRole={resume?.jobRole}
              currentAtsScore={resume?.atsScore}
              onRestore={(updatedResume) => {
                setResume(updatedResume)
                if (!updatedResume.enhancedText) {
                  setPreviewTab('original')
                } else {
                  setPreviewTab('enhanced')
                }
                setActiveTab('preview')
              }}
            />
          </Card>
        )}

        {activeTab === 'ats' && (
          <Card>
            <AtsProgressChart resumeId={resumeId} />
          </Card>
        )}
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useParams, Link } from 'react-router-dom'
import toast from 'react-hot-toast'
import { motion } from 'framer-motion'
import {
  MapPin, Globe, Github, Linkedin, Pencil, Save, X,
  FileText, Mic, Heart, MessageSquare, Calendar,
  Plus, ExternalLink
} from 'lucide-react'
import { useAuth } from '../hooks/useAuth'
import { userProfileApi } from '../services/api'
import Button from '../components/Button'
import Input from '../components/Input'
import AnalysisSkeleton from '../components/github/AnalysisSkeleton'
import { SkeletonList } from '../components/ui/Skeleton'
import { getGithubUsername } from '../utils/github'

const AVATAR_GRADIENTS = [
  'from-indigo-500 to-purple-600',
  'from-sky-500 to-indigo-600',
  'from-emerald-500 to-teal-600',
  'from-amber-500 to-orange-600',
  'from-rose-500 to-pink-600',
]

const itemVariants = {
  hidden: { opacity: 0, y: 16 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.4 } },
}

const containerVariants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.08 } },
}

export default function UserProfile() {
  const { uid: paramUid } = useParams()
  const { user } = useAuth()

  const targetUid = paramUid || user?.uid
  const isOwnProfile = !paramUid || paramUid === user?.uid

  const [profile, setProfile] = useState(null)
  const [stats, setStats] = useState({ resumesCreated: 0, interviewsDone: 0 })
  const [activity, setActivity] = useState([])
  const [loading, setLoading] = useState(true)
  const [editing, setEditing] = useState(false)
  const [saving, setSaving] = useState(false)
  // When true the GitHub repository analysis skeleton will show
  const [isRepoAnalyzing, setIsRepoAnalyzing] = useState(false)
  const [form, setForm] = useState({
    displayName: '',
    bio: '',
    jobRole: '',
    skills: '',
    location: '',
    website: '',
    github: '',
    linkedin: '',
  })

  useEffect(() => {
    if (targetUid) fetchAll()
  }, [targetUid])

  const fetchAll = async () => {
    setLoading(true)
    try {
      const [profileResult, statsResult, activityResult] = await Promise.allSettled([
        isOwnProfile ? userProfileApi.getMyProfile() : userProfileApi.getProfile(targetUid),
        isOwnProfile ? userProfileApi.getMyStats() : userProfileApi.getStats(targetUid),
        isOwnProfile ? userProfileApi.getMyActivity() : userProfileApi.getActivity(targetUid),
      ])

      if (profileResult.status === 'rejected') {
        throw profileResult.reason
      }

      const profileRes = profileResult.value
      const statsRes = statsResult.status === 'fulfilled' ? statsResult.value : { stats: { resumesCreated: 0, interviewsDone: 0 } }
      const activityRes = activityResult.status === 'fulfilled' ? activityResult.value : { activity: [] }

      setProfile(profileRes.profile)
      setStats(statsRes.stats)
      setActivity(activityRes.activity)

      if (statsResult.status === 'rejected') {
        console.warn('Profile stats fetch failed:', statsResult.reason)
      }

      if (activityResult.status === 'rejected') {
        console.warn('Profile activity fetch failed:', activityResult.reason)
      }
    } catch (err) {
      toast.error('Failed to load profile')
      console.error('Profile fetch failed:', err)
    } finally {
      setLoading(false)
    }
  }

  const startEdit = () => {
    setForm({
      displayName: profile?.displayName || '',
      bio: profile?.bio || '',
      jobRole: profile?.jobRole || '',
      skills: (profile?.skills || []).join(', '),
      location: profile?.location || '',
      website: profile?.website || '',
      github: profile?.github || '',
      linkedin: profile?.linkedin || '',
    })
    setEditing(true)
  }

  const cancelEdit = () => setEditing(false)
  const isValidWebsite = (url) => {
  if (!url) return true;

  try {
    new URL(url.startsWith("http") ? url : `https://${url}`);
    return true;
  } catch {
    return false;
  }
};

const isValidLinkedIn = (url) => {
  if (!url) return true;

  return /^https?:\/\/(www\.)?linkedin\.com\/in\/.+$/i.test(url);
};

const isValidGithub = (username) => {
  if (!username) return true;

  return /^[a-zA-Z0-9-]+$/.test(username);
};

  const saveEdit = async () => {
    const githubUsername = getGithubUsername(form.github)

    if (!isValidWebsite(form.website.trim())) {
      toast.error("Please enter a valid website URL")
      return
    }

    if (!isValidLinkedIn(form.linkedin.trim())) {
      toast.error("Please enter a valid LinkedIn profile URL")
      return
    }

    if (!isValidGithub(githubUsername)) {
      toast.error("Invalid GitHub username")
      return
    }

    setSaving(true)

    try {
      const res = await userProfileApi.updateMyProfile({
        displayName: form.displayName.trim(),
        bio: form.bio.trim(),
        jobRole: form.jobRole.trim(),
        skills: form.skills.split(',').map(s => s.trim()).filter(Boolean),
        location: form.location.trim(),
        website: form.website.trim(),
        github: githubUsername,
        linkedin: form.linkedin.trim(),
      })
      setProfile(res.profile)
      setEditing(false)
      toast.success('Profile updated')
    } catch (err) {
      toast.error(err.message || 'Failed to save profile')
    } finally {
      setSaving(false)
    }
  }

  const displayName =
    profile?.displayName ||
    user?.displayName ||
    user?.email?.split('@')[0] ||
    'User'
  const initials = displayName.charAt(0).toUpperCase()
  const avatarGradient =
    AVATAR_GRADIENTS[(displayName.charCodeAt(0) || 0) % AVATAR_GRADIENTS.length]

  const formatDate = (date) => {
    if (!date) return ''
    return new Date(date).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    })
  }

  const externalHref = (url) =>
    url.startsWith('http') ? url : `https://${url}`

  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <div className="relative max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4 }}
            className="space-y-6"
          >
            {/* Profile Header Skeleton */}
            <div className="rounded-2xl bg-card border border-border p-6 space-y-4">
              <div className="flex items-start gap-5">
                <div className="w-20 h-20 rounded-2xl bg-muted animate-pulse shrink-0" />
                <div className="flex-1 space-y-3">
                  <div className="h-6 bg-muted rounded-lg w-1/2 animate-pulse" />
                  <div className="h-4 bg-muted rounded-lg w-1/3 animate-pulse" />
                  <div className="h-4 bg-muted rounded-lg w-1/4 animate-pulse" />
                </div>
              </div>
            </div>

            {/* Stats Skeleton */}
            <div className="grid grid-cols-3 gap-4">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="rounded-lg bg-card border border-border p-4 space-y-2">
                  <div className="h-3 bg-muted rounded w-2/3 animate-pulse" />
                  <div className="h-8 bg-muted rounded w-1/2 animate-pulse" />
                </div>
              ))}
            </div>

            {/* Activity Skeleton */}
            <SkeletonList count={3} />
          </motion.div>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-sky-500/5 rounded-full blur-3xl" />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-cyan-500/5 rounded-full blur-3xl" />
      </div>

      <div className="relative max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <motion.div
          variants={containerVariants}
          initial="hidden"
          animate="visible"
          className="space-y-6"
        >
          {/* Profile Header */}
          <motion.div
            variants={itemVariants}
            className="relative overflow-hidden rounded-2xl bg-card/80 backdrop-blur-sm border border-border shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300 p-6">
            <div className="flex flex-col sm:flex-row items-start gap-5">
             <div className="w-20 h-20 rounded-3xl bg-gradient-to-br from-sky-100 to-cyan-100 border border-sky-200 flex items-center justify-center shadow-sm flex-shrink-0">
  <span className="text-3xl font-bold bg-gradient-to-br from-sky-500 to-cyan-500 bg-clip-text text-transparent">
    {initials}
  </span>
</div>

              <div className="flex-1 min-w-0">
                {editing ? (
                  <div className="mb-0">
                    <Input
                      label="Display Name"
                      name="displayName"
                      value={form.displayName}
                      onChange={(e) =>
                        setForm((f) => ({ ...f, displayName: e.target.value }))
                      }
                      placeholder="Your name"
                    />
                  </div>
                ) : (
                  <>
                    <h1 className="text-2xl font-bold text-foreground">{displayName}</h1>
                    {profile?.jobRole && (
                      <p className="text-sky-400 font-medium mt-0.5">{profile.jobRole}</p>
                    )}
                    {profile?.location && (
                      <p className="flex items-center gap-1.5 text-sm text-muted-foreground mt-1">
                        <MapPin className="w-3.5 h-3.5 flex-shrink-0" />
                        {profile.location}
                      </p>
                    )}
                  </>
                )}
              </div>

              {isOwnProfile && (
                <div className="flex items-center gap-2 self-start">
                  {editing ? (
                    <>
                      <Button
                        variant="ghost"
                        onClick={cancelEdit}
                        disabled={saving}
                        className="!py-2 !px-3"
                      >
                        <X className="w-4 h-4" />
                      </Button>
                      <Button
                        variant="primary"
                        onClick={saveEdit}
                        loading={saving}
                        className="!py-2 !px-4 text-sm"
                      >
                        <Save className="w-4 h-4 mr-1.5" />
                        Save
                      </Button>
                    </>
                  ) : (
                    <Button
                      variant="outline"
                      onClick={startEdit}
                      className="!py-2 !px-4 text-sm"
                    >
                      <Pencil className="w-4 h-4 mr-1.5" />
                      Edit Profile
                    </Button>
                  )}
                </div>
              )}
            </div>

            {/* Bio */}
            <div className="mt-5">
              {editing ? (
                <div>
                 <label className="block text-sm font-medium text-foreground mb-1.5">
                    Bio
                  </label>
                  <textarea
                    value={form.bio}
                    onChange={(e) =>
                      setForm((f) => ({ ...f, bio: e.target.value }))
                    }
                    maxLength={500}
                    rows={3}
                    placeholder="Tell others about yourself..."
                  className="w-full px-4 py-2.5 rounded-lg bg-background border border-border text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-sky-500/50 focus:border-sky-500 resize-none transition-all duration-200"
                  />
                  <p className="text-xs text-sky-200/60 mt-1 text-right">
                    {form.bio.length}/500
                  </p>
                </div>
              ) : profile?.bio ? (
                <p className="text-foreground text-sm leading-relaxed">{profile.bio}</p>
              ) : isOwnProfile ? (
                <p className="text-muted-foreground text-sm italic">
                  No bio yet — click Edit Profile to add one.
                </p>
              ) : null}
            </div>

            {/* Edit extra fields */}
            {editing && (
              <div className="mt-4 grid sm:grid-cols-2 gap-x-4">
                <Input
                  label="Job Role"
                  name="jobRole"
                  value={form.jobRole}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, jobRole: e.target.value }))
                  }
                  placeholder="e.g. Software Engineer"
                />
                <Input
                  label="Location"
                  name="location"
                  value={form.location}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, location: e.target.value }))
                  }
                  placeholder="e.g. San Francisco, CA"
                />
                <Input
                  label="Skills (comma-separated)"
                  name="skills"
                  value={form.skills}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, skills: e.target.value }))
                  }
                  placeholder="e.g. React, Node.js, Python"
                />
                <Input
                  label="Website"
                  name="website"
                  value={form.website}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, website: e.target.value }))
                  }
                  placeholder="https://yoursite.com"
                />
                <Input
                  label="GitHub Username"
                  name="github"
                  value={form.github}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, github: e.target.value }))
                  }
                  placeholder="username"
                />
                <Input
                  label="LinkedIn URL"
                  name="linkedin"
                  value={form.linkedin}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, linkedin: e.target.value }))
                  }
                  placeholder="https://linkedin.com/in/..."
                />
              </div>
            )}

            {/* External links (view mode) */}
            {!editing &&
              (profile?.website || profile?.github || profile?.linkedin) && (
                <div className="flex flex-wrap gap-4 mt-5 pt-5 border-t border-border">
                  {profile.website && (
                    <a
                      href={externalHref(profile.website)}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-sky-400 transition-colors"
                    >
                      <Globe className="w-4 h-4" />
                      Website
                      <ExternalLink className="w-3 h-3" />
                    </a>
                  )}
                  {profile.github && (
                    <a
                      href={`https://github.com/${profile.github}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center gap-1.5 text-sm text-zinc-400 hover:text-sky-400 transition-colors"
                    >
                      <Github className="w-4 h-4" />
                      {profile.github}
                      <ExternalLink className="w-3 h-3" />
                    </a>
                  )}
                  {profile.linkedin && (
                    <a
                      href={externalHref(profile.linkedin)}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center gap-1.5 text-sm text-zinc-400 hover:text-sky-400 transition-colors"
                    >
                      <Linkedin className="w-4 h-4" />
                      LinkedIn
                      <ExternalLink className="w-3 h-3" />
                    </a>
                  )}
                </div>
              )}

          {/* Repository analysis (loading) - render skeleton when analysis is in progress */}
          {isRepoAnalyzing && (
            <motion.div variants={itemVariants} className="mt-6">
              <div className="absolute inset-0 bg-gradient-to-br from-primary/5 via-transparent to-transparent pointer-events-none" />
              <AnalysisSkeleton />
            </motion.div>
          )}
          </motion.div>

          {/* Skills */}
          {!editing && profile?.skills?.length > 0 && (
            <motion.div
              variants={itemVariants}
              className="rounded-2xl bg-card/80 backdrop-blur-sm border border-border shadow-[0_8px_30px_rgb(0,0,0,0.06)] p-6"
            >
              <h2 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-4">
                Skills
              </h2>
              <div className="flex flex-wrap gap-2">
                {profile.skills.map((skill, i) => (
                  <span
                    key={i}
                    className="px-3 py-1.5 bg-sky-500/10 border border-sky-500/20 text-sky-400 rounded-full text-sm font-medium"
                  >
                    {skill}
                  </span>
                ))}
              </div>
            </motion.div>
          )}

          {!editing && (
             <> 

          {/* Stats */}
          <motion.div variants={itemVariants} className="grid grid-cols-2 gap-4">
            <div className="relative overflow-hidden rounded-2xl bg-card/80 backdrop-blur-sm border border-sky-500/10 shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300 p-5 text-center">
            <div className="absolute inset-0 bg-gradient-to-br from-sky-300/5 via-cyan-200/5 to-transparent opacity-0 hover:opacity-100 transition-opacity duration-300 pointer-events-none" />              <div className="w-10 h-10 bg-sky-500/10 rounded-xl flex items-center justify-center mx-auto mb-2">
                <FileText className="w-5 h-5 text-sky-400" />
              </div>
              <p className="text-2xl font-bold text-foreground">{stats.resumesCreated}</p>
              <p className="text-xs text-muted-foreground mt-0.5">Resumes Created</p>
            </div>
            <div className="relative overflow-hidden rounded-2xl bg-card/80 backdrop-blur-sm border border-sky-500/10 shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300 p-5 text-center">
              <div className="absolute inset-0 bg-gradient-to-br from-sky-300/5 via-cyan-200/5 to-transparent opacity-0 hover:opacity-100 transition-opacity duration-300 pointer-events-none" />
              <div className="w-10 h-10 bg-sky-500/10 rounded-xl flex items-center justify-center mx-auto mb-2">
                <Mic className="w-5 h-5 text-sky-400" />
              </div>
              <p className="text-2xl font-bold text-foreground">{stats.interviewsDone}</p>
              <p className="text-xs text-muted-foreground mt-0.5">Interviews Done</p>
            </div>
          </motion.div>

          {/* Activity Feed */}
          <motion.div variants={itemVariants}>
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-semibold text-foreground flex items-center gap-2">
                <Calendar className="w-5 h-5 text-muted-foreground" />
                Activity
              </h2>
              {isOwnProfile && (
                <Link
                  to="/community"
                  className="text-sky-400 hover:text-sky-300 text-sm font-medium flex items-center gap-1 transition-colors"
                >
                  Go to Community
                </Link>
              )}
            </div>

            {activity.length === 0 ? (
              <div className="relative overflow-hidden rounded-2xl bg-card/80 backdrop-blur-sm border border-border shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300 text-center py-12">
                <MessageSquare className="w-12 h-12 text-sky-500/40 mx-auto mb-3" />
                <h3 className="font-medium text-foreground mb-1">No posts yet</h3>
                {isOwnProfile && (
                  <>
                    <p className="text-muted-foreground text-sm mb-4">
                      Share posts in the community to see them here
                    </p>
                    <Link to="/community">
                      <Button variant="primary" className="text-sm">
                        <Plus className="w-4 h-4 mr-1.5" />
                        Create a Post
                      </Button>
                    </Link>
                  </>
                )}
              </div>
            ) : (
              <div className="relative overflow-hidden rounded-2xl bg-card/80 backdrop-blur-sm border border-border shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-xl hover:border-primary/20 transition-all duration-300">
                <div className="divide-y divide-border">
                  {activity.map((item) => (
                    <div
                      key={item.id}
                      className="p-4 hover:bg-muted/50 transition-colors"
                    >
                      {item.title && (
                        <h4 className="font-medium text-foreground text-sm">{item.title}</h4>
                      )}
                      {item.content && (
                        <p className="text-muted-foreground text-sm mt-0.5 line-clamp-2">
                          {item.content}
                        </p>
                      )}
                      <div className="flex items-center gap-3 mt-2">
                        {item.category && (
                          <span className="px-2 py-0.5 bg-sky-500/10 border border-sky-500/20 text-sky-300 rounded text-xs">
                            {item.category}
                          </span>
                        )}
                        <span className="flex items-center gap-1 text-muted-foreground">
                          <Heart className="w-3 h-3" />
                          {item.likeCount}
                        </span>
                        <span className="flex items-center gap-1 text-muted-foreground">
                          <MessageSquare className="w-3 h-3" />
                          {item.commentCount}
                        </span>
                        {item.createdAt && (
                          <span className="text-muted-foreground">
                            {formatDate(item.createdAt)}
                          </span>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </motion.div>
          </>
          )}
        </motion.div>
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useParams, useNavigate, useOutletContext } from 'react-router-dom'
import { fellowshipApi, paymentApi } from '../../services/api'
import toast from 'react-hot-toast'
import { motion } from 'framer-motion'
import {
    ArrowLeft,
    User,
    Clock,
    IndianRupee,
    ExternalLink,
    CheckCircle,
    XCircle,
    Loader2,
    FileText,
    Mail,
    MessageCircle,
    CreditCard
} from 'lucide-react'
import { SkeletonPanel } from '../../components/ui/Skeleton'

const STATUS_CONFIG = {
    pending: { label: 'Pending', color: 'bg-yellow-950 text-yellow-400', icon: Clock },
    accepted: { label: 'Accepted', color: 'bg-emerald-950 text-emerald-400', icon: CheckCircle },
    rejected: { label: 'Rejected', color: 'bg-red-950 text-red-400', icon: XCircle },
}

export default function ChallengeProposals() {
    const { id } = useParams()
    const navigate = useNavigate()
    const { profile } = useOutletContext()
    const [challenge, setChallenge] = useState(null)
    const [proposals, setProposals] = useState([])
    const [chatRooms, setChatRooms] = useState({})
    const [loading, setLoading] = useState(true)
    const [updating, setUpdating] = useState(null)
    const [feedback, setFeedback] = useState('')
    const [showFeedbackFor, setShowFeedbackFor] = useState(null)

    const formatDate = (value) => {
        const date = new Date(value)
        return Number.isNaN(date.getTime()) ? 'Unknown' : date.toLocaleDateString()
    }

    useEffect(() => {
        if (profile?.role === 'student') {
            navigate('/fellowship/challenges')
            return
        }
        if (profile?.role === 'corporate') {
            loadData()
        }
    }, [profile, id])

    const loadData = async () => {
        try {
            const [challengeRes, proposalsRes, roomsRes] = await Promise.all([
                fellowshipApi.getChallenge(id),
                fellowshipApi.getChallengeProposals(id),
                fellowshipApi.getChatRooms()
            ])
            setChallenge(challengeRes.data)
            setProposals(proposalsRes.data)

            const roomMap = {}
            roomsRes.data.forEach(room => {
                roomMap[room.proposalId] = room
            })
            setChatRooms(roomMap)
        } catch (error) {
            toast.error('Failed to load proposals')
            navigate('/fellowship/my-challenges')
        } finally {
            setLoading(false)
        }
    }

    const handleUpdateStatus = async (proposalId, status) => {
        setUpdating(proposalId)

        try {
            if (status === 'accepted') {
                // For acceptance, initiate payment flow
                const orderRes = await paymentApi.createOrder(proposalId)
                const orderData = orderRes.data

                if (typeof window === 'undefined' || !window.Razorpay) {
                    toast.error('Payment gateway unavailable. Please try again later.')
                    setUpdating(null)
                    return
                }

                // Configure Razorpay options with all payment methods
                const options = {
                    key: orderData.keyId,
                    amount: orderData.amount,
                    currency: orderData.currency,
                    name: 'careerpilot Fellowships',
                    description: `Payment for: ${orderData.challengeTitle}`,
                    order_id: orderData.orderId,
                    handler: async function (response) {
                        try {
                            // Verify payment and complete acceptance
                            const verifyRes = await paymentApi.verifyPayment({
                                razorpay_order_id: response.razorpay_order_id,
                                razorpay_payment_id: response.razorpay_payment_id,
                                razorpay_signature: response.razorpay_signature,
                                proposalId: proposalId,
                                feedback: feedback
                            })

                            toast.success('Payment successful! Proposal accepted.')
                            setShowFeedbackFor(null)
                            setFeedback('')

                            if (verifyRes.data.chatRoom) {
                                setChatRooms(prev => ({
                                    ...prev,
                                    [proposalId]: verifyRes.data.chatRoom
                                }))
                            }

                            loadData()
                        } catch (err) {
                            toast.error(err.message || 'Payment verification failed')
                        } finally {
                            setUpdating(null)
                        }
                    },
                    prefill: {
                        name: profile?.companyName || '',
                        email: '',
                        contact: ''
                    },
                    notes: {
                        proposalId: proposalId,
                        studentName: orderData.studentName
                    },
                    theme: {
                        color: '#10b981'
                    },
                    modal: {
                        ondismiss: function () {
                            setUpdating(null)
                            toast.error('Payment cancelled')
                        }
                    },
                    // Enable all payment methods
                    config: {
                        display: {
                            blocks: {
                                banks: {
                                    name: 'Pay via UPI/Cards/NetBanking',
                                    instruments: [
                                        { method: 'upi' },
                                        { method: 'card' },
                                        { method: 'netbanking' },
                                        { method: 'wallet' }
                                    ]
                                }
                            },
                            sequence: ['block.banks'],
                            preferences: {
                                show_default_blocks: true
                            }
                        }
                    }
                }

                // Open Razorpay checkout
                const rzp = new window.Razorpay(options)
                rzp.on('payment.failed', function (response) {
                    toast.error('Payment failed: ' + response.error.description)
                    setUpdating(null)
                })
                rzp.open()

            } else {
                // For rejection, use the old direct update flow
                await fellowshipApi.updateProposalStatus(proposalId, status, feedback)
                toast.success(`Proposal ${status}!`)
                setShowFeedbackFor(null)
                setFeedback('')
                loadData()
                setUpdating(null)
            }
        } catch (error) {
            toast.error(error.message || 'Failed to process')
            setUpdating(null)
        }
    }

    const handleMessageClick = (proposalId) => {
        const room = chatRooms[proposalId]
        if (room) {
            navigate(`/fellowship/messages/${room._id}`)
        }
    }

    if (loading) {
        return <SkeletonPanel rows={4} className="max-w-4xl mx-auto" />
    }

    return (
        <div className="max-w-4xl mx-auto space-y-6">
            <button
                onClick={() => navigate('/fellowship/my-challenges')}
                className="flex items-center gap-2 text-muted-foreground hover:text-foreground text-sm"
            >
                <ArrowLeft className="w-4 h-4" />
                Back to My Challenges
            </button>

            {challenge && (
                <div className="bg-background border border-border rounded-2xl p-6">
                    <h1 className="text-2xl font-bold text-foreground">{challenge.title}</h1>
                    <div className="mt-2 flex flex-wrap gap-4 text-sm text-muted-foreground">
                        <span className="flex items-center gap-1">
                            <IndianRupee className="w-4 h-4" />
                            ₹{challenge.price?.toLocaleString('en-IN')}
                        </span>
                        <span className="flex items-center gap-1">
                            <Clock className="w-4 h-4" />
                            Deadline: {formatDate(challenge.deadline)}
                        </span>
                        <span className="flex items-center gap-1">
                            <FileText className="w-4 h-4" />
                            {proposals.length} proposal{proposals.length !== 1 ? 's' : ''}
                        </span>
                    </div>
                </div>
            )}

            <div>
                <h2 className="text-xl font-semibold text-foreground mb-4">Proposals Received</h2>

                {proposals.length === 0 ? (
                    <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-border py-16">
                        <FileText className="h-12 w-12 text-muted-foreground/80" />
                        <h3 className="mt-4 text-lg font-semibold text-foreground">No proposals yet</h3>
                        <p className="mt-2 text-sm text-muted-foreground">Students will submit proposals once they see your challenge</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {proposals.map((proposal) => {
                            const status = STATUS_CONFIG[proposal.status] || STATUS_CONFIG.pending
                            const StatusIcon = status.icon
                            const hasRoom = chatRooms[proposal._id]

                            return (
                                <motion.div
                                    key={proposal._id}
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    className="bg-background border border-border rounded-2xl p-6"
                                >
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-12 h-12 rounded-full bg-muted flex items-center justify-center">
                                                <User className="w-6 h-6 text-muted-foreground" />
                                            </div>
                                            <div>
                                                <h3 className="font-semibold text-foreground">{proposal.studentName}</h3>
                                                <p className="text-sm text-muted-foreground flex items-center gap-1">
                                                    <Mail className="w-3 h-3" />
                                                    {proposal.studentEmail}
                                                </p>
                                            </div>
                                        </div>
                                        <span className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm ${status.color}`}>
                                            <StatusIcon className="w-4 h-4" />
                                            {status.label}
                                        </span>
                                    </div>

                                    <div className="mt-4 grid grid-cols-2 gap-4 text-sm">
                                        <div className="p-3 bg-muted rounded-lg">
                                            <p className="text-muted-foreground mb-1">Proposed Price</p>
                                            <p className="text-emerald-400 font-semibold">₹{proposal.proposedPrice?.toLocaleString('en-IN')}</p>
                                        </div>
                                        <div className="p-3 bg-muted rounded-lg">
                                            <p className="text-muted-foreground mb-1">Delivery Time</p>
                                            <p className="text-foreground font-semibold">{proposal.estimatedDays} days</p>
                                        </div>
                                    </div>

                                    <div className="mt-4">
                                        <p className="text-sm text-muted-foreground mb-2">Cover Letter</p>
                                        <p className="text-foreground text-sm whitespace-pre-wrap bg-muted rounded-lg p-4">
                                            {proposal.coverLetter}
                                        </p>
                                    </div>

                                    {proposal.portfolioLinks?.length > 0 && (
                                        <div className="mt-4">
                                            <p className="text-sm text-muted-foreground mb-2">Portfolio Links</p>
                                            <div className="flex flex-wrap gap-2">
                                                {proposal.portfolioLinks.map((link, i) => (
                                                    <a
                                                        key={i}
                                                        href={link}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="flex items-center gap-1 px-3 py-1.5 bg-muted text-blue-400 rounded-lg text-sm hover:bg-muted/80"
                                                    >
                                                        <ExternalLink className="w-3 h-3" />
                                                        Link {i + 1}
                                                    </a>
                                                ))}
                                            </div>
                                        </div>
                                    )}

                                    {proposal.status === 'pending' && (
                                        <div className="mt-6 pt-4 border-t border-border">
                                            {showFeedbackFor === proposal._id ? (
                                                <div className="space-y-3">
                                                    <textarea
                                                        value={feedback}
                                                        onChange={(e) => setFeedback(e.target.value)}
                                                        placeholder="Add feedback (optional)..."
                                                        rows={3}
                                                        className="w-full px-4 py-3 bg-muted border border-border rounded-xl text-foreground placeholder:text-muted-foreground focus:outline-none focus:border-emerald-500 resize-none"
                                                    />
                                                    <div className="flex gap-2">
                                                        <button
                                                            onClick={() => handleUpdateStatus(proposal._id, 'accepted')}
                                                            disabled={updating === proposal._id}
                                                            className="flex-1 py-2.5 bg-emerald-600 hover:bg-emerald-500 text-foreground rounded-lg font-medium disabled:opacity-50 flex items-center justify-center gap-2"
                                                        >
                                                            {updating === proposal._id ? <Loader2 className="w-4 h-4 animate-spin" /> : <CheckCircle className="w-4 h-4" />}
                                                            Accept
                                                        </button>
                                                        <button
                                                            onClick={() => handleUpdateStatus(proposal._id, 'rejected')}
                                                            disabled={updating === proposal._id}
                                                            className="flex-1 py-2.5 bg-red-600 hover:bg-red-500 text-foreground rounded-lg font-medium disabled:opacity-50 flex items-center justify-center gap-2"
                                                        >
                                                            <XCircle className="w-4 h-4" />
                                                            Reject
                                                        </button>
                                                    </div>
                                                    <button
                                                        onClick={() => { setShowFeedbackFor(null); setFeedback('') }}
                                                        className="w-full py-2 text-muted-foreground hover:text-foreground text-sm"
                                                    >
                                                        Cancel
                                                    </button>
                                                </div>
                                            ) : (
                                                <button
                                                    onClick={() => setShowFeedbackFor(proposal._id)}
                                                    className="w-full py-2.5 bg-muted hover:bg-muted/80 text-foreground rounded-lg font-medium"
                                                >
                                                    Review This Proposal
                                                </button>
                                            )}
                                        </div>
                                    )}

                                    {proposal.status === 'accepted' && (
                                        <div className="mt-6 pt-4 border-t border-border">
                                            <button
                                                onClick={() => handleMessageClick(proposal._id)}
                                                disabled={!hasRoom}
                                                className="w-full py-2.5 bg-emerald-600 hover:bg-emerald-500 text-foreground rounded-lg font-medium flex items-center justify-center gap-2"
                                            >
                                                <MessageCircle className="w-4 h-4" />
                                                Message Student
                                            </button>
                                        </div>
                                    )}

                                    <p className="mt-4 text-xs text-muted-foreground">
                                        Submitted on {formatDate(proposal.createdAt)}
                                    </p>
                                </motion.div>
                            )
                        })}
                    </div>
                )}
            </div>
        </div>
    )
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useOutletContext } from 'react-router-dom'
import { fellowshipApi } from '../../services/api'
import toast from 'react-hot-toast'
import { motion } from 'framer-motion'
import {
    Search,
    Briefcase,
    TrendingUp,
    Sparkles,
    Filter,
    Clock,
    IndianRupee
} from 'lucide-react'
import { SkeletonChallengeGrid } from '../../components/ui/Skeleton'

const CATEGORIES = [
    { id: 'all', label: 'All', icon: '🎯' },
    { id: 'design', label: 'Design', icon: '🎨' },
    { id: 'content', label: 'Content', icon: '✍️' },
    { id: 'development', label: 'Development', icon: '💻' },
    { id: 'research', label: 'Research', icon: '🔬' },
    { id: 'marketing', label: 'Marketing', icon: '📈' },
]

function ChallengeCard({ challenge, onClick }) {
    const deadlineDate = new Date(challenge.deadline)
    const isValidDeadline = !Number.isNaN(deadlineDate.getTime())
    const daysLeft = isValidDeadline
        ? Math.ceil((deadlineDate - new Date()) / (1000 * 60 * 60 * 24))
        : null
    const priceValue = Number(challenge.price)
    const formattedPrice = Number.isFinite(priceValue) ? priceValue.toLocaleString('en-IN') : '0'

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            whileHover={{ y: -4 }}
            onClick={onClick}
            className="bg-background border border-border rounded-2xl p-5 cursor-pointer hover:border-emerald-500/50 transition-all"
        >
            <div className="flex items-start justify-between gap-4">
                <span className="text-xs px-2 py-1 bg-muted rounded-lg">
                    {CATEGORIES.find(c => c.id === challenge.category)?.icon} {challenge.category}
                </span>
                <span className="text-emerald-400 font-bold">₹{formattedPrice}</span>
            </div>

            <h3 className="mt-3 text-lg font-semibold text-foreground line-clamp-2">{challenge.title}</h3>
            <p className="mt-2 text-sm text-muted-foreground line-clamp-2">{challenge.description || ''}</p>

            <div className="mt-4 flex items-center justify-between text-sm">
                <span className="text-muted-foreground">by {challenge.companyName}</span>
                <div className="flex items-center gap-1 text-muted-foreground">
                    <Clock className="w-4 h-4" />
                    {daysLeft === null ? 'Unknown' : daysLeft > 0 ? `${daysLeft} days left` : 'Expired'}
                </div>
            </div>

            {challenge.proposalCount > 0 && (
                <div className="mt-3 text-xs text-muted-foreground">
                    {challenge.proposalCount} proposal{challenge.proposalCount > 1 ? 's' : ''} received
                </div>
            )}
        </motion.div>
    )
}

export default function Challenges() {
    const navigate = useNavigate()
    const { profile } = useOutletContext()
    const [challenges, setChallenges] = useState([])
    const [loading, setLoading] = useState(true)
    const [searchQuery, setSearchQuery] = useState('')
    const [selectedCategory, setSelectedCategory] = useState('all')

    useEffect(() => {
        loadChallenges()
    }, [])

    const loadChallenges = async () => {
        try {
            const response = await fellowshipApi.getChallenges({ status: 'open', limit: 50 })
            setChallenges(response.data.challenges)
        } catch (error) {
            toast.error('Failed to load challenges')
            setChallenges([])
        } finally {
            setLoading(false)
        }
    }

    const filteredChallenges = challenges.filter(challenge => {
        const title = (challenge.title || '').toLowerCase()
        const description = (challenge.description || '').toLowerCase()
        const matchesSearch = title.includes(searchQuery.toLowerCase()) ||
            description.includes(searchQuery.toLowerCase())
        const matchesCategory = selectedCategory === 'all' || challenge.category === selectedCategory
        return matchesSearch && matchesCategory
    })

    const priceValues = challenges.map(c => Number(c.price)).filter(Number.isFinite)
    const avgReward = priceValues.length > 0
        ? Math.round(priceValues.reduce((sum, price) => sum + price, 0) / priceValues.length)
        : 0
    const maxReward = priceValues.length > 0
        ? Math.max(...priceValues)
        : 0

    return (
        <div className="space-y-6">
            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-foreground">Browse Challenges</h1>
                    <p className="text-muted-foreground">Find opportunities to earn while building your portfolio</p>
                </div>
                <div className="flex items-center gap-2">
                    <span className="flex items-center gap-1 px-3 py-1.5 bg-emerald-950 text-emerald-400 rounded-lg text-sm">
                        <TrendingUp className="w-3 h-3" />
                        {challenges.length} Open
                    </span>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-4 sm:grid-cols-4">
                <div className="rounded-xl border border-border bg-background p-4">
                    <div className="flex items-center gap-2 text-muted-foreground">
                        <Briefcase className="h-4 w-4" />
                        <span className="text-sm">Total</span>
                    </div>
                    <p className="mt-2 text-2xl font-bold text-foreground">{challenges.length}</p>
                </div>
                <div className="rounded-xl border border-border bg-background p-4">
                    <div className="flex items-center gap-2 text-muted-foreground">
                        <Sparkles className="h-4 w-4" />
                        <span className="text-sm">Avg. Reward</span>
                    </div>
                    <p className="mt-2 text-2xl font-bold text-foreground">₹{avgReward.toLocaleString('en-IN')}</p>
                </div>
                <div className="rounded-xl border border-border bg-background p-4">
                    <div className="flex items-center gap-2 text-emerald-400">
                        <TrendingUp className="h-4 w-4" />
                        <span className="text-sm">Highest</span>
                    </div>
                    <p className="mt-2 text-2xl font-bold text-emerald-400">₹{maxReward.toLocaleString('en-IN')}</p>
                </div>
                <div className="rounded-xl border border-border bg-background p-4">
                    <div className="flex items-center gap-2 text-muted-foreground">
                        <Filter className="h-4 w-4" />
                        <span className="text-sm">Categories</span>
                    </div>
                    <p className="mt-2 text-2xl font-bold text-foreground">5</p>
                </div>
            </div>

            <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Search challenges..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 bg-background border border-border rounded-xl text-foreground placeholder:text-muted-foreground focus:outline-none focus:border-emerald-500"
                    />
                </div>
                <div className="flex flex-wrap gap-2">
                    {CATEGORIES.map(cat => (
                        <button
                            key={cat.id}
                            onClick={() => setSelectedCategory(cat.id)}
                            className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${selectedCategory === cat.id
                                    ? 'bg-emerald-600 text-foreground'
                                    : 'bg-muted text-muted-foreground hover:text-foreground'
                                }`}
                        >
                            {cat.id === 'all' ? 'All' : `${cat.icon} ${cat.label}`}
                        </button>
                    ))}
                </div>
            </div>

            {loading ? (
                <SkeletonChallengeGrid count={6} />
            ) : filteredChallenges.length > 0 ? (
                <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                    {filteredChallenges.map(challenge => (
                        <ChallengeCard
                            key={challenge._id || challenge.id}
                            challenge={challenge}
                            onClick={() => navigate(`/fellowship/challenges/${challenge._id || challenge.id}`)}
                        />
                    ))}
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-border py-16">
                    <Briefcase className="h-12 w-12 text-muted-foreground/80" />
                    <h3 className="mt-4 text-lg font-semibold text-foreground">No challenges found</h3>
                    <p className="mt-2 text-sm text-muted-foreground">
                        {searchQuery || selectedCategory !== 'all' ? 'Try adjusting your filters' : 'Check back later for new opportunities'}
                    </p>
                </div>
            )}
        </div>
    )
}

import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useOutletContext } from 'react-router-dom'
import { fellowshipApi } from '../../services/api'
import toast from 'react-hot-toast'
